window.ADRIVE_THEME_DATA=window.ADRIVE_THEME_DATA||{};window.ADRIVE_THEME_DATA[5]=[{"id":100400942,"themeId":5,"group":1004009,"chapter":20,"chapters":[20],"q":"При пересечении проезжей части водитель средства персональной мобильности:","a":["Должен двигаться по пешеходному переходу.","Должен двигаться по велосипедному переезду."],"c":1,"e":"<p>Пересечение проезжей части дороги на средстве персональной мобильности (не спешиваясь) должно осуществляться <strong>по велосипедному переезду</strong> при условии определения порядка проезда с использованием транспортных светофоров для регулирования движения велосипедистов (как на фотографии).</p>","image":"assets/adrive-questions/q100400942.jpg"},{"id":100401041,"themeId":5,"group":1004010,"chapter":20,"chapters":[20],"q":"Обязан ли водитель средства персональной мобильности сойти («спешиться»), чтобы пересечь проезжую часть дороги по нерегулируемому пешеходному переходу?","a":["Да, обязан.","Нет, не обязан."],"c":0,"e":"<p>Водитель средства персональной мобильности перед пересечением проезжей части дороги <strong>по пешеходному переходу обязан спешиться</strong> и переходить дорогу в соответствии обязанностям пешехода.</p>","image":null},{"id":100401042,"themeId":5,"group":1004010,"chapter":20,"chapters":[20],"q":"Кто из показанных участников дорожного движения в показанной ситуации правильно пересекает проезжую часть дороги на разрешающий сигнал светофора?","a":["Только водитель средства персональной мобильности, руководствуясь разрешающим сигналом транспортного светофора, предназначенного для регулирования движения велосипедистов.","Только пешеход, руководствуясь разрешающим сигналом пешеходного светофора.","Оба пересекают проезжую часть дороги правильно.","Оба пересекают проезжую часть дороги неправильно."],"c":2,"e":"<p>Оба участника дорожного движения правильно пересекают проезжую часть дороги. Водитель СПМ <strong>вправе не спешиваться</strong> при пересечении проезжей части дороги по велосипедному переезду, на котором движение регулируется транспортным светофором, предназначенным <strong>для регулирования движения велосипедистов</strong>.</p>","image":"assets/adrive-questions/q100401042.jpg"},{"id":100401043,"themeId":5,"group":1004010,"chapter":20,"chapters":[20],"q":"Кто из участников дорожного движения в показанной ситуации правильно пересекает проезжую часть дороги?","a":["Водитель средства персональной мобильности, двигаясь на разрешающий сигнал транспортного светофора, предназначенного для регулирования движения велосипедистов.","Пешеход, пересекающий проезжую часть дороги на разрешающий сигнал пешеходного светофора.","Оба пересекают проезжую часть дороги правильно.","Оба пересекают проезжую часть дороги неправильно."],"c":0,"e":"<p>Пересечение проезжей части дороги на средстве персональной мобильности, не спешиваясь, должно осуществляться <strong>по велосипедному переезду</strong> на разрешающий сигнал транспортного светофора, предназначенного для регулирования движения велосипедистов.</p> <p>Пешеход должен переходить дорогу в показанном месте <strong>по пешеходному переходу</strong>, а <strong>не по велосипедному переезду</strong>.</p>","image":"assets/adrive-questions/q100401043.jpg"},{"id":100401241,"themeId":5,"group":1004012,"chapter":20,"chapters":[20],"q":"Водитель средства персональной мобильности обязан:","a":["Двигаться по велосипедной или пешеходной дорожке, а при их отсутствии — по тротуару либо обочине.","Двигаться по велосипедной, пешеходной дорожке или тротуару, а при их отсутствии — по обочине.","Двигаться по велосипедной дорожке, а при её отсутствии — по обочине, тротуару или пешеходной дорожке ."],"c":2,"e":"<p>Управляя средством персональной мобильности, водитель обязан двигаться <strong>по велосипедной дорожке</strong>, а при её отсутствии — <strong>по обочине, тротуару или пешеходной дорожке</strong>, не создавая при этом препятствия для безопасного движения пешеходов.</p>","image":null},{"id":100401242,"themeId":5,"group":1004012,"chapter":20,"chapters":[20],"q":"Правильно ли водитель средства персональной мобильности осуществляет движение по дороге в показанной ситуации?","a":["Да, правильно.","Нет, неправильно."],"c":1,"e":"<p>Водитель средства персональной мобильности должен двигаться по велосипедной дорожке при её наличии.</p> <p>Велосипедная дорожка на показанном участке дороги присутствует, поэтому водитель средства персональной мобильности неправильно осуществляет движение, используя тротуар.</p>","image":"assets/adrive-questions/q100401242.jpg"},{"id":100401243,"themeId":5,"group":1004012,"chapter":20,"chapters":[20],"q":"В каком случае из перечисленных допускается движение на средствах персональной мобильности по проезжей части дороги?","a":["Допускается при отсутствии велосипедной дорожки.","Допускается при отсутствии велосипедной дорожки, пешеходной дорожки или тротуара.","Допускается только при отсутствии велосипедной дорожки, пешеходной дорожки, тротуара и обочины.","Не допускается в любом случае."],"c":2,"e":"<p>При отсутствии велосипедной дорожки, тротуара, пешеходной дорожки, обочины допускается движение по проезжей части дороги в один ряд <strong>не далее 1 метра от её правого края</strong>.</p>","image":"assets/adrive-questions/q100401243.jpg"},{"id":100401441,"themeId":5,"group":1004014,"chapter":20,"chapters":[20],"q":"При движении на средстве персональной мобильности (за исключением движения по велосипедной дорожке) в тёмное время суток и (или) при недостаточной видимости дороги вне населённого пункта:","a":["Водитель должен быть одет в одежду повышенной видимости со световозвращающими элементами.","Водителю рекомендуется быть одетым в одежду повышенной видимости со световозвращающими элементами."],"c":0,"e":"<p>При движении на средстве персональной мобильности в тёмное время суток и (или) при недостаточной видимости (кроме движения по велосипедной дорожке), водитель <strong>должен быть одет в одежду повышенной видимости</strong> со световозвращающими элементами.</p>","image":null},{"id":100401442,"themeId":5,"group":1004014,"chapter":20,"chapters":[20],"q":"При движении на средстве персональной мобильности в тёмное время суток и (или) при недостаточной видимости дороги:","a":["Должны быть включены: спереди — фара (фонарь), излучающая белый свет, сзади — фонарь, излучающий красный свет.","Должна быть установлена и включена фара (фонарь), позволяющая своевременно обнаружить препятствие для дорожного движения."],"c":0,"e":"<p>При движении на средстве персональной мобильности в тёмное время суток и (или) при недостаточной видимости дороги должны быть включены: <strong>спереди — фара (фонарь), излучающая белый свет, сзади — фонарь, излучающий красный свет</strong>.</p>","image":null},{"id":100401443,"themeId":5,"group":1004014,"chapter":20,"chapters":[20],"q":"При движении на средстве персональной мобильности (вне велосипедной дорожки) в тёмное время суток и (или) при недостаточной видимости дороги вне населённого пункта:","a":["Водитель должен быть одет в одежду повышенной видимости со световозвращающими элементами.","На средстве персональной мобильности должны быть включены: спереди — фара (фонарь), излучающая белый свет, сзади — фонарь, излучающий красный свет.","Должны быть выполнены оба условия."],"c":2,"e":"<p>При движении на средстве персональной мобильности в тёмное время суток и (или) при недостаточной видимости дороги (вне велосипедных дорожек) водитель должен быть одет в одежду повышенной видимости со световозвращающими элементами, а на средстве персональной мобильности должна быть спереди включена фара (фонарь), излучающая белый свет, а сзади — фонарь, излучающий красный свет.</p>","image":null},{"id":100401642,"themeId":5,"group":1004016,"chapter":20,"chapters":[20],"q":"Кому запрещается движение по тротуару в населённом пункте со скоростью более 10 км/ч?","a":["Водителю средства персональной мобильности.","Велосипедисту.","Запрещается обоим участникам дорожного движения."],"c":0,"e":"<p>При передвижении на средствах персональной мобильности, передвигаясь по тротуару в населённом пункте, запрещается превышать скорость в 10 км/ч.</p> <p>Скорость движения велосипедиста Правилами дорожного движения не ограничивается, за исключением электровелосипедов, конструктивная скорость которых не превышает 25 км/ч.</p>","image":null},{"id":100401841,"themeId":5,"group":1004018,"chapter":20,"chapters":[20],"q":"В каком возрасте запрещается управлять средством персональной мобильности на дорогах (кроме жилых зон) без сопровождения совершеннолетнего лица?","a":["В возрасте до 14 лет.","В возрасте до 16 лет.","В возрасте до 18 лет."],"c":0,"e":"<p>Запрещается управлять средством персональной мобильности в возрасте до четырнадцати лет (кроме жилых зон) без сопровождения совершеннолетнего лица.</p>","image":null},{"id":100401842,"themeId":5,"group":1004018,"chapter":20,"chapters":[20],"q":"Разрешается передвигаться на средствах персональной мобильности в возрасте до 14 лет без сопровождения совершеннолетнего лица:","a":["Только в жилых зонах.","Только по тротуарам в населённых пунктах.","В жилых зонах, пешеходных зонах, а также в зонах с ограничением максимальной скорости."],"c":0,"e":"<p>Запрещается без сопровождения совершеннолетнего лица управлять средством персональной мобильности в возрасте до четырнадцати лет (<strong>кроме жилых зон</strong>).</p>","image":null},{"id":100401843,"themeId":5,"group":1004018,"chapter":20,"chapters":[20],"q":"Разрешается ли продолжить движение прямо на средстве персональной мобильности ребёнку в возрасте до 14 лет по тротуару в показанной ситуации?","a":["Да, разрешается со скоростью шага пешехода.","Да, разрешается, но только в сопровождении совершеннолетнего лица.","Нет, не разрешается."],"c":1,"e":"<p>Запрещается передвигаться на средствах персональной мобильности в возрасте до четырнадцати лет (кроме жилых зон) без сопровождения совершеннолетнего лица.</p>","image":"assets/adrive-questions/q100401843.jpg"},{"id":101400101,"themeId":5,"group":1014001,"chapter":14,"chapters":[14],"q":"Как должен поступить водитель зелёного автомобиля при включении разрешающего сигнала транспортного светофора?","a":["Предоставить преимущество только пешеходу слева.","Предоставить преимущество только пешеходу справа.","Предоставить преимущество обоим пешеходам.","Начать движение, не дожидаясь, когда пешеходы закончат переход проезжей части дороги."],"c":2,"e":"<p>На регулируемом пешеходном переходе при подаче разрешающего сигнала регулировщиком или включении разрешающего сигнала светофора водитель должен предоставить преимущество пешеходам, не закончившим переход проезжей части дороги. Требование направлено на обеспечение безопасности пешеходов. Оно обязывает водителя ТС дать возможность пешеходу, не успевшему перейти проезжую часть за время действия разрешающего сигнала светофора или регулировщика, освободить проезжую часть, а также не ускорять темп движения.</p>","image":"assets/adrive-questions/q101400101.jpg"},{"id":101400133,"themeId":5,"group":1014001,"chapter":14,"chapters":[14],"q":"Как Вы должны поступить в показанной ситуации при включении зелёного сигнала транспортного светофора?","a":["Предоставить преимущество обоим пешеходам.","Предоставить преимущество только пешеходу справа.","Подать звуковой сигнал, чтобы пешеходы поскорее закончили переход проезжей части дороги."],"c":0,"e":"<p>При включении разрешающего сигнала светофора водитель должен предоставить преимущество пешеходам, не закончившим переход проезжей части дороги. Преимущество пешеходу считается предоставленным, если расстояние между транспортным средством и приближающимся пешеходом (в момент пересечения транспортным средством траектории движения пешехода) составило не менее двух полос движения транспортного средства (в том числе одну полосу и трамвайные пути попутного направления, одну полосу и разделительную полосу или зону, одну полосу и островок безопасности).</p>","image":"assets/adrive-questions/q101400133.jpg"},{"id":101400201,"themeId":5,"group":1014002,"chapter":14,"chapters":[14],"q":"Как Вы должны поступить, подъезжая к нерегулируемому пешеходному переходу, на котором пешеходы начинают переход проезжей части дороги?","a":["Продолжить движение, не дожидаясь, когда пешеходы выйдут на проезжую часть дороги.","Предоставить преимущество обоим пешеходам.","Предоставить преимущество только пешеходу справа."],"c":1,"e":"<p>При подъезде к нерегулируемому пешеходному переходу водитель должен предоставить преимущество пешеходу.</p> <p>Преимущество пешеходу считается предоставленным, если расстояние между транспортным средством и приближающимся пешеходом (в момент пересечения транспортным средством траектории движения пешехода) составило не менее двух полос движения транспортного средства.</p>","image":"assets/adrive-questions/q101400201.jpg"},{"id":101400205,"themeId":5,"group":1014002,"chapter":14,"chapters":[14],"q":"Кто должен уступить дорогу (предоставить преимущество) в представленной ситуации?","a":["Вы, управляя легковым автомобилем.","Пешеход, начинающий переход проезжей части дороги на перекрёстке вне пешеходного перехода."],"c":1,"e":"<p>В показанной ситуации пешеход намеревается перейти проезжую часть дороги вне пешеходного перехода, так как на необходимую пешеходу сторону дороги отсутствует пешеходный переход. В таком месте пешеход преимущества не имеет перед приближающимся транспортным средством. Но при этом следует помнить, что при появлении препятствия (если пешеход выйдет на проезжую часть перед движущимся транспортным средством) водитель обязан немедленно принять меры к снижению скорости вплоть до остановки.</p>","image":"assets/adrive-questions/q101400205.jpg"},{"id":101400232,"themeId":5,"group":1014002,"chapter":14,"chapters":[14],"q":"Предоставил ли преимущество водитель легкового автомобиля пешеходу, проезжая безостановочно пешеходный переход в показанной ситуации?","a":["Нет, не предоставил.","Да, предоставил."],"c":1,"e":"<p>При подъезде к нерегулируемому пешеходному переходу водитель должен предоставить преимущество пешеходу.</p> <p>Преимущество пешеходу считается предоставленным, если расстояние между транспортным средством и приближающимся пешеходом (в момент пересечения транспортным средством траектории движения пешехода) составило не менее двух полос движения транспортного средства (в том числе одну полосу и трамвайные пути попутного направления, одну полосу и разделительную полосу или зону, одну полосу и островок безопасности).</p> <p>Поэтому в показанной ситуации водитель не обязан останавливаться, так как между транспортным средством и пешеходом — три условные полосы.</p>","image":"assets/adrive-questions/q101400232.jpg"},{"id":101400233,"themeId":5,"group":1014002,"chapter":14,"chapters":[14],"q":"Предоставил ли преимущество водитель легкового автомобиля пешеходу, проезжая безостановочно пешеходный переход в показанной ситуации?","a":["Нет, не предоставил.","Да, предоставил."],"c":1,"e":"<p>При подъезде к нерегулируемому пешеходному переходу водитель должен предоставить преимущество пешеходу.</p> <p>Преимущество пешеходу считается предоставленным, если расстояние между транспортным средством и приближающимся пешеходом (в момент пересечения транспортным средством траектории движения пешехода) составило не менее двух полос движения транспортного средства.</p> <p>Поэтому в показанной ситуации водитель не обязан останавливаться, так как между транспортным средством и пешеходом — три полосы движения.</p>","image":"assets/adrive-questions/q101400233.jpg"},{"id":101400234,"themeId":5,"group":1014002,"chapter":14,"chapters":[14],"q":"Предоставил ли преимущество водитель легкового автомобиля пешеходу, проезжая безостановочно пешеходный переход в показанной ситуации?","a":["Нет, не предоставил.","Да, предоставил."],"c":1,"e":"<p>При подъезде к нерегулируемому пешеходному переходу водитель должен предоставить преимущество пешеходу.</p> <p>Преимущество пешеходу считается предоставленным, если расстояние между транспортным средством и приближающимся пешеходом (в момент пересечения транспортным средством траектории движения пешехода) составило не менее двух полос движения транспортного средства (в том числе одну полосу и трамвайные пути попутного направления).</p> <p>Поэтому в показанной ситуации водитель не обязан останавливаться, так как между транспортным средством и пешеходом — две условные полосы.</p>","image":"assets/adrive-questions/q101400234.jpg"},{"id":101400304,"themeId":5,"group":1014003,"chapter":14,"chapters":[14],"q":"Как должен поступить водитель синего автомобиля, объезжающий препятствие по встречной полосе перед пешеходным переходом?","a":["Первым проехать пешеходный переход, чтобы быстрее освободить полосу встречного движения.","Снизить скорость движения и при наличии пешеходов предоставить им преимущество."],"c":1,"e":"<p>Если перед нерегулируемым пешеходным переходом остановилось (стоит) транспортное средство, водители других транспортных средств, движущихся по соседним полосам движения в попутном направлении, должны снизить скорость движения и при наличии пешеходов предоставить им преимущество.<br> Наличие перед пешеходным переходом на расстоянии ближе 15 метров остановившегося (стоящего) ТС является препятствием, ограничивающим обзорность, из-за которого может появиться пешеход или группа пешеходов, которым необходимо предоставить преимущество.</p>","image":"assets/adrive-questions/q101400304.jpg"},{"id":101400331,"themeId":5,"group":1014003,"chapter":14,"chapters":[14],"q":"Как Вы должны поступить в показанной ситуации, если грузовой автомобиль замедлил движение?","a":["Продолжить движение с особой осторожностью.","Снизить скорость движения и при наличии пешеходов предоставить им преимущество.","Остановиться перед пешеходным переходом, убедиться в том, что перед грузовым автомобилем нет пешеходов, а затем возобновить движение."],"c":1,"e":"<p>Если перед нерегулируемым пешеходным переходом остановилось (стоит), замедлило движение или движется с меньшей скоростью транспортное средство, то водители других транспортных средств, движущихся по соседним полосам движения в попутном направлении, должны <strong>снизить скорость</strong> движения и <strong>при наличии пешеходов предоставить им преимущество</strong>.</p>","image":"assets/adrive-questions/q101400331.jpg"},{"id":101400332,"themeId":5,"group":1014003,"chapter":14,"chapters":[14],"q":"Как должен поступить водитель легкового автомобиля, если грузовой автомобиль замедлил движение?","a":["Продолжить движение с особой осторожностью.","Снизить скорость движения и при наличии пешеходов предоставить им преимущество.","Остановиться перед пешеходным переходом, убедиться в том, что перед грузовым автомобилем нет пешеходов, а затем возобновить движение."],"c":1,"e":"<p>Если перед нерегулируемым пешеходным переходом остановилось (стоит), замедлило движение или движется с меньшей скоростью транспортное средство, то водители других транспортных средств, движущихся по соседним полосам движения в попутном направлении, должны снизить скорость движения и при наличии пешеходов предоставить им преимущество.</p>","image":"assets/adrive-questions/q101400332.jpg"},{"id":101400333,"themeId":5,"group":1014003,"chapter":14,"chapters":[14],"q":"Как должен поступить водитель жёлтого легкового автомобиля, если транспортные средства замедлили движение перед пешеходным переходом?","a":["Продолжить движение с особой осторожностью.","Снизить скорость движения, предоставить преимущество пешеходу справа, при наличии иных пешеходов предоставить им преимущество.","Остановиться перед пешеходным переходом, предоставить преимущество пешеходу справа, а затем возобновить движение."],"c":1,"e":"<p>При подъезде к нерегулируемому пешеходному переходу водитель должен предоставить преимущество пешеходу. Если перед нерегулируемым пешеходным переходом остановилось (стоит), замедлило движение или движется с меньшей скоростью транспортное средство, то водители других транспортных средств, движущихся по соседним полосам движения в попутном направлении, должны снизить скорость движения и при наличии пешеходов предоставить им преимущество.</p>","image":"assets/adrive-questions/q101400333.jpg"},{"id":101400352,"themeId":5,"group":1014003,"chapter":14,"chapters":[14],"q":"Как следует двигаться через пешеходный переход в ситуации, когда перед ним стоят транспортные средства в нарушение Правил дорожного движения?","a":["Продолжить движение с прежней скоростью, сместиться в полосе движения как можно левее.","Снизить скорость движения и при наличии пешеходов предоставить им преимущество."],"c":1,"e":"<p>Если перед пешеходным переходом стоит транспортное средство, необходимо <strong>снизить скорость движения</strong> и при наличии пешеходов <strong>предоставить им преимущество</strong>.</p>","image":"assets/adrive-questions/q101400352.jpg"},{"id":101400431,"themeId":5,"group":1014004,"chapter":14,"chapters":[14],"q":"Как должен поступить водитель синего легкового автомобиля, если на соседней полосе стоит грузовой автомобиль, совершивший вынужденную остановку?","a":["Продолжить движение, повысив внимание.","Снизить скорость движения и при наличии пешеходов предоставить им преимущество.","Остановиться перед пешеходным переходом, убедиться в том, что перед грузовым автомобилем нет пешеходов, а затем возобновить движение."],"c":1,"e":"<p>Если перед нерегулируемым пешеходным переходом остановилось (стоит), замедлило движение или движется с меньшей скоростью транспортное средство, то водители других транспортных средств, движущихся по соседним полосам движения в попутном направлении, должны снизить скорость движения и при наличии пешеходов предоставить им преимущество.</p>","image":"assets/adrive-questions/q101400431.jpg"},{"id":101400432,"themeId":5,"group":1014004,"chapter":14,"chapters":[14],"q":"Объехав остановившийся перед пешеходным переходом автобус с включённой аварийной световой сигнализацией, водитель легкового автомобиля должен:","a":["Продолжить движение с постоянной скоростью, повысив внимание.","Снизить скорость движения и при наличии пешеходов предоставить им преимущество.","Остановиться перед пешеходным переходом, убедиться в том, что перед автобусом нет пешеходов, а затем возобновить движение."],"c":1,"e":"<p>Если перед нерегулируемым пешеходным переходом остановилось (стоит), замедлило движение или движется с меньшей скоростью транспортное средство, то водители других транспортных средств, движущихся по соседним полосам движения в попутном направлении, должны снизить скорость движения и при наличии пешеходов предоставить им преимущество.</p>","image":"assets/adrive-questions/q101400432.jpg"},{"id":101400433,"themeId":5,"group":1014004,"chapter":14,"chapters":[14],"q":"Как Вам следует поступить в показанной ситуации, управляя легковым автомобилем?","a":["Снизить скорость и предоставить преимущество перебегающему проезжую часть дороги пешеходу.","Снизить скорость движения, предоставить преимущество пешеходу, бегущему справа, при наличии иных пешеходов — также предоставить им преимущество.","Подать звуковой сигнал, чтобы пешеход обратил внимание на движущееся транспортное средство."],"c":1,"e":"<p>При подъезде к нерегулируемому пешеходному переходу водитель должен предоставить преимущество пешеходу (в том числе — бегущему).<br> Так как перед пешеходным переходом остановилось транспортное средство, ограничивающее обзорность, то необходимо снизить скорость движения и при наличии пешеходов предоставить им преимущество.</p>","image":"assets/adrive-questions/q101400433.jpg"},{"id":101400441,"themeId":5,"group":1014004,"chapter":14,"chapters":[14],"q":"Как Вам следует поступить, приближаясь к пешеходному переходу (светофоры отключены), если по соседней справа полосе автобус движется с меньшей скоростью, но не останавливается?","a":["Продолжить движение, так как автобус скорость не снижает.","Снизить скорость движения и при наличии пешеходов предоставить им преимущество."],"c":1,"e":"<p>Если перед нерегулируемыми пешеходным переходом движется с меньшей скоростью транспортное средство, водители других транспортных средств, движущихся по соседним полосам движения в попутном направлении, должны снизить скорость движения и при наличии пешеходов предоставить им преимущество.</p>","image":"assets/adrive-questions/q101400441.jpg"},{"id":101400501,"themeId":5,"group":1014005,"chapter":14,"chapters":[14],"q":"В каком месте должен остановиться водитель синего легкового автомобиля для пропуска встречного автомобиля при отсутствии пешеходов в пределах пешеходного перехода?","a":["На пешеходном переходе.","Перед пешеходным переходом.","В любом из вышеперечисленных мест."],"c":1,"e":"<p>Согласно Правилам дорожного движения, водителю запрещается въезжать на пешеходный переход, если образовался затор, который вынудит его остановиться на пешеходном переходе. Водитель ТС должен остановиться на границе пешеходного перехода.<br> Требование направлено на создание пешеходам беспрепятственного и безопасного движения в случае возникновения транспортного затора.</p>","image":"assets/adrive-questions/q101400501.jpg"},{"id":101400502,"themeId":5,"group":1014005,"chapter":14,"chapters":[14],"q":"В каком месте Вы должны остановиться в ожидании возможности продолжить движение при наличии пешеходов, переходящих проезжую часть дороги по пешеходному переходу?","a":["На пешеходном переходе.","Перед пешеходным переходом.","В любом из вышеперечисленных мест."],"c":1,"e":"<p>Согласно Правилам дорожного движения, водителю запрещается въезжать на пешеходный переход, если образовался затор, который вынудит его остановиться на пешеходном переходе. Водитель ТС должен остановиться на границе пешеходного перехода.<br> Требование направлено на создание пешеходам беспрепятственного и безопасного движения в случае возникновения транспортного затора.</p>","image":"assets/adrive-questions/q101400502.jpg"},{"id":101400581,"themeId":5,"group":1014005,"chapter":14,"chapters":[14],"q":"Разрешается ли Вам выехать на пешеходный переход в показанной ситуации в ожидании возможности продолжить движение?","a":["Да, пока горит разрешающий сигнал светофора.","Нет, не разрешается."],"c":1,"e":"<p><strong>Запрещается въезжать на пешеходный переход</strong>, если образовался затор, который вынудит водителя остановиться на пешеходном переходе.</p>","image":"assets/adrive-questions/q101400581.jpg"},{"id":101400701,"themeId":5,"group":1014007,"chapter":14,"chapters":[14],"q":"Как Вы должны поступить в показанной ситуации, если к проезжей части дороги приближается пешеход с тростью белого цвета?","a":["Остановиться возле пешехода и предложить ему помощь.","Предоставить преимущество пешеходу – инвалиду по зрению."],"c":1,"e":"<p>Даже вне пешеходных переходов, водитель должен предоставить преимущество пешеходу – инвалиду по зрению, подающему сигнал тростью белого цвета либо тростью с покрытием повышенной видимости, в том числе со световозвращающим элементом (элементами).</p>","image":"assets/adrive-questions/q101400701.jpg"},{"id":101400703,"themeId":5,"group":1014007,"chapter":14,"chapters":[14],"q":"Кто должен уступить дорогу (предоставить преимущество) в показанной ситуации?","a":["Водитель синего автомобиля.","Пешеход, держащий в руке трость с покрытием повышенной видимости со световозвращающими элементами."],"c":0,"e":"<p>Даже вне пешеходных переходов, водитель должен предоставить преимущество пешеходу – инвалиду по зрению, подающему сигнал тростью белого цвета либо тростью с покрытием повышенной видимости, в том числе со световозвращающим элементом (элементами).</p>","image":"assets/adrive-questions/q101400703.jpg"},{"id":101400705,"themeId":5,"group":1014007,"chapter":14,"chapters":[14],"q":"Как должен поступить водитель синего автомобиля, если на тротуаре находятся дети без сопровождения взрослых?","a":["Снизить скорость движения и не опережать детей, движущихся по тротуару.","Продолжить движение, сместиться ближе к центру проезжей части дороги, подать звуковой сигнал.","Продолжить движение, быть готовым снизить скорость движения или остановиться, чтобы исключить вероятность наезда на детей."],"c":2,"e":"<p>Согласно Правилам дорожного движения, везде, в том числе и вне пешеходных переходов, водитель должен быть готов снизить скорость движения или остановиться, чтобы исключить вероятность наезда на детей и пешеходов с видимыми нарушениями опорно-двигательного аппарата. Водитель ТС, обнаруживший на проезжей части или в опасной близости от неё детей (ребёнка), с целью предупреждения других водителей ТС об опасности для движения может включить аварийную световую сигнализацию.</p>","image":"assets/adrive-questions/q101400705.jpg"},{"id":101400801,"themeId":5,"group":1014008,"chapter":14,"chapters":[14],"q":"Как должен поступить водитель жёлтого автомобиля, подъезжая к остановочному пункту трамвая, где происходит посадка (высадка) пассажиров с проезжей части дороги?","a":["Остановиться, предоставив преимущество пешеходам.","Продолжить движение, если это не создаст препятствие для движения пешеходов."],"c":0,"e":"<p>Водитель должен остановиться, предоставив преимущество пешеходам, идущим к стоящему на остановочном пункте маршрутному транспортному средству либо от него (со стороны дверей), если посадка (высадка) пассажиров производится с проезжей части дороги или с посадочной площадки, расположенной на ней.<br> Требование направлено на обеспечение безопасности пешеходов и относится к ситуации, связанной с остановочными пунктами трамваев, рельсы которых расположены не у края проезжей части дороги.</p>","image":"assets/adrive-questions/q101400801.jpg"},{"id":101400802,"themeId":5,"group":1014008,"chapter":14,"chapters":[14],"q":"Как должен поступить водитель зелёного автомобиля, подъезжая к остановочному пункту трамвая, где происходит посадка (высадка) пассажиров с посадочной площадки, расположенной на проезжей части дороги?","a":["Остановиться, предоставив преимущество пешеходам, находящимся на проезжей части дороги.","Продолжить движение, если это не создаст препятствие для движения пешеходов."],"c":0,"e":"<p>Водитель должен остановиться, предоставив преимущество пешеходам, идущим к стоящему на остановочном пункте маршрутному транспортному средству либо от него (со стороны дверей), если посадка (высадка) пассажиров производится с проезжей части дороги или с посадочной площадки, расположенной на ней.<br> Требование направлено на обеспечение безопасности пешеходов и относится к ситуации, связанной с остановочными пунктами трамваев, рельсы которых расположены не у края проезжей части дороги.</p>","image":"assets/adrive-questions/q101400802.jpg"},{"id":101400803,"themeId":5,"group":1014008,"chapter":14,"chapters":[14],"q":"Кто должен уступить дорогу (предоставить преимущество) в показанной ситуации?","a":["Водитель зелёного автомобиля.","Пешеход, идущий к посадочной площадке."],"c":1,"e":"<p>В показанной ситуации на остановочном пункте отсутствует трамвай, поэтому водитель автомобиля не обязан предоставлять преимущество пешеходу.</p>","image":"assets/adrive-questions/q101400803.jpg"},{"id":101400901,"themeId":5,"group":1014009,"chapter":14,"chapters":[14],"q":"Когда можно возобновить движение водителю жёлтого автомобиля, остановившемуся, чтобы предоставить преимущество пешеходам, совершающим посадку (высадку)?","a":["Только после закрытия дверей трамвая.","Только когда пешеходы покинут проезжую часть.","Только после закрытия дверей трамвая и выключения на нём аварийной световой сигнализации."],"c":2,"e":"<p>Предоставив преимущество пешеходам, начинать движение разрешается только после закрытия дверей маршрутного транспортного средства и выключения на нём аварийной световой сигнализации (светового указателя правого поворота).</p>","image":"assets/adrive-questions/q101400901.jpg"},{"id":101400902,"themeId":5,"group":1014009,"chapter":14,"chapters":[14],"q":"Когда можно возобновить движение водителю зелёного автомобиля, остановившемуся, чтобы предоставить преимущество пешеходам, совершающим посадку (высадку)?","a":["Только после закрытия дверей трамвая.","Только когда пешеходы покинут проезжую часть.","Только после закрытия дверей трамвая и выключения на нём аварийной световой сигнализации."],"c":2,"e":"<p>Предоставив преимущество пешеходам, начинать движение разрешается только после закрытия дверей маршрутного транспортного средства и выключения на нём аварийной световой сигнализации (светового указателя правого поворота).</p>","image":"assets/adrive-questions/q101400902.jpg"},{"id":101401001,"themeId":5,"group":1014010,"chapter":14,"chapters":[14],"q":"Должен ли водитель зелёного автомобиля предоставить преимущество пешеходам?","a":["Должен только пешеходу справа, идущему к трамваю для посадки.","Должен только пешеходу слева, совершившему высадку из трамвая, идущему по направлению к тротуару.","Должен обоим пешеходам."],"c":2,"e":"<p>В показанной ситуации пешеходы переходят проезжую часть дороги по нерегулируемому пешеходному переходу, поэтому водитель обязан предоставить преимущество обоим пешеходам.</p>","image":"assets/adrive-questions/q101401001.jpg"},{"id":101401002,"themeId":5,"group":1014010,"chapter":14,"chapters":[14],"q":"Имеют ли преимущество пешеходы при переходе проезжей части дороги в показанной ситуации?","a":["Нет, не имеют.","Имеет только пешеход справа, идущий к трамваю для посадки.","Имеет только пешеход слева, совершившему высадку из трамвая и идущий по направлению к тротуару.","Преимущество в показанной ситуации при переходе проезжей части дороги имеют оба пешехода."],"c":0,"e":"<p>Согласно Правилам дорожного движения, водитель должен остановиться, предоставив преимущество пешеходам, идущим к стоящему на остановочном пункте маршрутному транспортному средству либо от него (со стороны дверей), если посадка (высадка) пассажиров производится с проезжей части дороги или с посадочной площадки, расположенной на ней. Начинать движение разрешается только после закрытия дверей маршрутного транспортного средства и выключения на нём аварийной световой сигнализации (светового указателя правого поворота). Требование направлено на обеспечение безопасности пешеходов и относится к ситуации, связанной с остановочными пунктами трамваев, рельсы которых расположены не у края проезжей части дороги.</p>","image":"assets/adrive-questions/q101401002.jpg"},{"id":101401003,"themeId":5,"group":1014010,"chapter":14,"chapters":[14],"q":"Должен ли водитель зелёного автомобиля предоставить преимущество пешеходам?","a":["Нет, не должен.","Должен обоим пешеходам.","Должен только пешеходу справа, идущему к трамваю для посадки.","Должен только пешеходу слева, совершившему высадку из трамвая, идущему по направлению к тротуару."],"c":0,"e":"<p>Водитель должен остановиться, предоставив преимущество пешеходам, идущим к стоящему на остановочном пункте маршрутному транспортному средству либо от него (со стороны дверей), если посадка (высадка) пассажиров производится с проезжей части дороги или с посадочной площадки, расположенной на ней. В показанной же ситуации пешеходы переходят проезжую часть не со стороны дверей, поэтому водитель не обязан предоставлять им преимущество.</p>","image":"assets/adrive-questions/q101401003.jpg"},{"id":101401101,"themeId":5,"group":1014011,"chapter":14,"chapters":[14],"q":"Как должен поступить водитель жёлтого автомобиля, подъезжая к остановочному пункту трамвая, если у стоящего трамвая двери открыты, а пешеходы на проезжей части дороги отсутствуют?","a":["Остановиться.","Продолжить движение."],"c":0,"e":"<p>Согласно Правилам дорожного движения, водитель должен остановиться, предоставив преимущество пешеходам, идущим к стоящему на остановочном пункте маршрутному транспортному средству либо от него (со стороны дверей), если посадка (высадка) пассажиров производится с проезжей части дороги или с посадочной площадки, расположенной на ней. В показанной ситуации, когда двери трамвая открыты, появление пешехода на проезжей части дороги возможно в любой момент времени. Особенно опасен внезапный выход из трамвая прямо под колёса движущегося автомобиля. Начинать движение следует только после закрытия дверей маршрутного транспортного средства и выключения на нём аварийной световой сигнализации (светового указателя правого поворота). Требование направлено на обеспечение безопасности пешеходов.</p>","image":"assets/adrive-questions/q101401101.jpg"},{"id":101401102,"themeId":5,"group":1014011,"chapter":14,"chapters":[14],"q":"Разрешено ли водителю зелёного автомобиля возобновить движение, если у стоящего трамвая двери открыты, а пешеходы на проезжей части дороги отсутствуют?","a":["Разрешено.","Запрещено."],"c":1,"e":"<p>Согласно Правилам дорожного движения, водитель должен остановиться, предоставив преимущество пешеходам, идущим к стоящему на остановочном пункте маршрутному транспортному средству либо от него (со стороны дверей), если посадка (высадка) пассажиров производится с проезжей части дороги или с посадочной площадки, расположенной на ней. Начинать движение разрешается только после закрытия дверей маршрутного транспортного средства и выключения на нём аварийной световой сигнализации (светового указателя правого поворота). Требование направлено на обеспечение безопасности пешеходов и относится к ситуации, связанной с остановочными пунктами трамваев, рельсы которых расположены не у края проезжей части дороги.</p>","image":"assets/adrive-questions/q101401102.jpg"},{"id":101401201,"themeId":5,"group":1014012,"chapter":14,"chapters":[14],"q":"Разрешено ли водителю жёлтого автомобиля опередить трамвай в зоне остановочного пункта трамвая в показанной ситуации при отсутствии пешеходов на проезжей части дороги?","a":["Разрешено.","Запрещено."],"c":1,"e":"<p>Запрещается опережать движущийся трамвай, у которого включена аварийная световая сигнализация (световой указатель правого поворота), в зоне остановочного пункта трамвая, обозначенной дорожным знаком 5.13.1 «Остановочный пункт трамвая» и (или) горизонтальной дорожной разметкой 1.17.2 .</p>","image":"assets/adrive-questions/q101401201.jpg"},{"id":101401202,"themeId":5,"group":1014012,"chapter":14,"chapters":[14],"q":"Разрешено ли водителю зелёного автомобиля опередить трамвай в зоне остановочного пункта трамвая при отсутствии пешеходов на проезжей части дороги?","a":["Разрешено.","Запрещено."],"c":1,"e":"<p>Запрещается опережать движущийся трамвай, у которого включена аварийная световая сигнализация (световой указатель правого поворота), в зоне остановочного пункта трамвая, обозначенной дорожным знаком 5.13.1 «Остановочный пункт трамвая» и (или) горизонтальной дорожной разметкой 1.17.2 .</p>","image":"assets/adrive-questions/q101401202.jpg"},{"id":101401203,"themeId":5,"group":1014012,"chapter":14,"chapters":[14],"q":"Разрешено ли водителю жёлтого автомобиля опередить трамвай в зоне остановочного пункта трамвая в показанной ситуации при отсутствии пешеходов на проезжей части дороги?","a":["Разрешено.","Запрещено."],"c":0,"e":"<p>В показанной ситуации у трамвая выключена аварийная световая сигнализация (световой указатель правого поворота), поэтому водителю легкового автомобиля разрешено опередить движущийся трамвай в зоне остановочного пункта.</p>","image":"assets/adrive-questions/q101401203.jpg"},{"id":101401204,"themeId":5,"group":1014012,"chapter":14,"chapters":[14],"q":"Разрешено ли водителю зелёного автомобиля опередить трамвай в зоне остановочного пункта трамвая в показанной ситуации при отсутствии пешеходов на проезжей части дороги?","a":["Разрешено.","Запрещено."],"c":0,"e":"<p>Запрещается опережать движущийся трамвай, у которого включена аварийная световая сигнализация (световой указатель правого поворота), в зоне остановочного пункта трамвая, обозначенной дорожным знаком 5.13.1 «Остановочный пункт трамвая» и (или) горизонтальной дорожной разметкой 1.17.2 .</p> <p>В показанной ситуации у трамвая выключена аварийная световая сигнализация (световой указатель правого поворота), поэтому водителю легкового автомобиля разрешено опередить движущийся трамвай в зоне остановочного пункта.</p>","image":"assets/adrive-questions/q101401204.jpg"},{"id":101401301,"themeId":5,"group":1014013,"chapter":14,"chapters":[14],"q":"Разрешено ли водителю синего автомобиля опередить трамвай в показанной ситуации?","a":["Разрешено.","Запрещено."],"c":0,"e":"<p>В показанной ситуации трамвай находится в зоне остановочного пункта автобуса или троллейбуса, а не в зоне остановочного пункта трамвая. Поэтому водителю легкового автомобиля разрешено опередить трамвай с включённой аварийной световой сигнализацией.</p>","image":"assets/adrive-questions/q101401301.jpg"},{"id":101401302,"themeId":5,"group":1014013,"chapter":14,"chapters":[14],"q":"Разрешено ли водителю синего автомобиля опередить трамвай в показанной ситуации?","a":["Разрешено.","Запрещено."],"c":0,"e":"<p>В показанной ситуации трамвай находится в зоне остановочного пункта автобуса или троллейбуса, а не в зоне остановочного пункта трамвая. Поэтому водителю легкового автомобиля разрешено опередить трамвай с включённой аварийной световой сигнализацией.</p>","image":"assets/adrive-questions/q101401302.jpg"},{"id":101401401,"themeId":5,"group":1014014,"chapter":14,"chapters":[14],"q":"Разрешено ли водителю жёлтого автомобиля опередить трамвай до начала зоны остановочного пункта трамвая?","a":["Разрешено.","Запрещено."],"c":0,"e":"<p>В показанной ситуации трамвай находится вне зоны остановочного пункта трамвая. Согласно Правилам дорожного движения, запрещается опережать движущийся трамвай, у которого включена аварийная световая сигнализация (световой указатель правого поворота), в зоне остановочного пункта трамвая, обозначенной дорожным знаком 5.13.1 «Остановочный пункт трамвая» и (или) горизонтальной дорожной разметкой 1.17.2 .<br> Водитель трамвая должен включить аварийную световую сигнализацию или световой указатель поворота заблаговременно (до въезда в зону остановочного пункта), чтобы другие водители могли остановиться, не прибегая к экстренному торможению.</p>","image":"assets/adrive-questions/q101401401.jpg"},{"id":101401402,"themeId":5,"group":1014014,"chapter":14,"chapters":[14],"q":"Разрешено ли водителю жёлтого автомобиля опередить трамвай в показанной ситуации?","a":["Разрешено.","Запрещено."],"c":1,"e":"<p>В показанной ситуации трамвай находится в зоне остановочного пункта трамвая. Согласно Правилам дорожного движения, запрещается опережать движущийся трамвай, у которого включена аварийная световая сигнализация (световой указатель правого поворота), в зоне остановочного пункта трамвая, обозначенной дорожным знаком 5.13.1 «Остановочный пункт трамвая» и (или) горизонтальной дорожной разметкой 1.17.2 .<br> Водитель трамвая должен включить аварийную световую сигнализацию или световой указатель поворота заблаговременно (до въезда в зону остановочного пункта), чтобы другие водители могли остановиться, не прибегая к экстренному торможению.</p>","image":"assets/adrive-questions/q101401402.jpg"},{"id":101401403,"themeId":5,"group":1014014,"chapter":14,"chapters":[14],"q":"Разрешено ли водителю синего автомобиля опередить трамвай сразу после проезда зоны остановочного пункта трамвая?","a":["Разрешено.","Запрещено."],"c":0,"e":"<p>В показанной ситуации трамвай находится вне зоны остановочного пункта трамвая. Согласно Правилам дорожного движения, запрещается опережать движущийся трамвай, у которого включена аварийная световая сигнализация (световой указатель правого поворота), в зоне остановочного пункта трамвая, обозначенной дорожным знаком 5.13.1 «Остановочный пункт трамвая» и (или) горизонтальной дорожной разметкой 1.17.2 .</p>","image":"assets/adrive-questions/q101401403.jpg"},{"id":101401501,"themeId":5,"group":1014015,"chapter":14,"chapters":[14],"q":"Как Вы должны поступить, приближаясь к стоящему автобусу с опознавательным знаком «Перевозка детей» в показанной обстановке?","a":["Снизить скорость движения, при необходимости остановиться и предоставить преимущество пешеходам.","Продолжать движение, быть готовым снизить скорость движения или остановиться, чтобы исключить вероятность наезда на детей."],"c":0,"e":"<p>Приближаясь к стоящему транспортному средству с включённой аварийной световой сигнализацией и имеющему опознавательный знак «Перевозка детей», водитель должен снизить скорость движения, при необходимости остановиться и предоставить преимущество пешеходам.<br> Требование направлено на исключение вероятности наезда на детей (ребёнка) независимо от наличия детей на тротуаре, обочине или проезжей части. Необходимость остановки также возникает в случае подачи лицом, сопровождающим детей, сигнала о намерении перейти дорогу.</p>","image":"assets/adrive-questions/q101401501.jpg"},{"id":101401502,"themeId":5,"group":1014015,"chapter":14,"chapters":[14],"q":"Как должен поступить водитель легкового автомобиля, если на тротуаре находятся дети в сопровождении взрослых?","a":["Снизить скорость движения, при необходимости остановиться и предоставить преимущество пешеходам.","Двигаясь, быть готовым снизить скорость движения или остановиться, чтобы исключить вероятность наезда на детей."],"c":0,"e":"<p>Приближаясь к стоящему транспортному средству с включённой аварийной световой сигнализацией и имеющему опознавательный знак «Перевозка детей», водитель должен снизить скорость движения, при необходимости остановиться и предоставить преимущество пешеходам.<br> Требование направлено на исключение вероятности наезда на детей (ребёнка) независимо от наличия детей на тротуаре, обочине или проезжей части. Необходимость остановки также возникает в случае подачи лицом, сопровождающим детей, сигнала о намерении перейти дорогу.</p>","image":"assets/adrive-questions/q101401502.jpg"},{"id":101401503,"themeId":5,"group":1014015,"chapter":14,"chapters":[14],"q":"Как должен поступить водитель легкового автомобиля в показанной ситуации?","a":["Снизить скорость движения, при необходимости остановиться и предоставить преимущество пешеходу.","Продолжать движение, так как пешеход не имеет преимущества."],"c":0,"e":"<p>Приближаясь к стоящему транспортному средству с включённой аварийной световой сигнализацией и имеющему опознавательный знак «Перевозка детей», водитель должен снизить скорость движения, при необходимости остановиться и предоставить преимущество пешеходам.</p>","image":"assets/adrive-questions/q101401503.jpg"},{"id":101500101,"themeId":5,"group":1015001,"chapter":15,"chapters":[15],"q":"Должен ли водитель зелёного легкового автомобиля уступить дорогу трамваю?","a":["Да, должен.","Нет, не должен."],"c":0,"e":"<p>В показанной ситуации трамвай въезжает в депо.<br> Согласно Правилам дорожного движения, вне перекрёстков в местах, где трамвайные пути пересекают проезжую часть дороги, трамвай имеет преимущество перед другими транспортными средствами, кроме случаев выезда из депо и мест, где очерёдность движения определяется дорожными знаками приоритета или сигналами светофоров.<br> Требование устанавливает преимущество трамваев в движении вне перекрёстков при пересечении трамвайными путями проезжей части.</p>","image":"assets/adrive-questions/q101500101.jpg"},{"id":101500102,"themeId":5,"group":1015001,"chapter":15,"chapters":[15],"q":"Должен ли водитель зелёного легкового автомобиля уступить дорогу трамваю?","a":["Да, должен.","Нет, не должен."],"c":1,"e":"<p>В показанной ситуации трамвай выезжает из депо.<br> Согласно Правилам дорожного движения, вне перекрёстков в местах, где трамвайные пути пересекают проезжую часть дороги, трамвай имеет преимущество перед другими транспортными средствами, кроме случаев выезда из депо и мест, где очерёдность движения определяется дорожными знаками приоритета или сигналами светофоров.<br> Требование устанавливает преимущество трамваев в движении вне перекрёстков при пересечении трамвайными путями проезжей части. Если такие пересечения трамвайных путей проезжей части имеют место на выезде из трамвайного депо, то трамваи теряют преимущество в движении, так как они выезжают с прилегающей территории и ещё не находятся на маршруте.</p>","image":"assets/adrive-questions/q101500102.jpg"},{"id":101500103,"themeId":5,"group":1015001,"chapter":15,"chapters":[15],"q":"Какому из трамваев обязан уступить дорогу водитель зелёного легкового автомобиля?","a":["Только жёлтому трамваю.","Только красному трамваю.","Обязан уступить дорогу обоим трамваям.","В показанной ситуации водитель легкового автомобиля имеет преимущество."],"c":0,"e":"<p>В показанной ситуации красный трамвай выезжает из депо, а жёлтый трамвай въезжает в депо.<br> Согласно Правилам дорожного движения, вне перекрёстков в местах, где трамвайные пути пересекают проезжую часть дороги, трамвай имеет преимущество перед другими транспортными средствами, кроме случаев выезда из депо и мест, где очерёдность движения определяется дорожными знаками приоритета или сигналами светофоров.<br> Требование устанавливает преимущество трамваев в движении вне перекрёстков при пересечении трамвайными путями проезжей части. Если такие пересечения трамвайных путей проезжей части имеют место на выезде из трамвайного депо, то трамваи теряют преимущество в движении, так как они выезжают с прилегающей территории и ещё не находятся на маршруте.</p>","image":"assets/adrive-questions/q101500103.jpg"},{"id":101500121,"themeId":5,"group":1015001,"chapter":15,"chapters":[15],"q":"В показанной ситуации при движении прямо Вы:","a":["Имеете преимущество.","Обязаны уступить дорогу трамваю, заезжающему в депо."],"c":1,"e":"<p>В местах, где трамвайные пути пересекают проезжую часть дороги, трамвай имеет преимущество перед другими транспортными средствами, кроме случаев выезда из депо, а также тех мест, где очерёдность движения определяется дорожными знаками приоритета или сигналами светофоров.</p> <p>В показанной ситуации трамвай не выезжает, а заезжает в депо и имеет преимущество перед безрельсовыми транспортными средствами.</p>","image":"assets/adrive-questions/q101500121.jpg"},{"id":101500203,"themeId":5,"group":1015002,"chapter":15,"chapters":[15],"q":"Разрешено ли продолжить движение, управляя легковым автомобилем, по показанной полосе движения?","a":["Разрешено.","Разрешено, управляя электромобилем.","Разрешено, управляя электромобилем или автомобилем с гибридной силовой установкой.","Запрещено."],"c":1,"e":"<p>На дорогах с полосой движения для маршрутных транспортных средств, обозначенных дорожными знаками «5.9.1 Полоса для маршрутных транспортных средств» , «5.10.1 Дорога с полосой для маршрутных транспортных средств» , также разрешается движение электромобилей по данной полосе.</p>","image":"assets/adrive-questions/q101500203.jpg"},{"id":101500204,"themeId":5,"group":1015002,"chapter":15,"chapters":[15],"q":"По каким из перечисленных полос разрешено продолжить движение после поворота направо на показанную дорогу, управляя автомобилем, который приводится в движение двигателем внутреннего сгорания?","a":["Только по крайней правой полосе.","Только по соседней полосе слева.","По любой из перечисленных полос."],"c":1,"e":"<p>На полосе для движения маршрутных транспортных средств разрешается осуществлять движение электромобилям, по средней полосе движение разрешено всем легковым автомобилям.</p>","image":"assets/adrive-questions/q101500204.jpg"},{"id":101500205,"themeId":5,"group":1015002,"chapter":15,"chapters":[15],"q":"По каким из перечисленных полос разрешено продолжить движение после поворота направо на показанную дорогу, управляя электромобилем?","a":["Только по крайней правой полосе.","Только по соседней полосе слева.","По любой из перечисленных полос."],"c":2,"e":"<p>На полосе для движения маршрутных транспортных средств разрешается осуществлять движение электромобилям, по средней полосе движение разрешено всем легковым автомобилям.</p>","image":"assets/adrive-questions/q101500205.jpg"},{"id":101500301,"themeId":5,"group":1015003,"chapter":15,"chapters":[15],"q":"Разрешено ли Вам, управляя электромобилем, совершить перестроение на крайнюю правую полосу движения с целью опережения?","a":["Да, разрешено.","Нет, не разрешено."],"c":1,"e":"<p>На дороге с полосой движения для маршрутных транспортных средств, обозначенной дорожным знаком «5.9.1 Полоса для маршрутных транспортных средств» , запрещается движение других транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей.</p> <p>Однако в показанной ситуации на дороге с тремя полосами в попутном направлении Вы собираетесь произвести перестроение на крайнюю правую полосу с целью опережения по ней, что запрещено правилами расположения транспортных средств на проезжей части дороги.</p>","image":"assets/adrive-questions/q101500301.jpg"},{"id":101500302,"themeId":5,"group":1015003,"chapter":15,"chapters":[15],"q":"Разрешено ли Вам, управляя электромобилем, совершить перестроение на крайнюю правую полосу движения с целью объезда образовавшегося неподвижного затора?","a":["Да, разрешено.","Нет, не разрешено."],"c":0,"e":"<p>Движение электромобилей разрешено по полосе для маршрутных транспортных средств, поэтому её разрешено использовать в том числе и для объезда затора.</p>","image":"assets/adrive-questions/q101500302.jpg"},{"id":101500401,"themeId":5,"group":1015004,"chapter":15,"chapters":[15],"q":"Должен ли уступить дорогу трамваям водитель жёлтого легкового автомобиля?","a":["Должен уступить дорогу только жёлтому трамваю.","Должен уступить дорогу только красному трамваю.","Должен уступить дорогу обоим трамваям.","Водитель легкового автомобиля имеет преимущество."],"c":2,"e":"<p>Согласно Правилам дорожного движения, вне перекрёстков в местах, где трамвайные пути пересекают проезжую часть дороги, трамвай имеет преимущество перед другими транспортными средствами, кроме случаев выезда из депо и мест, где очерёдность движения определяется дорожными знаками приоритета или сигналами светофоров.<br> Требование устанавливает преимущество трамваев в движении вне перекрёстков при пересечении трамвайными путями проезжей части.</p>","image":"assets/adrive-questions/q101500401.jpg"},{"id":101500402,"themeId":5,"group":1015004,"chapter":15,"chapters":[15],"q":"Водитель жёлтого легкового автомобиля в показанной ситуации (на светофоре включён жёлтый мигающий сигнал):","a":["Имеет преимущество.","Обязан уступить дорогу встречному трамваю."],"c":1,"e":"<p>Согласно Правилам дорожного движения, вне перекрёстков в местах, где трамвайные пути пересекают проезжую часть дороги, трамвай имеет преимущество перед другими транспортными средствами, кроме случаев выезда из депо и мест, где очерёдность движения определяется дорожными знаками приоритета или сигналами светофоров.<br> Требование устанавливает преимущество трамваев в движении вне перекрёстков при пересечении трамвайными путями проезжей части.</p>","image":"assets/adrive-questions/q101500402.jpg"},{"id":101500471,"themeId":5,"group":1015004,"chapter":15,"chapters":[15],"q":"Обязаны ли Вы, управляя легковым автомобилем, уступить дорогу трамваю в показанной ситуации (не выезд из депо)?","a":["Да, обязаны.","Нет, не обязаны."],"c":0,"e":"<p>Вне перекрёстков в местах, где трамвайные пути пересекают проезжую часть дороги, при отсутствии знаков приоритета и светофоров трамвай имеет преимущество перед другими транспортными средствами. Поэтому <strong>Вы обязаны уступить дорогу трамваю</strong>.</p>","image":"assets/adrive-questions/q101500471.jpg"},{"id":101500501,"themeId":5,"group":1015005,"chapter":15,"chapters":[15],"q":"В каких направлениях разрешено продолжить движение водителю автомобиля-такси, приводимого в движение двигателем внутреннего сгорания?","a":["Прямо и направо.","Прямо, налево и на разворот.","Прямо, направо и на разворот.","Во всех направлениях."],"c":2,"e":"<p>На дороге с полосой движения для маршрутных транспортных средств, обозначенных дорожными знаками 5.9.1 «Полоса для маршрутных транспортных средств» , 5.10.1 «Дорога с полосой для маршрутных транспортных средств» , запрещаются движение, остановка и стоянка других транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей. Поэтому в показанной ситуации движение налево по полосе для маршрутных транспортных средств запрещено.</p>","image":"assets/adrive-questions/q101500501.jpg"},{"id":101500502,"themeId":5,"group":1015005,"chapter":15,"chapters":[15],"q":"В каких направлениях Вам, управляя автомобилем, приводимым в движение двигателем внутреннего сгорания, разрешается продолжить движение на перекрёстке?","a":["Только направо.","Налево и на разворот.","Направо и на разворот.","Направо, налево и на разворот."],"c":2,"e":"<p>На дороге с полосой движения для маршрутных транспортных средств, обозначенной дорожными знаками 5.9.1 «Полоса для маршрутных транспортных средств» , 5.10.1 «Дорога с полосой для маршрутных транспортных средств» , запрещаются движение, остановка и стоянка других транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей.</p>","image":"assets/adrive-questions/q101500502.jpg"},{"id":101500503,"themeId":5,"group":1015005,"chapter":15,"chapters":[15],"q":"В каких направлениях Вам разрешается продолжить движение на перекрёстке, управляя электромобилем?","a":["Только налево.","Только направо.","Налево и на разворот.","Направо и на разворот.","Направо, налево и на разворот."],"c":4,"e":"<p>На дороге с полосой движения для маршрутных транспортных средств, обозначенной дорожным знаком «5.10.1 Дорога с полосой для маршрутных транспортных средств» , запрещается движение других транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей.</p> <p>Поэтому, управляя электромобилем, Вам разрешено повернуть и на полосу для движения маршрутных транспортных средств.</p>","image":"assets/adrive-questions/q101500503.jpg"},{"id":101500601,"themeId":5,"group":1015006,"chapter":15,"chapters":[15],"q":"В каких направлениях разрешено продолжить движение водителю автомобиля-такси, приводимого в движение двигателем внутреннего сгорания?","a":["Прямо и налево.","Прямо, налево и на разворот.","Прямо, направо и на разворот.","Во всех направлениях."],"c":1,"e":"<p>На дорогах с полосой движения для маршрутных транспортных средств, обозначенных дорожными знаками 5.9.1 «Полоса для маршрутных транспортных средств» , 5.10.1 «Дорога с полосой для маршрутных транспортных средств» , запрещаются движение, остановка и стоянка других транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей. Поэтому в показанной ситуации движение направо по полосе для маршрутных транспортных средств запрещено.</p>","image":"assets/adrive-questions/q101500601.jpg"},{"id":101500602,"themeId":5,"group":1015006,"chapter":15,"chapters":[15],"q":"В каких направлениях Вам, управляя автомобилем, приводимым в движение двигателем внутреннего сгорания, разрешается продолжить движение на перекрестке?","a":["Только налево.","Только направо.","Только налево и на разворот.","Прямо, налево и на разворот.","Во всех направлениях."],"c":3,"e":"<p>На дорогах с полосой движения для маршрутных транспортных средств, обозначенных дорожными знаками 5.9.1 «Полоса для маршрутных транспортных средств» , 5.10.1 «Дорога с полосой для маршрутных транспортных средств» , запрещаются движение, остановка и стоянка других транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей. Поэтому в показанной ситуации движение направо по полосе для маршрутных транспортных средств запрещено.</p>","image":"assets/adrive-questions/q101500602.jpg"},{"id":101500603,"themeId":5,"group":1015006,"chapter":15,"chapters":[15],"q":"В каких направлениях Вам разрешается продолжить движение на перекрёстке, управляя электромобилем?","a":["Только налево.","Только направо.","Только налево и на разворот.","Прямо, налево и на разворот.","Во всех направлениях."],"c":4,"e":"<p>На дороге с полосой движения для маршрутных транспортных средств, обозначенной дорожным знаком «5.10.1 Дорога с полосой для маршрутных транспортных средств» , запрещается движение других транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей.</p> <p>Поэтому, управляя электромобилем, Вам разрешено повернуть и на полосу для движения маршрутных транспортных средств.</p>","image":"assets/adrive-questions/q101500603.jpg"},{"id":101500704,"themeId":5,"group":1015007,"chapter":15,"chapters":[15],"q":"Разрешено ли водителю белого автомобиля повернуть налево во двор?","a":["Разрешено.","Запрещено."],"c":0,"e":"<p>Согласно Правилам дорожного движения, на дорогах с полосой движения для маршрутных транспортных средств, обозначенных дорожными знаками «5.9.1 Полоса для маршрутных транспортных средств» , «5.10.1 Дорога с полосой для маршрутных транспортных средств» , запрещаются движение, остановка и стоянка других транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей.<br> При этом, пересекать такую полосу движения не запрещено.</p>","image":"assets/adrive-questions/q101500704.jpg"},{"id":101500706,"themeId":5,"group":1015007,"chapter":15,"chapters":[15],"q":"Нарушит ли Правила дорожного движения водитель автомобиля-такси, приводимого в движение двигателем внутреннего сгорания, совершив разворот в показанной ситуации?","a":["Да, нарушит.","Нет, не нарушит.","Не нарушит, если это связано с посадкой (высадкой) пассажиров и не создаст препятствия для движения маршрутных транспортных средств."],"c":0,"e":"<p>В показанной ситуации совершить разворот для автомобиля, который приводится в движение двигателем внутреннего сгорания, с целью движения или остановки на полосе для маршрутных транспортных средств запрещено.</p>","image":"assets/adrive-questions/q101500706.jpg"},{"id":101500708,"themeId":5,"group":1015007,"chapter":15,"chapters":[15],"q":"Нарушит ли Правила дорожного движения водитель автомобиля-такси, приводимого в движение двигателем внутреннего сгорания, совершив разворот на перекрёстке для посадки пассажира?","a":["Да, нарушит.","Нет, не нарушит.","Не нарушит, если это не создаст препятствия для движения маршрутных транспортных средств."],"c":0,"e":"<p>На дорогах с полосой движения для маршрутных транспортных средств, обозначенных дорожными знаками 5.9.1 «Полоса для маршрутных транспортных средств» , 5.10.1 «Дорога с полосой для маршрутных транспортных средств» , запрещаются движение, остановка и стоянка других транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей. Поэтому в показанной ситуации разворот в полосу для маршрутных транспортных средств запрещён.</p>","image":"assets/adrive-questions/q101500708.jpg"},{"id":101500709,"themeId":5,"group":1015007,"chapter":15,"chapters":[15],"q":"В каких направлениях Вам разрешено продолжить движение в показанной ситуации, управляя электромобилем?","a":["Только прямо.","Прямо и налево.","Прямо, налево и на разворот."],"c":2,"e":"<p>На дорогах с полосой движения для маршрутных транспортных средств, обозначенных дорожными знаками «5.9.1 Полоса для маршрутных транспортных средств» , «5.10.1 Дорога с полосой для маршрутных транспортных средств» , запрещаются движение, остановка и стоянка других транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей.</p>","image":"assets/adrive-questions/q101500709.jpg"},{"id":101500737,"themeId":5,"group":1015007,"chapter":15,"chapters":[15],"q":"Нарушает ли Правила дорожного движения водитель автомобиля-такси, приводимого в движение двигателем внутреннего сгорания, двигаясь по данной полосе?","a":["Да, нарушает.","Нет, не нарушает.","Не нарушает, только если движется с включённым ближним светом фар или дневными ходовыми огнями."],"c":0,"e":"<p>На дорогах с полосой движения для маршрутных транспортных средств запрещаются движение, остановка и стоянка других транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей.</p>","image":"assets/adrive-questions/q101500737.jpg"},{"id":101500801,"themeId":5,"group":1015008,"chapter":15,"chapters":[15],"q":"По какой из указанных траекторий водителю синего автомобиля разрешено повернуть направо?","a":["Разрешено только по траектории «А».","Разрешено только по траектории «Б».","Разрешено по обеим траекториям.","Поворот направо в показанной ситуации запрещён."],"c":0,"e":"<p>Согласно Правилам дорожного движения, на дорогах с полосой движения для маршрутных транспортных средств, обозначенных дорожными знаками «5.9.1 Полоса для маршрутных транспортных средств» , 5.10.1 «Дорога с полосой для маршрутных транспортных средств» , запрещаются движение, остановка и стоянка других транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей.<br> Если полоса движения, обозначенная дорожным знаком «5.9.1 Полоса для маршрутных транспортных средств», отделена от остальной проезжей части дороги прерывистой линией горизонтальной дорожной разметки, то для осуществления поворота водитель обязан перестраиваться на неё.</p> <p>Но в показанной ситуации данная полоса отделена сплошной линией горизонтальной дорожной разметки, поэтому поворот направо должен осуществляться без предварительного перестроения на полосу для маршрутных транспортных средств, на основании п. 66, т.к. выполнить поворот направо из крайнего правого положения невозможно.</p>","image":"assets/adrive-questions/q101500801.jpg"},{"id":101500802,"themeId":5,"group":1015008,"chapter":15,"chapters":[15],"q":"По какой из указанных траекторий водителю синего автомобиля разрешено повернуть направо?","a":["Разрешено только по траектории «А».","Разрешено только по траектории «Б».","Разрешено по обеим траекториям."],"c":1,"e":"<p>Согласно Правилам дорожного движения, если полоса движения, обозначенная дорожным знаком 5.9.1 «Полоса для маршрутных транспортных средств» , отделена от остальной проезжей части дороги прерывистой линией горизонтальной дорожной разметки, то для осуществления поворота водитель обязан перестраиваться на неё.</p>","image":"assets/adrive-questions/q101500802.jpg"},{"id":101500803,"themeId":5,"group":1015008,"chapter":15,"chapters":[15],"q":"Как должен поступить водитель синего автомобиля, чтобы повернуть направо, если справа по соседней полосе движется маршрутный автобус?","a":["Снизить скорость и повернуть направо со второй полосы движения, уступив дорогу автобусу.","Снизить скорость, перестроиться на правую полосу движения, уступив дорогу автобусу, а затем повернуть направо."],"c":1,"e":"<p>Согласно Правилам дорожного движения, если полоса движения, обозначенная дорожным знаком 5.9.1 «Полоса для маршрутных транспортных средств» , отделена от остальной проезжей части дороги прерывистой линией горизонтальной дорожной разметки, то для осуществления поворота водитель обязан перестраиваться на неё.</p>","image":"assets/adrive-questions/q101500803.jpg"},{"id":101500804,"themeId":5,"group":1015008,"chapter":15,"chapters":[15],"q":"По каким из показанных траекторий разрешено двигаться водителю чёрного автомобиля, приводимого в движение двигателем внутреннего сгорания, выполняя поворот направо в показанной ситуации?","a":["Только по траектории «А».","Только по траектории «Б».","Только по траектории «В».","По траекториям «А» и «Б».","По траекториям «Б» и «В»."],"c":1,"e":"<p>Если полоса для маршрутных транспортных средств отделена от остальной проезжей части дороги прерывистой линией дорожной разметки (в данной ситуации разметкой 1.11 с прерывистой разметкой к полосе), то для осуществления поворота водитель обязан перестраиваться на неё.<br> Затем водитель может перестроиться на соседнюю полосу движения в месте, разрешённом для перестроения.</p>","image":"assets/adrive-questions/q101500804.jpg"},{"id":101500805,"themeId":5,"group":1015008,"chapter":15,"chapters":[15],"q":"По каким из показанных траекторий разрешено двигаться водителю электромобиля, выполняя поворот направо в показанной ситуации?","a":["Только по траектории «А».","Только по траектории «Б».","Только по траектории «В».","По траекториям «А» и «Б».","По траекториям «Б» и «В»."],"c":4,"e":"<p>Если полоса для маршрутных транспортных средств отделена от остальной проезжей части дороги прерывистой линией дорожной разметки (в данной ситуации разметкой 1.11 с прерывистой разметкой к полосе), то для осуществления поворота водитель обязан перестраиваться на неё.<br> Затем водитель может перестроиться на соседнюю полосу движения в месте, разрешённом для перестроения. <br> При этом водителю электромобиля разрешается продолжить движение по полосе для маршрутных транспортных средств.</p>","image":"assets/adrive-questions/q101500805.jpg"},{"id":101500901,"themeId":5,"group":1015009,"chapter":15,"chapters":[15],"q":"По какой полосе Вам разрешено осуществить опережение грузового автомобиля в показанной ситуации?","a":["Только по левой полосе.","Только по правой полосе.","Только по левой полосе, а при управлении электромобилем — также по правой полосе.","Как по правой, так и по левой полосе."],"c":0,"e":"<p>Несмотря на то, что движение электромобилей разрешено по полосе для маршрутных транспортных средств, при трех и более полосах движения в данном направлении запрещается производить перестроение на крайнюю правую полосу движения в целях опережения по ней.</p>","image":"assets/adrive-questions/q101500901.jpg"},{"id":101500902,"themeId":5,"group":1015009,"chapter":15,"chapters":[15],"q":"По какой полосе Вам разрешено осуществить опережение грузового автомобиля в показанной ситуации?","a":["Только по левой полосе.","Только по правой полосе.","Только по левой полосе, а при управлении электромобилем — также по правой полосе.","Как по правой, так и по левой полосе."],"c":0,"e":"<p>Несмотря на то, что движение электромобилей разрешено по полосе для маршрутных транспортных средств, при трех и более полосах движения в данном направлении запрещается производить перестроение на крайнюю правую полосу движения в целях опережения по ней.<br> Кроме того, для перестроения на крайнюю правую полосу движения необходимо будет пересечь сплошную линию горизонтальной дорожной разметки, что также в сложившейся обстановке запрещено.</p>","image":"assets/adrive-questions/q101500902.jpg"},{"id":101500904,"themeId":5,"group":1015009,"chapter":15,"chapters":[15],"q":"Нарушает ли Правила дорожного движения водитель автомобиля-такси, приводимого в движение двигателем внутреннего сгорания, используя крайнюю правую полосу для движения прямо в показанной ситуации, когда остальные полосы движения заняты?","a":["Да, нарушает.","Нет, не нарушает.","Не нарушает, если это не создаёт препятствия для движения маршрутных транспортных средств."],"c":0,"e":"<p>На дорогах с полосой движения для маршрутных транспортных средств, обозначенных дорожными знаками 5.9.1 «Полоса для маршрутных транспортных средств» , 5.10.1 «Дорога с полосой для маршрутных транспортных средств» , запрещаются движение, остановка и стоянка транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей.</p>","image":"assets/adrive-questions/q101500904.jpg"},{"id":101500933,"themeId":5,"group":1015009,"chapter":15,"chapters":[15],"q":"Разрешено ли Вам, управляя автомобилем, приводимым в движение двигателем внутреннего сгорания, совершить перестроение на крайнюю правую полосу движения с целью опережения?","a":["Да, разрешено.","Нет, не разрешено.","Разрешено, если это не создаст препятствия для движения маршрутных транспортных средств."],"c":1,"e":"<p>На дорогах с полосой движения для маршрутных транспортных средств запрещаются движение, остановка и стоянка других транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей. Несмотря на то, что движение электромобилей разрешено по полосе для маршрутных транспортных средств, при трех и более полосах движения в данном направлении запрещается производить перестроение на крайнюю правую полосу движения в целях опережения по ней.</p>","image":"assets/adrive-questions/q101500933.jpg"},{"id":101500935,"themeId":5,"group":1015009,"chapter":15,"chapters":[15],"q":"По какой траектории водителю красного легкового автомобиля следует выполнить поворот налево, если автомобиль приводится в движение двигателем внутреннего сгорания?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из показанных траекторий.","Поворот налево по обеим траекториям запрещён."],"c":0,"e":"<p>На дорогах с полосой движения для маршрутных транспортных средств запрещаются движение, остановка и стоянка других транспортных средств на этой полосе, за исключением движения в данной полосе электромобилей.</p>","image":"assets/adrive-questions/q101500935.jpg"},{"id":101500952,"themeId":5,"group":1015009,"chapter":15,"chapters":[15],"q":"Нарушает ли Правила дорожного движения водитель электромобиля-такси, двигаясь по данной полосе?","a":["Нарушает.","Не нарушает."],"c":1,"e":"<p>Электромобилям <strong>не запрещается осуществлять движение по полосам для маршрутных транспортных средств</strong>, даже если они отделены от остальных полос сплошной линией горизонтальной дорожной разметки.</p>","image":"assets/adrive-questions/q101500952.jpg"},{"id":101500961,"themeId":5,"group":1015009,"chapter":15,"chapters":[15],"q":"Разрешено ли водителю транспортного средства оперативного назначения движение по занимаемой полосе в показанной ситуации?","a":["Разрешено.","Запрещено.","Разрешено только в случае включения маячков синего цвета."],"c":0,"e":"<p>Пункт 124, запрещающий движение по полосе для маршрутных транспортных средств, не действует на транспортные средства оперативного назначения, <strong>даже если на них не включены маячки синего цвета</strong>.</p>","image":"assets/adrive-questions/q101500961.jpg"},{"id":101501001,"themeId":5,"group":1015010,"chapter":15,"chapters":[15],"q":"Нарушает ли Правила дорожного движения водитель автомобиля-такси, совершив остановку на данной полосе движения?","a":["Да, нарушает.","Не нарушает, если это не создаёт препятствия для движения маршрутных транспортных средств.","Не нарушает, если это связано с посадкой (высадкой) пассажиров и не создаёт препятствия для движения маршрутных транспортных средств."],"c":2,"e":"<p>Если полоса движения, обозначенная дорожным знаком 5.9.1 «Полоса для маршрутных транспортных средств» , отделена от остальной проезжей части дороги прерывистой линией горизонтальной дорожной разметки, то разрешается заезжать на эту полосу для посадки (высадки) пассажиров у правого края проезжей части, если это не создаст препятствия для движения маршрутных транспортных средств.</p>","image":"assets/adrive-questions/q101501001.jpg"},{"id":101501002,"themeId":5,"group":1015010,"chapter":15,"chapters":[15],"q":"Разрешено ли Вам, управляя легковым автомобилем, совершить остановку у правого края проезжей части дороги для посадки или высадки пассажира?","a":["Да, разрешено, только управляя электромобилем.","Нет, не разрешено.","Да, разрешено, если это не создаст препятствия для движения маршрутных транспортных средств."],"c":2,"e":"<p>Если полоса движения, обозначенная дорожным знаком 5.9.1 «Полоса для маршрутных транспортных средств» , отделена от остальной проезжей части дороги прерывистой линией горизонтальной дорожной разметки, то разрешается заезжать на эту полосу для посадки (высадки) пассажиров у правого края проезжей части, если это не создаст препятствия для движения маршрутных транспортных средств.</p>","image":"assets/adrive-questions/q101501002.jpg"},{"id":101501003,"themeId":5,"group":1015010,"chapter":15,"chapters":[15],"q":"Нарушает ли Правила дорожного движения водитель автомобиля-такси, совершив остановку на данной полосе движения для посадки (высадки) пассажиров?","a":["Да, нарушает.","Не нарушает, если это не создаст препятствия для движения маршрутных транспортных средств.","Не нарушает, если заблаговременно перестроился на показанную полосу движения, не пересекая сплошную линию дорожной разметки."],"c":0,"e":"<p>В показанной ситуации полоса для движения маршрутных ТС отделена от остальной проезжей части дороги сплошной линией горизонтальной дорожной разметки.<br> Согласно Правилам дорожного движения, разрешается заезжать на полосу для движения маршрутных ТС для посадки (высадки) пассажиров у правого края проезжей части, только если полоса движения, обозначенная дорожным знаком 5.9.1 «Полоса для маршрутных транспортных средств» , отделена от остальной проезжей части дороги прерывистой линией горизонтальной дорожной разметки.</p>","image":"assets/adrive-questions/q101501003.jpg"},{"id":101501101,"themeId":5,"group":1015011,"chapter":15,"chapters":[15],"q":"Разрешено ли Вам, управляя легковым автомобилем, поставить его на стоянку на показанном участке дороги?","a":["Да, разрешено.","Разрешено поставить на стоянку только электромобиль.","Разрешено поставить в ночное время, на период, когда не осуществляется движение маршрутных транспортных средств.","Нет, не разрешено."],"c":3,"e":"<p>На дорогах с полосой движения для маршрутных транспортных средств, обозначенных дорожными знаками 5.9.1 «Полоса для маршрутных транспортных средств» , 5.10.1 «Дорога с полосой для маршрутных транспортных средств» , запрещается стоянка других транспортных средств на этой полосе.<br> Требование направлено на обеспечение беспрепятственного движения маршрутных ТС.</p>","image":"assets/adrive-questions/q101501101.jpg"},{"id":101501102,"themeId":5,"group":1015011,"chapter":15,"chapters":[15],"q":"Разрешено ли водителю поставить на стоянку автомобиль-такси на данной полосе движения?","a":["Запрещено.","Разрешено с включённым таксометром.","Разрешено, если это не создаст препятствия для движения маршрутных транспортных средств."],"c":0,"e":"<p>Согласно Правилам дорожного движения, на дорогах с полосой движения для маршрутных транспортных средств, обозначенных дорожными знаками 5.9.1 «Полоса для маршрутных транспортных средств» , 5.10.1 «Дорога с полосой для маршрутных транспортных средств» , запрещается стоянка других транспортных средств на этой полосе.<br> Требование направлено на обеспечение беспрепятственного движения маршрутных ТС.</p>","image":"assets/adrive-questions/q101501102.jpg"},{"id":101501151,"themeId":5,"group":1015011,"chapter":15,"chapters":[15],"q":"Разрешено ли Вам, управляя легковым автомобилем, совершить остановку у правого края проезжей части дороги в показанной ситуации?","a":["Да, разрешено.","Разрешено для посадки (высадки) пассажиров у правого края проезжей части, если это не создаст препятствия для движения маршрутных транспортных средств.","Нет, не разрешено."],"c":2,"e":"<p>Разрешается заезжать на полосу для маршрутных транспортных средств, отделённую прерывистой линией разметки, для посадки (высадки) пассажиров у правого края проезжей части дороги, если при этом не будет создано препятствия для движения маршрутных транспортных средств.</p> <p>Но в показанной ситуации остановка запрещена, так как у края проезжей части дороги нанесена жёлтая сплошная линия дорожной разметки, запрещающая остановку.</p>","image":"assets/adrive-questions/q101501151.jpg"},{"id":101501201,"themeId":5,"group":1015012,"chapter":15,"chapters":[15],"q":"Разрешено ли Вам, управляя электромобилем, совершить остановку с целью посадки пассажира на показанном участке дороги?","a":["Да, разрешено.","Разрешено, если это не создаст препятствия для движения маршрутных транспортных средств.","Нет, не разрешено."],"c":1,"e":"<p>На полосе для движения маршрутных транспортных средств разрешается осуществлять движение электромобилям, однако посадка (высадка) пассажиров на ней разрешена, только если данная полоса отделена от остальной проезжей части дороги прерывистой линией дорожной разметки, и если это не создаст препятствия для движения маршрутных транспортных средств.</p>","image":"assets/adrive-questions/q101501201.jpg"},{"id":101501202,"themeId":5,"group":1015012,"chapter":15,"chapters":[15],"q":"Разрешено ли Вам, управляя электромобилем, совершить остановку с целью посадки пассажира на показанном участке дороги?","a":["Да, разрешено.","Разрешено, если это не создаст препятствия для движения маршрутных транспортных средств.","Нет, не разрешено."],"c":2,"e":"<p>На полосе для движения маршрутных транспортных средств разрешается осуществлять движение электромобилям, однако посадка (высадка) пассажиров на ней разрешена, только если данная полоса отделена от остальной проезжей части дороги прерывистой линией дорожной разметки.<br> Кроме того, очевидно, что при остановке расстояние до сплошной линии разметки составило бы менее 3 метров.</p>","image":"assets/adrive-questions/q101501202.jpg"},{"id":101501203,"themeId":5,"group":1015012,"chapter":15,"chapters":[15],"q":"Разрешено ли Вам, управляя электромобилем, совершить остановку с целью, не связанной с посадкой (высадкой) пассажира на показанном участке дороги?","a":["Да, разрешено.","Разрешено, если это не создаст препятствия для движения маршрутных транспортных средств.","Нет, не разрешено."],"c":2,"e":"<p>На полосе для движения маршрутных транспортных средств разрешается осуществлять движение электромобилям, однако остановка может быть разрешена только для посадки (высадки) пассажиров и только при условии, если данная полоса отделена от остальной проезжей части дороги прерывистой линией дорожной разметки, и если это не создаст препятствия для движения маршрутных транспортных средств.</p>","image":"assets/adrive-questions/q101501203.jpg"},{"id":101501301,"themeId":5,"group":1015013,"chapter":15,"chapters":[15],"q":"Должны ли Вы, управляя легковым автомобилем, уступить дорогу троллейбусу, начинающему движение от обозначенного остановочного пункта в показанной ситуации?","a":["Да, должны.","Нет, не должны."],"c":0,"e":"<p>Согласно Правилам дорожного движения, в населённом пункте водитель транспортного средства, движущегося по крайней правой полосе, должен уступить дорогу маршрутному транспортному средству, начинающему движение от обозначенного остановочного пункта, при его перестроении на крайнюю правую полосу движения. Положение направлено на уменьшение времени задержек маршрутных ТС, начинающих движение от обозначенных остановочных пунктов.</p>","image":"assets/adrive-questions/q101501301.jpg"},{"id":101501303,"themeId":5,"group":1015013,"chapter":15,"chapters":[15],"q":"Как Вам необходимо поступить в показанной ситуации в населённом пункте?","a":["Проехать первым, пользуясь преимуществом.","Уступить дорогу водителю зелёного автомобиля, начинающего движение от обозначенного остановочного пункта."],"c":0,"e":"<p>В показанной ситуации от остановочного пункта начинает движение легковой автомобиль, а не маршрутное транспортное средство.</p> <p>Согласно Правилам дорожного движения, в населённом пункте водитель транспортного средства, движущегося по крайней правой полосе, должен уступить дорогу только маршрутному транспортному средству, начинающему движение от обозначенного остановочного пункта, при его перестроении на крайнюю правую полосу движения. Положение направлено на уменьшение времени задержек маршрутных транспортных средств, начинающих движение от обозначенных остановочных пунктов.</p>","image":"assets/adrive-questions/q101501303.jpg"},{"id":101501305,"themeId":5,"group":1015013,"chapter":15,"chapters":[15],"q":"Должны ли Вы уступить дорогу автомобилю-такси, начинающему движение в населённом пункте?","a":["Да, должны.","Нет, не должны."],"c":1,"e":"<p>В показанной ситуации от остановочного пункта начинает движение легковой автомобиль-такси, а не маршрутное транспортное средство.</p> <p>Согласно Правилам дорожного движения, в населённом пункте водитель транспортного средства, движущегося по крайней правой полосе, должен уступить дорогу только маршрутному транспортному средству, начинающему движение от обозначенного остановочного пункта, при его перестроении на крайнюю правую полосу движения. Положение направлено на уменьшение времени задержек маршрутных транспортных средств, начинающих движение от обозначенных остановочных пунктов.</p>","image":"assets/adrive-questions/q101501305.jpg"},{"id":101501306,"themeId":5,"group":1015013,"chapter":15,"chapters":[15],"q":"Кто в показанной ситуации обязан уступить дорогу?","a":["Водитель трактора.","Водитель легкового автомобиля, начинающий движение от обозначенного остановочного пункта."],"c":1,"e":"<p>В показанной ситуации от остановочного пункта начинает движение легковой автомобиль, а не маршрутное транспортное средство.<br> Согласно Правилам дорожного движения, в населённом пункте водитель транспортного средства, движущегося по крайней правой полосе, должен уступить дорогу маршрутному транспортному средству, начинающему движение от обозначенного остановочного пункта, при его перестроении на крайнюю правую полосу движения. Положение направлено на уменьшение времени задержек маршрутных ТС, начинающих движение от обозначенных остановочных пунктов.</p>","image":"assets/adrive-questions/q101501306.jpg"},{"id":101501401,"themeId":5,"group":1015014,"chapter":15,"chapters":[15],"q":"Должен ли водитель синего легкового автомобиля уступить дорогу автобусу, начинающему движение вне населённого пункта?","a":["Да, должен.","Нет, не должен."],"c":1,"e":"<p>Согласно Правилам дорожного движения, только в населённом пункте водитель транспортного средства, движущегося по крайней правой полосе, должен уступить дорогу маршрутному транспортному средству, начинающему движение от обозначенного остановочного пункта, при его перестроении на крайнюю правую полосу движения. Положение направлено на уменьшение времени задержек маршрутных ТС, начинающих движение от обозначенных остановочных пунктов.</p>","image":"assets/adrive-questions/q101501401.jpg"},{"id":101501403,"themeId":5,"group":1015014,"chapter":15,"chapters":[15],"q":"Должен ли водитель синего легкового автомобиля при движении вне населённого пункта уступить дорогу маршрутному автобусу, совершающему перестроение?","a":["Да, должен.","Нет, не должен."],"c":1,"e":"<p>Согласно Правилам дорожного движения, только в населённом пункте водитель транспортного средства, движущегося по крайней правой полосе, должен уступить дорогу маршрутному транспортному средству, начинающему движение от обозначенного остановочного пункта, при его перестроении на крайнюю правую полосу движения. В показанной ситуации легковой автомобиль движется по дороге вне населённого пункта, к тому же по второй полосе движения.</p>","image":"assets/adrive-questions/q101501403.jpg"},{"id":101501701,"themeId":5,"group":1015017,"chapter":15,"chapters":[15],"q":"Должны ли Вы в показанной ситуации при движении в населённом пункте уступить дорогу автобусу, начинающему движение от обозначенного остановочного пункта?","a":["Да, должны.","Нет, не должны."],"c":1,"e":"<p>В показанной ситуации водитель автобуса перестраивается в крайнюю левую полосу движения.<br> Согласно Правилам дорожного движения, в населённом пункте водитель транспортного средства, движущегося по крайней правой полосе, должен уступить дорогу маршрутному транспортному средству, начинающему движение от обозначенного остановочного пункта, при его перестроении на крайнюю правую полосу движения. Положение направлено на уменьшение времени задержек маршрутных ТС, начинающих движение от обозначенных остановочных пунктов.</p>","image":"assets/adrive-questions/q101501701.jpg"},{"id":101501702,"themeId":5,"group":1015017,"chapter":15,"chapters":[15],"q":"Должны ли Вы, управляя легковым автомобилем, при движении в населённом пункте уступить дорогу автобусу, совершающему в показанной ситуации перестроение в конце зоны остановочного пункта?","a":["Да, должны.","Нет, не должны."],"c":1,"e":"<p>В показанной ситуации водитель автобуса перестраивается в третью полосу движения.<br> Согласно Правилам дорожного движения, в населённом пункте водитель транспортного средства, движущегося по крайней правой полосе, должен уступить дорогу маршрутному транспортному средству, начинающему движение от обозначенного остановочного пункта, при его перестроении на крайнюю правую полосу движения. Положение направлено на уменьшение времени задержек маршрутных ТС, начинающих движение от обозначенных остановочных пунктов.</p>","image":"assets/adrive-questions/q101501702.jpg"},{"id":101501704,"themeId":5,"group":1015017,"chapter":15,"chapters":[15],"q":"Должны ли Вы, управляя автомобилем в населённом пункте в показанной ситуации, уступить дорогу начинающему движение от обозначенного остановочного пункта маршрутному транспортному средству?","a":["Да, должны.","Нет, водитель маршрутного транспортного средства обязан уступить Вам дорогу."],"c":0,"e":"<p>В населённом пункте Вы, двигаясь по крайней правой полосе, должны уступить дорогу маршрутному транспортному средству, начинающему движение от обозначенного остановочного пункта, при его перестроении на крайнюю правую полосу движения, то есть как в показанной ситуации.</p>","image":"assets/adrive-questions/q101501704.jpg"},{"id":101600101,"themeId":5,"group":1016001,"chapter":16,"chapters":[16],"q":"Разрешается ли не останавливаться в показанной ситуации перед «стоп-линией»?","a":["Разрешается, убедившись в отсутствии запрещающих сигналов светофора.","Разрешается, убедившись в отсутствии приближающегося железнодорожного транспортного средства.","Разрешается при интенсивном движении при выключенных сигналах светофора и поднятом шлагбауме.","Запрещается."],"c":3,"e":"<p>В показанной ситуации перед железнодорожным переездом наряду с установленным дорожным знаком 2.5 \"Движение без остановки запрещено\" нанесена линия разметки 1.12 «стоп-линия» , поэтому водителю необходимо остановиться перед ней независимо от сигналов светофора и положения шлагбаума.</p>","image":"assets/adrive-questions/q101600101.jpg"},{"id":101600132,"themeId":5,"group":1016001,"chapter":16,"chapters":[16],"q":"В каком месте водитель должен остановиться, если в пределах видимости к железнодорожному переезду не приближается железнодорожное транспортное средство?","a":["Перед светофором.","Перед линией разметки «стоп-линия».","При отсутствии в пределах видимости приближающегося железнодорожного транспортного средства останавливаться необязательно."],"c":1,"e":"<p>При подъезде к участку дороги, на котором установлен знак 2.5 «Движение без остановки запрещено», а также к железнодорожному переезду, движение через который не запрещено, водитель должен остановиться перед знаком 5.33 «Стоп-линия» (горизонтальной дорожной разметкой 1.12 «стоп-линия» ).</p>","image":"assets/adrive-questions/q101600132.jpg"},{"id":101600201,"themeId":5,"group":1016002,"chapter":16,"chapters":[16],"q":"В чём Вы должны убедиться, подъехав к железнодорожному переезду?","a":["В отсутствии в пределах видимости железнодорожного транспортного средства.","В отсутствии в пределах видимости приближающегося железнодорожного транспортного средства.","В отсутствии в пределах видимости приближающегося или отдаляющегося железнодорожного транспортного средства."],"c":1,"e":"<p>Согласно Правилам дорожного движения, при подъезде к железнодорожному переезду водитель обязан убедиться в отсутствии приближающегося железнодорожного транспортного средства и руководствоваться указаниями дежурного по железнодорожному переезду, требованиями светофоров, дорожных знаков, дорожной разметки, положением шлагбаума и звуковым сигналом.<br> Правила дорожного движения не конкретизирует, каким способом водитель должен убедиться в том, что к переезду не приближается железнодорожное ТС, поскольку выбор способа зависит от конкретной дорожно-транспортной ситуации, складывающейся на железнодорожном переезде.</p>","image":"assets/adrive-questions/q101600201.jpg"},{"id":101600202,"themeId":5,"group":1016002,"chapter":16,"chapters":[16],"q":"Кто в показанной ситуации обязан уступить дорогу?","a":["Водитель легкового автомобиля.","Машинист железнодорожного транспортного средства, движущегося с минимальной скоростью."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при пересечении железнодорожных путей водители обязаны уступить дорогу железнодорожным транспортным средствам.</p>","image":"assets/adrive-questions/q101600202.jpg"},{"id":101600301,"themeId":5,"group":1016003,"chapter":16,"chapters":[16],"q":"Что Вы обязаны выполнить в показанной ситуации, если технические средства организации дорожного движения не запрещают движение через железнодорожный переезд?","a":["Убедиться в исправности технических средств организации дорожного движения.","Определить на слух, не приближается ли железнодорожное транспортное средство.","Убедиться в отсутствии в пределах видимости приближающегося железнодорожного транспортного средства.","Обязаны выполнить всё перечисленное."],"c":2,"e":"<p>Согласно Правилам дорожного движения, при подъезде к железнодорожному переезду водитель обязан убедиться в отсутствии приближающегося железнодорожного транспортного средства и руководствоваться указаниями дежурного по железнодорожному переезду, требованиями светофоров, дорожных знаков, дорожной разметки, положением шлагбаума и звуковым сигналом.</p>","image":"assets/adrive-questions/q101600301.jpg"},{"id":101600302,"themeId":5,"group":1016003,"chapter":16,"chapters":[16],"q":"Чем должен руководствоваться водитель при подъезде к железнодорожному переезду?","a":["Требованиями дорожных знаков и дорожной разметки.","Указаниями дежурного по железнодорожному переезду.","Всем перечисленным."],"c":2,"e":"<p>Согласно Правилам дорожного движения, при подъезде к железнодорожному переезду водитель обязан убедиться в отсутствии приближающегося железнодорожного транспортного средства и руководствоваться указаниями дежурного по железнодорожному переезду, требованиями светофоров, дорожных знаков, дорожной разметки, положением шлагбаума и звуковым сигналом.<br> Водитель ТС при подъезде к железнодорожному переезду и движении через него должен руководствоваться требованиями установленных там технических средств организации дорожного движения, указаниями дежурного по этому переезду и подчиняться им.</p>","image":"assets/adrive-questions/q101600302.jpg"},{"id":101600401,"themeId":5,"group":1016004,"chapter":16,"chapters":[16],"q":"Разрешается ли проехать в показанной ситуации через железнодорожный переезд, если локомотив остановился, перекрыв только встречную полосу движения?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается на минимальной скорости, включив аварийную световую сигнализацию."],"c":1,"e":"<p>В показанной ситуации на светофоре включены запрещающие сигналы.<br> Согласно Правилам дорожного движения, запрещается выезжать на железнодорожный переезд при запрещающем сигнале светофора.</p>","image":"assets/adrive-questions/q101600401.jpg"},{"id":101600402,"themeId":5,"group":1016004,"chapter":16,"chapters":[16],"q":"Как должен поступить водитель синего автомобиля в показанной ситуации (поезд стоит, на светофоре включены красные мигающие сигналы)?","a":["Остановиться перед светофором.","Проехать через железнодорожный переезд, так как с иных направлений в показанной ситуации железнодорожное транспортное средство приблизиться не может."],"c":0,"e":"<p>В показанной ситуации на светофоре включены запрещающие сигналы.<br> Согласно Правилам дорожного движения, запрещается выезжать на железнодорожный переезд при запрещающем сигнале светофора.</p>","image":"assets/adrive-questions/q101600402.jpg"},{"id":101600403,"themeId":5,"group":1016004,"chapter":16,"chapters":[16],"q":"Как должен поступить водитель синего автомобиля в показанной ситуации (железнодорожное транспортное средство в пределах видимости отсутствует, сзади скопились транспортные средства)?","a":["Проехать через переезд с особой осторожностью.","Оставаться в показанном месте, не выезжая на железнодорожный переезд."],"c":1,"e":"<p>В показанной ситуации на светофоре включены запрещающие сигналы.<br> Согласно Правилам дорожного движения, запрещается выезжать на железнодорожный переезд при запрещающем сигнале светофора.</p>","image":"assets/adrive-questions/q101600403.jpg"},{"id":101600501,"themeId":5,"group":1016005,"chapter":16,"chapters":[16],"q":"Разрешается ли Вам в показанной ситуации выехать на железнодорожный переезд, остановившись в ожидании проезда встречного автомобиля, с целью дальнейшего объезда препятствия по встречной полосе?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации за железнодорожным переездом образовался затор.<br> Согласно Правилам дорожного движения, запрещается выезжать на железнодорожный переезд, если за железнодорожным переездом образовался затор, который вынудит водителя остановиться на железнодорожном переезде. Требование обязывает водителя ТС внимательно следить за движущимися через ж/д переезд ТС с целью своевременного обнаружения образовавшегося в направлении движения транспортного затора, в результате чего может сложиться ситуация вынужденной остановки на ж/д пути или рядом с ним.</p>","image":"assets/adrive-questions/q101600501.jpg"},{"id":101600502,"themeId":5,"group":1016005,"chapter":16,"chapters":[16],"q":"Разрешается ли Вам в показанной ситуации выехать на железнодорожный переезд, если это не вынудит Вас остановиться на нём?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации на светофоре включён запрещающий сигнал.<br> Запрещается выезжать на железнодорожный переезд при запрещающем сигнале светофора.</p>","image":"assets/adrive-questions/q101600502.jpg"},{"id":101600601,"themeId":5,"group":1016006,"chapter":16,"chapters":[16],"q":"Как должен поступить водитель легкового автомобиля, если через переезд только что проследовал поезд?","a":["Проехать через железнодорожный переезд.","Не возобновлять движение, пока проследовавший поезд не исчезнет из поля зрения.","Убедиться в отсутствии приближающегося железнодорожного транспортного средства, после чего проехать через железнодорожный переезд."],"c":2,"e":"<p>Согласно Правилам дорожного движения, при подъезде к железнодорожному переезду водитель обязан убедиться в отсутствии приближающегося железнодорожного транспортного средства и руководствоваться указаниями дежурного по железнодорожному переезду, требованиями светофоров, дорожных знаков, дорожной разметки, положением шлагбаума и звуковым сигналом.<br> Правила дорожного движения не конкретизирует, каким способом водитель должен убедиться в том, что к переезду не приближается железнодорожное ТС, поскольку выбор способа зависит от конкретной дорожно-транспортной ситуации, складывающейся на железнодорожном переезде.</p>","image":"assets/adrive-questions/q101600601.jpg"},{"id":101600602,"themeId":5,"group":1016006,"chapter":16,"chapters":[16],"q":"Как должен поступить водитель легкового автомобиля, если через переезд только что проследовал поезд?","a":["Проехать через железнодорожный переезд.","Не возобновлять движение, пока проследовавший поезд не исчезнет из поля зрения.","Убедиться в отсутствии приближающегося железнодорожного транспортного средства слева, после чего проехать через железнодорожный переезд.","Убедиться в отсутствии приближающегося железнодорожного транспортного средства слева и справа (подождав, пока поезд не удалится на значительное расстояние), после чего проехать через железнодорожный переезд."],"c":3,"e":"<p>Согласно Правилам дорожного движения, при подъезде к железнодорожному переезду водитель обязан убедиться в отсутствии приближающегося железнодорожного транспортного средства и руководствоваться указаниями дежурного по железнодорожному переезду, требованиями светофоров, дорожных знаков, дорожной разметки, положением шлагбаума и звуковым сигналом.<br> Правила дорожного движения не конкретизирует, каким способом водитель должен убедиться в том, что к переезду не приближается железнодорожное ТС, поскольку выбор способа зависит от конкретной дорожно-транспортной ситуации, складывающейся на железнодорожном переезде.</p> <p>В показанной ситуации прошедший поезд ограничивает обзорность второго железнодорожного пути, поэтому убедиться в отсутствии встречного железнодорожного транспортного средства можно только после того, как проследовавший поезд удалится от переезда.</p>","image":"assets/adrive-questions/q101600602.jpg"},{"id":101600701,"themeId":5,"group":1016007,"chapter":16,"chapters":[16],"q":"В каких случаях из перечисленных запрещается выезжать на железнодорожный переезд?","a":["При запрещающем сигнале светофора и открытом шлагбауме.","При закрытом или начинающем закрываться шлагбауме и выключенном светофоре.","Если дежурный по железнодорожному переезду обращён к водителю грудью или спиной с вытянутыми в стороны руками.","Запрещается во всех перечисленных случаях."],"c":3,"e":"<p>Согласно Правилам дорожного движения, запрещается выезжать на железнодорожный переезд:</p> <ul><li>при закрытом или начинающем закрываться шлагбауме независимо от сигнала светофора;</li> <li>при запрещающем сигнале светофора независимо от наличия и положения шлагбаума;</li> <li>при запрещающем сигнале дежурного по железнодорожному переезду (дежурный обращён к водителю грудью или спиной с поднятым над головой фонарём, излучающим красный свет, или флажком красного цвета, либо с вытянутыми в стороны руками);</li> <li>если за железнодорожным переездом образовался затор, который вынудит водителя остановиться на железнодорожном переезде;</li> <li>если к железнодорожному переезду в пределах видимости приближается железнодорожное транспортное средство.</li></ul> <p>Помимо перечисленных требований, на железнодорожном переезде запрещаются разворот, обгон, остановка и стоянка транспортных средств, а также движение задним ходом.</p>","image":null},{"id":101600752,"themeId":5,"group":1016007,"chapter":16,"chapters":[16],"q":"Разрешено ли Вам, управляя автомобилем, выехать на железнодорожный переезд в показанной ситуации?","a":["Разрешено.","Запрещено.","Разрешено, если к переезду не приближается железнодорожное транспортное средство."],"c":1,"e":"<p><strong>Запрещается выезжать на железнодорожный переезд при запрещающем сигнале светофора</strong> независимо от положения шлагбаума, даже если на данный момент не видно приближающегося железнодорожного транспортного средства.</p>","image":"assets/adrive-questions/q101600752.jpg"},{"id":101600801,"themeId":5,"group":1016008,"chapter":16,"chapters":[16],"q":"Разрешается ли в показанной ситуации объехать стоящее перед железнодорожным переездом транспортное средство?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, запрещается объезжать с выездом на встречную полосу движения стоящие перед железнодорожным переездом транспортные средства.</p>","image":"assets/adrive-questions/q101600801.jpg"},{"id":101600802,"themeId":5,"group":1016008,"chapter":16,"chapters":[16],"q":"Разрешается ли в показанной ситуации объехать стоящее перед железнодорожным переездом транспортное средство?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>В показанной ситуации водитель объезжает стоящее ТС перед ж/д переездом без выезда на полосу встречного движения. Согласно Правилам дорожного движения, запрещается объезжать с выездом на встречную полосу движения стоящие перед железнодорожным переездом транспортные средства, поэтому показанный манёвр будет разрешён.</p>","image":"assets/adrive-questions/q101600802.jpg"},{"id":101600901,"themeId":5,"group":1016009,"chapter":16,"chapters":[16],"q":"Водителю какого автомобиля разрешается объехать стоящие перед переездом транспортные средства так, как показано на рисунке?","a":["Только водителю синего автомобиля.","Только водителю зелёного автомобиля.","Разрешается обоим водителям.","Запрещается обоим водителям."],"c":1,"e":"<p>Согласно Правилам дорожного движения, запрещается объезжать с выездом на встречную полосу движения стоящие перед железнодорожным переездом транспортные средства. В показанной ситуации имеется свободная полоса в попутном направлении, поэтому водителю зелёного автомобиля разрешено объехать стоящие ТС перед ж/д переездом. Водителю синего автомобиля такой манёвр будет запрещён, так как нанесена сплошная линия горизонтальной дорожной разметки 1.1, которую в данной ситуации пересекать запрещено.</p>","image":"assets/adrive-questions/q101600901.jpg"},{"id":101600902,"themeId":5,"group":1016009,"chapter":16,"chapters":[16],"q":"Разрешено ли Вам в показанной ситуации открыть шлагбаум (сигналы светофора выключены, через переезд движутся встречные транспортные средства)?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, запрещается самовольно открывать шлагбаум. Категорически запрещено водителю ТС или любому другому лицу, кроме дежурного по ж/д переезду, самовольно открывать шлагбаум, поскольку это может ввести в заблуждение водителей и повлечь столкновение ТС с ж/д транспортным средством.</p>","image":"assets/adrive-questions/q101600902.jpg"},{"id":101601032,"themeId":5,"group":1016010,"chapter":16,"chapters":[16],"q":"Разрешается ли водителю синего автомобиля объехать стоящее транспортное средство так, как показано на рисунке?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>В показанной ситуации перед железнодорожным переездом водитель красного автомобиля совершил вынужденную остановку. В попутном направлении имеется свободная полоса, которую в данной ситуации можно использовать для объезда препятствия.</p>","image":"assets/adrive-questions/q101601032.jpg"},{"id":101601201,"themeId":5,"group":1016012,"chapter":16,"chapters":[16],"q":"С каким максимальным габаритом по высоте от поверхности дороги допускается движение транспортных средств через указанный переезд без согласования с начальником дистанции электроснабжения организации Белорусской железной дороги?","a":["3 метра.","3.5 метра.","4 метра.","4.2 метра."],"c":2,"e":"<p>Согласно Правилам дорожного движения, запрещается движение через железнодорожный переезд на электрифицированных участках транспортных средств, габаритные размеры которых с грузом или без груза превышают по высоте 4 метра от поверхности дороги, — без согласования с начальником дистанции электроснабжения организации Белорусской железной дороги. Требование преследует цель обеспечения безопасности и исключения соприкосновения ТС с контактной сетью.</p>","image":"assets/adrive-questions/q101601201.jpg"},{"id":101601202,"themeId":5,"group":1016012,"chapter":16,"chapters":[16],"q":"С какой минимальной скоростью разрешается движение через железнодорожный переезд тихоходных транспортных средств без разрешения начальника дистанции пути железной дороги?","a":["4 км/ч.","8 км/ч.","10 км/ч.","12 км/ч."],"c":1,"e":"<p>Согласно Правилам дорожного движения, запрещается движение через железнодорожный переезд тихоходных транспортных средств, скорость движения которых менее 8 км/ч, и саней-волокуш — без разрешения начальника дистанции пути железной дороги. Требования направлены на предотвращение ситуаций, в которых есть вероятность столкновения с ж/д транспортным средством.</p>","image":"assets/adrive-questions/q101601202.jpg"},{"id":101601203,"themeId":5,"group":1016012,"chapter":16,"chapters":[16],"q":"С кем необходимо согласовать проезд тихоходного транспортного средства, скорость которого менее 8 км/ч, через показанный на рисунке железнодорожный переезд?","a":["С Госавтоинспекцией.","С дежурным по переезду.","С начальником дистанции пути железной дороги.","С начальником дистанции электроснабжения организации Белорусской железной дороги."],"c":2,"e":"<p>Согласно Правилам дорожного движения, запрещается движение через железнодорожный переезд тихоходных транспортных средств, скорость движения которых менее 8 км/ч, и саней-волокуш — без разрешения начальника дистанции пути железной дороги. Разрешение на передвижение через ж/д переезд даётся при соблюдении требований безопасности. Например, для тихоходного ТС даётся временной интервал движения, когда обеспечивается запас времени (нет движения поездов) для совершения такого передвижения. Требования направлены на предотвращения ситуаций, в которых есть вероятность столкновения с ж/д транспортным средством.</p>","image":"assets/adrive-questions/q101601203.jpg"},{"id":101601301,"themeId":5,"group":1016013,"chapter":16,"chapters":[16],"q":"В каком из указанных мест Вам необходимо остановиться в показанной ситуации?","a":["Перед светофором.","Не ближе 5 метров до ближайшего рельса.","Не ближе 10 метров до ближайшего рельса.","У дорожного знака «Движение без остановки запрещено»."],"c":3,"e":"<p>В показанной ситуации мигают красные запрещающие сигналы светофора.<br> Согласно Правилам дорожного движения, в случае, когда движение через железнодорожный переезд запрещено, водитель должен остановиться у дорожного знака 2.5 «Движение без остановки запрещено» .</p>","image":"assets/adrive-questions/q101601301.jpg"},{"id":101601302,"themeId":5,"group":1016013,"chapter":16,"chapters":[16],"q":"Кто из водителей остановился перед железнодорожным переездом в соответствии с Правилами дорожного движения в показанной ситуации?","a":["Водитель автобуса.","Водитель легкового автомобиля.","Оба водителя остановились в соответствии с Правилами дорожного движения."],"c":0,"e":"<p>В показанной ситуации мигают красные запрещающие сигналы светофора.<br> Согласно Правилам дорожного движения, в случае, когда движение через железнодорожный переезд запрещено, водители должны остановиться у «стоп-линии» (линии горизонтальной дорожной разметки 1.12 ).<br> Водитель легкового автомобиля остановился на меньшем расстоянии до железнодорожного переезда, чем разрешено Правилами дорожного движения.</p>","image":"assets/adrive-questions/q101601302.jpg"},{"id":101601401,"themeId":5,"group":1016014,"chapter":16,"chapters":[16],"q":"Как должен поступить водитель легкового автомобиля, если он заметил приближающийся вдали поезд, а шлагбаум открыт и на светофоре не горят запрещающие сигналы?","a":["Остановиться перед светофором.","Остановиться не ближе 5 метров от шлагбаума.","Остановиться не ближе 10 метров до ближайшего рельса.","Остановиться перед дорожным знаком «Движение без остановки запрещено».","Проехать железнодорожный переезд, пока не закрылся шлагбаум и не сработала сигнализация."],"c":3,"e":"<p>В данной ситуации к ж/д переезду приближается поезд.<br> Согласно Правилам дорожного движения, в случае, когда движение через железнодорожный переезд запрещено, водитель должен остановиться у дорожного знака 2.5 «Движение без остановки запрещено» .<br> Места остановки ТС перед ж/д переездом определены с учётом обеспечения безопасности остановившихся ТС.</p>","image":"assets/adrive-questions/q101601401.jpg"},{"id":101601402,"themeId":5,"group":1016014,"chapter":16,"chapters":[16],"q":"Как должен поступить водитель легкового автомобиля, если он заметил стоящий вдали поезд, а шлагбаум открыт и на светофоре не горят запрещающие сигналы?","a":["Остановиться перед дорожным знаком «Движение без остановки запрещено».","Остановиться не ближе 5 метров от шлагбаума.","Остановиться не ближе 10 метров до ближайшего рельса.","Остановиться перед «Стоп-линией» и проехать железнодорожный переезд, убедившись в отсутствии другого приближающегося железнодорожного транспортного средства."],"c":3,"e":"<p>В данной ситуации к ж/д переезду не приближается железнодорожное транспортное средство.<br> Установленный перед ж/д переездом дорожный знак 2.5 «Движение без остановки запрещено» обязывает водителей остановиться перед \"стоп-линией\" независимо от того, что движение через ж/д переезд не запрещено. Затем можно продолжить движение через переезд, убедившись в отсутствии приближающегося железнодорожного транспортного средства.</p>","image":"assets/adrive-questions/q101601402.jpg"},{"id":101601501,"themeId":5,"group":1016015,"chapter":16,"chapters":[16],"q":"Нарушил ли Правила дорожного движения водитель легкового автомобиля, остановившись перед переездом так, как показано на рисунке?","a":["Да, нарушил.","Нет, не нарушил."],"c":1,"e":"<p>В показанной ситуации к ж/д переезду приближается поезд.<br> Согласно Правилам дорожного движения, в случае, когда движение через железнодорожный переезд запрещено, водитель должен остановиться не ближе 10 метров до ближайшего рельса. Поэтому водитель легкового автомобиля, остановившись на расстоянии в 12 метров, не нарушил Правила дорожного движения.</p>","image":"assets/adrive-questions/q101601501.jpg"},{"id":101601502,"themeId":5,"group":1016015,"chapter":16,"chapters":[16],"q":"На каком расстоянии до ближайшего рельса должен остановиться водитель автомобиля в показанной ситуации?","a":["Не ближе 5 метров.","Не ближе 10 метров.","Не ближе 15 метров.","От 5 до 15 метров."],"c":1,"e":"<p>В показанной ситуации к ж/д переезду приближается поезд. Согласно Правилам дорожного движения, в случае, когда движение через железнодорожный переезд запрещено, водитель должен остановиться не ближе 10 метров до ближайшего рельса.</p>","image":"assets/adrive-questions/q101601502.jpg"},{"id":101601601,"themeId":5,"group":1016016,"chapter":16,"chapters":[16],"q":"Как должен поступить водитель в показанной ситуации?","a":["Остановиться перед светофором.","Остановиться не ближе 5 метров от шлагбаума.","Проехать железнодорожный переезд с особой осторожностью.","Остановиться перед дежурным по железнодорожному переезду."],"c":0,"e":"<p>В показанной ситуации дежурный по ж/д переезду показывает запрещающий сигнал.<br> Согласно Правилам дорожного движения, в случае, когда движение через железнодорожный переезд запрещено, водитель должен остановиться у дорожного знака 1.3.1 «Однопутная железная дорога» .<br> Места остановки транспортных средств перед ж/д переездом определены с учётом обеспечения безопасности остановившихся ТС.</p>","image":"assets/adrive-questions/q101601601.jpg"},{"id":101601602,"themeId":5,"group":1016016,"chapter":16,"chapters":[16],"q":"Как должен поступить водитель легкового автомобиля в показанной ситуации?","a":["Остановиться перед светофором.","Остановиться перед «стоп-линией».","Безостановочно проехать железнодорожный переезд.","Снизить скорость и проехать железнодорожный переезд с особой осторожностью."],"c":1,"e":"<p>В показанной ситуации дежурный по ж/д переезду показывает запрещающий сигнал.<br> Согласно Правилам дорожного движения, в случае, когда движение через железнодорожный переезд запрещено, водитель должен остановиться у «стоп-линии» (линии горизонтальной дорожной разметки 1.12 ).<br> Места остановки транспортных средств перед ж/д переездом определены с учётом обеспечения безопасности остановившихся ТС.</p>","image":"assets/adrive-questions/q101601602.jpg"},{"id":101601701,"themeId":5,"group":1016017,"chapter":16,"chapters":[16],"q":"В каком месте из перечисленных необходимо остановиться водителю мотоцикла, если к железнодорожному переезду в пределах видимости приближается локомотив?","a":["Не ближе 5 метров до ближайшего рельса.","У дорожного знака «Однопутная железная дорога».","У дорожного знака «Движение без остановки запрещено»."],"c":2,"e":"<p>В данной ситуации к ж/д переезду приближается локомотив.<br> Согласно Правилам дорожного движения, в случае, когда движение через железнодорожный переезд запрещено, водитель должен остановиться у дорожного знака 2.5 «Движение без остановки запрещено» .<br> Места остановки транспортных средств перед ж/д переездом определены с учётом обеспечения безопасности остановившихся ТС.</p>","image":"assets/adrive-questions/q101601701.jpg"},{"id":101601702,"themeId":5,"group":1016017,"chapter":16,"chapters":[16],"q":"Правильно ли остановился водитель легкового автомобиля в условиях, когда движение через железнодорожный переезд запрещено?","a":["Да, правильно.","Нет, неправильно."],"c":1,"e":"<p>Согласно Правилам дорожного движения, в случае, когда движение через железнодорожный переезд запрещено, водитель должен остановиться у дорожного знака 2.5 «Движение без остановки запрещено» .<br> Места остановки транспортных средств перед ж/д переездом определены с учётом обеспечения безопасности остановившихся ТС.<br> Водитель легкового автомобиля остановился на меньшем расстоянии до железнодорожного переезда, чем разрешено Правилами дорожного движения, проехав место установки дорожного знака «Движение без остановки запрещено».</p>","image":"assets/adrive-questions/q101601702.jpg"},{"id":101601801,"themeId":5,"group":1016018,"chapter":16,"chapters":[16],"q":"Нарушили ли Правила дорожного движения водители автомобилей, остановившись перед железнодорожным переездом так, как показано на рисунке?","a":["Нарушил водитель синего автомобиля.","Нарушил водитель красного автомобиля.","Водители обоих автомобилей не нарушили Правила дорожного движения."],"c":2,"e":"<p>Согласно Правилам дорожного движения, в показанной ситуации, когда движение через железнодорожный переезд запрещено, водители должны остановиться перед светофором.<br> Точное расстояние до светофора Правилами дорожного движения не установлено. Поэтому оба водителя не нарушили Правила дорожного движения.</p>","image":"assets/adrive-questions/q101601801.jpg"},{"id":101601802,"themeId":5,"group":1016018,"chapter":16,"chapters":[16],"q":"Водитель какого автомобиля остановился правильно для пропуска локомотива?","a":["Водитель синего автомобиля.","Водитель красного автомобиля.","Оба водителя в показанной ситуации остановились правильно."],"c":1,"e":"<p>Согласно Правилам дорожного движения, в показанной ситуации водители должны остановиться у дорожного знака 1.3.2 «Многопутная железная дорога» .<br> Места остановки транспортных средств перед ж/д переездом определены с учётом обеспечения безопасности остановившихся ТС.<br> В показанной ситуации только водитель красного автомобиля остановился в соответствии с Правилами дорожного движения.</p>","image":"assets/adrive-questions/q101601802.jpg"},{"id":101602001,"themeId":5,"group":1016020,"chapter":16,"chapters":[16],"q":"В каком месте необходимо остановиться водителю легкового автомобиля в показанной ситуации?","a":["Перед шлагбаумом.","Не ближе 5 метров от шлагбаума.","Не ближе 10 метров до ближайшего рельса.","У дорожного знака «Многопутная железная дорога»."],"c":1,"e":"<p>Согласно Правилам дорожного движения, в случае, когда движение через железнодорожный переезд запрещено, водитель должен остановиться не ближе 5 метров от шлагбаума.<br> Места остановки транспортных средств перед ж/д переездом определены с учётом обеспечения безопасности остановившихся ТС.</p>","image":"assets/adrive-questions/q101602001.jpg"},{"id":101602002,"themeId":5,"group":1016020,"chapter":16,"chapters":[16],"q":"На каком расстоянии от шлагбаума необходимо остановиться водителю легкового автомобиля в показанной ситуации?","a":["Не ближе 5 метров от шлагбаума.","Не ближе 10 метров от шлагбаума.","Непосредственно перед шлагбаумом.","На любом удобном водителю расстоянии."],"c":0,"e":"<p>Согласно Правилам дорожного движения, в случае, когда движение через железнодорожный переезд запрещено, водитель должен остановиться не ближе 5 метров от шлагбаума.<br> Места остановки транспортных средств перед ж/д переездом определены с учётом обеспечения безопасности остановившихся ТС.</p>","image":"assets/adrive-questions/q101602002.jpg"},{"id":101602101,"themeId":5,"group":1016021,"chapter":16,"chapters":[16],"q":"В каком месте мотоциклист обязан остановиться в показанной ситуации?","a":["Не ближе 10 метров до ближайшего рельса.","Перед дежурным по железнодорожному переезду.","У дорожного знака «Однопутная железная дорога».","Не ближе 5 метров от дежурного по железнодорожному переезду."],"c":2,"e":"<p>В показанной ситуации дежурный по ж/д переезду показывает запрещающий сигнал.<br> Согласно Правилам дорожного движения, в показанной ситуации водитель должен остановиться у дорожного знака 1.3.1 «Однопутная железная дорога» .<br> Места остановки транспортных средств перед ж/д переездом определены с учётом обеспечения безопасности остановившихся ТС.</p>","image":"assets/adrive-questions/q101602101.jpg"},{"id":101602102,"themeId":5,"group":1016021,"chapter":16,"chapters":[16],"q":"В каком месте мотоциклист обязан остановиться в показанной ситуации?","a":["Перед светофором.","Не ближе 10 метров до ближайшего рельса.","Перед дежурным по железнодорожному переезду.","Не ближе 5 метров от дежурного по железнодорожному переезду."],"c":0,"e":"<p>В показанной ситуации дежурный по ж/д переезду показывает запрещающий сигнал.<br> Согласно Правилам дорожного движения, в показанной ситуации водитель должен остановиться перед светофором.<br> Места остановки транспортных средств перед ж/д переездом определены с учётом обеспечения безопасности остановившихся ТС.</p>","image":"assets/adrive-questions/q101602102.jpg"},{"id":101602201,"themeId":5,"group":1016022,"chapter":16,"chapters":[16],"q":"Что представляет собой сигнал общей тревоги?","a":["Телефонный звонок в МЧС.","Длинный непрерывный звуковой сигнал.","Серии из одного длинного и трёх коротких звуковых сигналов.","Круговое движение руки (днём — с лоскутом яркой материи или каким-либо хорошо видимым предметом, ночью — с фонарём или факелом)."],"c":2,"e":"<p>Сигнал общей тревоги должен подаваться сериями, состоящими из одного длинного и трёх коротких звуковых сигналов.</p>","image":"assets/adrive-questions/q101602201.jpg"},{"id":101602202,"themeId":5,"group":1016022,"chapter":16,"chapters":[16],"q":"Как правильно подавать сигнал общей тревоги?","a":["Серии из одного длинного и трёх коротких звуковых сигналов.","Серии из одного короткого и трёх длинных звуковых сигналов.","Серии из трёх коротких, трёх длинных и затем опять трёх коротких звуковых сигналов."],"c":0,"e":"<p>Сигнал общей тревоги должен подаваться сериями, состоящими из одного длинного и трёх коротких звуковых сигналов.</p>","image":"assets/adrive-questions/q101602202.jpg"},{"id":101602301,"themeId":5,"group":1016023,"chapter":16,"chapters":[16],"q":"В каком ответе водитель, совершивший вынужденную остановку на железнодорожном переезде, поступил в соответствии с Правилами дорожного движения?","a":["Включил аварийную световую сигнализацию, высадил пассажиров, после чего попытался запустить двигатель.","Попытался запустить двигатель, после неудачной попытки — включил аварийную световую сигнализацию и высадил пассажиров.","Высадил пассажиров, попытался запустить двигатель, после неудачной попытки — включил аварийную световую сигнализацию и выставил знак аварийной остановки."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при вынужденной остановке транспортного средства на железнодорожном переезде водитель обязан включить аварийную световую сигнализацию, немедленно высадить пассажиров и принять меры для освобождения железнодорожного переезда.<br> Если на ж/д переезде есть дежурный, то необходимо руководствоваться его указаниями.</p>","image":"assets/adrive-questions/q101602301.jpg"},{"id":101602302,"themeId":5,"group":1016023,"chapter":16,"chapters":[16],"q":"Что необходимо сделать в первую очередь при вынужденной остановке на железнодорожном переезде?","a":["Немедленно попытаться освободить железнодорожный переезд.","Включить аварийную световую сигнализацию и высадить пассажиров.","Включить аварийную световую сигнализацию и выставить знак аварийной остановки."],"c":1,"e":"<p>Согласно Правилам дорожного движения, при вынужденной остановке транспортного средства на железнодорожном переезде водитель обязан незамедлительно включить аварийную световую сигнализацию, предупредив тем самым всех участников дорожного движения о сложившейся опасной ситуации на дороге, немедленно высадить пассажиров и принять меры для освобождения железнодорожного переезда.<br> Если на ж/д переезде есть дежурный, то необходимо руководствоваться его указаниями.</p>","image":"assets/adrive-questions/q101602302.jpg"},{"id":101602401,"themeId":5,"group":1016024,"chapter":16,"chapters":[16],"q":"В каком ответе водитель, совершивший вынужденную остановку на железнодорожном переезде, поступил в соответствии с Правилами дорожного движения?","a":["Не имея возможности освободить железнодорожный переезд, остался в транспортном средстве и подавал сигнал общей тревоги.","Не имея возможности освободить железнодорожный переезд, остался возле транспортного средства и подавал сигнал общей тревоги.","Не имея возможности освободить железнодорожный переезд, пошёл в сторону худшей видимости железнодорожного пути для подачи сигнала остановки машинисту железнодорожного транспортного средства."],"c":1,"e":"<p>Согласно Правилам дорожного движения, при вынужденной остановке транспортного средства на железнодорожном переезде водитель обязан включить аварийную световую сигнализацию, немедленно высадить пассажиров и принять меры для освобождения железнодорожного переезда.<br> В случае невозможности освободить железнодорожный переезд — оставаться возле транспортного средства и подавать сигналы общей тревоги (серии из одного длинного и трёх коротких звуковых сигналов).<br> Если на ж/д переезде есть дежурный, то необходимо руководствоваться его указаниями.</p>","image":"assets/adrive-questions/q101602401.jpg"},{"id":101602402,"themeId":5,"group":1016024,"chapter":16,"chapters":[16],"q":"В какую сторону следует послать пассажира при вынужденной остановке на железнодорожном переезде?","a":["В сторону ближайшей железнодорожной станции.","В сторону лучшей видимости железнодорожного пути.","В сторону худшей видимости железнодорожного пути.","В сторону наиболее вероятного появления железнодорожного транспортного средства."],"c":2,"e":"<p>Согласно Правилам дорожного движения, при вынужденной остановке транспортного средства на железнодорожном переезде водитель обязан включить аварийную световую сигнализацию, немедленно высадить пассажиров и принять меры для освобождения железнодорожного переезда.<br> Если невозможно освободить железнодорожный переезд, то необходимо послать двух человек вдоль железнодорожных путей в обе стороны от переезда на 1 километр (если одного, то в сторону худшей видимости железнодорожного пути).</p>","image":"assets/adrive-questions/q101602402.jpg"},{"id":101602501,"themeId":5,"group":1016025,"chapter":16,"chapters":[16],"q":"Как должен выглядеть сигнал остановки машинисту железнодорожного транспортного средства в светлое время суток в случае вынужденной остановки на железнодорожном переезде?","a":["Движение руки вверх-вниз с лоскутом яркой материи или каким-либо хорошо видимым предметом.","Круговое движение руки с лоскутом яркой материи или каким-либо хорошо видимым предметом.","Движение руки из стороны в сторону с лоскутом яркой материи или каким-либо хорошо видимым предметом.","Скрещивание и разведение рук над головой с лоскутами яркой материи или какими-либо хорошо видимыми предметами."],"c":1,"e":"<p>Сигналом остановки поезда служит круговое движение руки (днём — с лоскутом яркой материи или каким-либо хорошо видимым предметом, ночью — с фонарём или факелом).<br> Своевременная подача сигнала остановки водителем или пассажиром транспортного средства позволит машинисту поезда раньше прибегнуть к экстренному торможению с целью избежать столкновения или, в худшем случае, снизить тяжесть последствий такого столкновения.</p>","image":"assets/adrive-questions/q101602501.jpg"},{"id":101602502,"themeId":5,"group":1016025,"chapter":16,"chapters":[16],"q":"Как должен выглядеть сигнал остановки машинисту железнодорожного транспортного средства в тёмное время суток в случае вынужденной остановки на железнодорожном переезде?","a":["Круговое движение руки с фонарём или факелом.","Движение руки вверх-вниз с фонарём или факелом.","Движение руки из стороны в сторону с фонарём или факелом.","Скрещивание и разведение рук над головой с фонарём или факелом."],"c":0,"e":"<p>Сигналом остановки поезда в тёмное время суток служит круговое движение руки с фонарём или факелом.<br> Своевременная подача сигнала остановки водителем или пассажиром транспортного средства позволит машинисту поезда раньше прибегнуть к экстренному торможению с целью избежать столкновения или, в худшем случае, снизить тяжесть последствий такого столкновения.</p>","image":"assets/adrive-questions/q101602502.jpg"},{"id":101602601,"themeId":5,"group":1016026,"chapter":16,"chapters":[16],"q":"Что должен делать водитель транспортного средства, совершивший вынужденную остановку на железнодорожном переезде, при появлении железнодорожного транспортного средства?","a":["Предпринять последнюю попытку освободить железнодорожный переезд.","Бежать ему навстречу, подавая сигнал остановки и соблюдая меры предосторожности.","До последней возможности подавать сигнал общей тревоги, соблюдая меры предосторожности.","Отойти от транспортного средства на безопасное расстояние, подавая сигнал остановки машинисту железнодорожного транспортного средства."],"c":1,"e":"<p>Согласно Правилам дорожного движения, при вынужденной остановке транспортного средства на железнодорожном переезде водитель при появлении железнодорожного транспортного средства обязан бежать ему навстречу, подавая сигнал остановки и соблюдая меры предосторожности. Сигналом остановки служит круговое движение руки (днём — с лоскутом яркой материи или каким-либо хорошо видимым предметом, ночью — с фонарём или факелом).</p>","image":"assets/adrive-questions/q101602601.jpg"},{"id":101602602,"themeId":5,"group":1016026,"chapter":16,"chapters":[16],"q":"Каким должно быть первое действие водителя, совершившего вынужденную остановку на железнодорожном переезде?","a":["Подать сигнал общей тревоги.","Сообщить о случившемся в милицию.","Выставить знак аварийной остановки.","Включить аварийную световую сигнализацию.","Принять меры к немедленному освобождению переезда."],"c":3,"e":"<p>Согласно Правилам дорожного движения, при вынужденной остановке транспортного средства на железнодорожном переезде водитель обязан включить аварийную световую сигнализацию, предупредив тем самым всех участников дорожного движения о сложившейся опасной ситуации на дороге, немедленно высадить пассажиров и принять меры для освобождения железнодорожного переезда.</p>","image":"assets/adrive-questions/q101602602.jpg"},{"id":101700101,"themeId":5,"group":1017001,"chapter":17,"chapters":[17],"q":"Нарушают ли Правила дорожного движения водители, двигаясь по автомагистрали со скоростью менее 40 км/ч (автобус не может развивать скорость более 40 км/ч)?","a":["Нарушает только водитель автобуса.","Нарушает только водитель легкового автомобиля.","Нарушают оба водителя."],"c":0,"e":"<p>Согласно Правилам дорожного движения, на автомагистралях запрещается движение транспортных средствах, которые по техническим причинам не могут развивать скорость движения более 40 км/ч. Такие транспортные средства представляют собой препятствие для дорожного движения быстро передвигающихся механических ТС. В тоже время ТС, которые по своим техническим характеристикам могут двигаться со скоростью более 40 км/ч, в целях обеспечения безопасности дорожного движения на отдельных участках автомагистрали могут двигаться со скоростью менее 40 км/ч. Со скоростью менее 40 км/ч по автомагистрали могут двигаться, например, организованные транспортные колонны.</p>","image":"assets/adrive-questions/q101700101.jpg"},{"id":101700102,"themeId":5,"group":1017001,"chapter":17,"chapters":[17],"q":"Нарушают ли Правила дорожного движения водители, двигаясь по автомагистрали с указанными скоростями по причинам, не связанным с техническими?","a":["Нарушает только водитель колёсного трактора, движущийся со скоростью 45 км/ч.","Нарушает только водитель легкового автомобиля, движущийся со скоростью 35 км/ч.","Нарушают оба водителя.","Не нарушают оба водителя."],"c":0,"e":"<p>Согласно Правилам дорожного движения, на автомагистралях запрещается движение на колёсных тракторах. Такие транспортные средства представляют собой препятствие для дорожного движения быстро передвигающихся механических ТС.</p> <p>В тоже время ТС, которые по своим техническим характеристикам могут двигаться со скоростью более 40 км/ч, в целях обеспечения безопасности дорожного движения на отдельных участках автомагистрали могут двигаться со скоростью менее 40 км/ч. Со скоростью менее 40 км/ч по автомагистрали могут двигаться, например, организованные транспортные колонны.</p>","image":"assets/adrive-questions/q101700102.jpg"},{"id":101700201,"themeId":5,"group":1017002,"chapter":17,"chapters":[17],"q":"Каким транспортным средствам запрещается двигаться по автомагистрали со скоростью 40 км/ч?","a":["Транспортным средствам, которые по техническим причинам не могут развивать скорость движения более 40 км/ч.","Транспортным средствам, которые по иным причинам, кроме технических, не развивают скорость более 40 км/ч.","Всем транспортным средствам."],"c":0,"e":"<p>Согласно Правилам дорожного движения, на автомагистралях запрещается движение транспортных средств, которые по техническим причинам не могут развивать скорость движения более 40 км/ч. Такие транспортные средства могут представлять препятствие для дорожного движения быстро передвигающимся механическим ТС. В то же время ТС, которые по своим техническим характеристикам могут двигаться со скоростью более 40 км/ч, в целях обеспечения безопасности дорожного движения на отдельных участках автомагистрали могут двигаться со скоростью менее 40 км/ч. Со скоростью менее 40 км/ч по автомагистрали могут двигаться организованные транспортные колонны и проч.</p>","image":null},{"id":101700202,"themeId":5,"group":1017002,"chapter":17,"chapters":[17],"q":"Разрешается ли на мопеде двигаться по автомагистрали?","a":["Разрешается.","Запрещается.","Разрешается только по обочине.","Разрешается только со скоростью более 40 км/ч."],"c":1,"e":"<p>Согласно Правилам дорожного движения, на автомагистралях запрещается движение на мопедах. Такие транспортные средства могут представлять препятствие для дорожного движения быстро передвигающимся механическим ТС.</p>","image":null},{"id":101700301,"themeId":5,"group":1017003,"chapter":17,"chapters":[17],"q":"Должен ли водитель грузового автомобиля, совершившего вынужденную остановку на обочине, выставить знак аварийной остановки в показанной ситуации?","a":["Да, должен.","Нет, не должен."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 5.4 «Конец дороги для автомобилей» с табличкой информирует о том, что грузовой автомобиль совершил вынужденную остановку на дороге для автомобилей.</p> <p>Согласно Правилам дорожного движения, на автомагистралях запрещается остановка транспортных средств вне площадок для стоянки, обозначенных дорожными знаками 5.15 «Место стоянки» , 6.11 «Место отдыха» . После включения аварийной световой сигнализации должен быть незамедлительно выставлен знак аварийной остановки при вынужденной остановке транспортного средства на проезжей части дороги и в местах, где остановка запрещена.<br> Требования Правил дорожного движения, установленные для движения по автомагистрали, распространяются также на дороги, обозначенные дорожным знаком 5.3 «Дорога для автомобилей» .</p>","image":"assets/adrive-questions/q101700301.jpg"},{"id":101700302,"themeId":5,"group":1017003,"chapter":17,"chapters":[17],"q":"Должен ли водитель грузового автомобиля, совершившего вынужденную остановку на обочине, выставить знак аварийной остановки в показанной ситуации?","a":["Да, должен.","Нет, не должен."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 5.3 «Дорога для автомобилей» с табличкой информирует о том, что водитель грузового автомобиля совершил вынужденную остановку на дороге общего пользования, на расстоянии менее 800 метров до начала дороги для автомобилей.<br> То есть в показанном месте остановка на обочине не запрещена.</p> <p>Согласно Правилам дорожного движения, знак аварийной остановки выставляется в местах, где остановка запрещена. Кроме того, в показанной ситуации разрешено выключить аварийную световую сигнализацию.</p>","image":"assets/adrive-questions/q101700302.jpg"},{"id":101700401,"themeId":5,"group":1017004,"chapter":17,"chapters":[17],"q":"Разрешено ли водителю легкового автомобиля в показанной ситуации совершить остановку на обочине?","a":["Да, разрешено.","Нет, не разрешено."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 5.2 «Конец автомагистрали» с табличкой информирует о том, что легковой автомобиль ещё находится на автомагистрали.<br> Согласно Правилам дорожного движения, на автомагистралях запрещается остановка транспортных средств вне площадок для стоянки, обозначенных дорожными знаками 5.15 «Место стоянки» , 6.11 «Место отдыха» .</p>","image":"assets/adrive-questions/q101700401.jpg"},{"id":101700402,"themeId":5,"group":1017004,"chapter":17,"chapters":[17],"q":"Разрешено ли водителю легкового автомобиля в показанной ситуации совершить остановку на обочине?","a":["Да, разрешено.","Нет, не разрешено."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 5.1 «Автомагистраль» с табличкой информирует о том, что водитель легкового автомобиля намерен совершить остановку на дороге общего пользования, на расстоянии менее 400 метров до начала автомагистрали, то есть в том месте, где ещё разрешена остановка на обочине.</p>","image":"assets/adrive-questions/q101700402.jpg"},{"id":101700462,"themeId":5,"group":1017004,"chapter":17,"chapters":[17],"q":"Нарушил ли водитель Правила дорожного движения, совершив остановку для кратковременного отдыха на обочине дороги, обозначенной дорожным знаком «5.3 Дорога для автомобилей»?","a":["Нарушил.","Не нарушил, если не было создано препятствия и опасности для движения других участников дорожного движения."],"c":0,"e":"<p>На автомагистралях и дорогах для автомобилей остановка и стоянка разрешены только на местах для стоянки, обозначенных дорожными знаками <strong>«Место стоянки», «Место отдыха»</strong>.</p> <p><strong>Остановка и стоянка на обочине запрещены</strong>.</p>","image":"assets/adrive-questions/q101700462.jpg"},{"id":101700501,"themeId":5,"group":1017005,"chapter":17,"chapters":[17],"q":"По какой траектории разрешено развернуться водителю синего легкового автомобиля?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из показанных на рисунке траекторий."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 5.3 «Дорога для автомобилей» информирует о том, что легковой автомобиль находится на дороге для автомобилей.<br> Согласно Правилам дорожного движения, на автомагистралях запрещается разворот и въезд в разрывы разделительной полосы, за исключением мест, обозначенных дорожными знаками 5.11.1 «Место для разворота» , 5.11.2 «Зона для разворота» .<br> Требования Правил дорожного движения, установленные для движения по автомагистрали, распространяются также на дороги, обозначенные дорожным знаком «Дорога для автомобилей».</p> <p>Разрывы в разделительной полосе, не обозначенные дорожными знаками 5.11.1 «Место для разворота», 5.11.2 «Зона для разворота», являются технологическими и не предназначены для разворота транспортных средств, участвующих в дорожном движении.<br> Технологические разрывы предназначены для возможности движения дорожных машин, предназначенных для ремонтных и уборочных работ, а также для движения ТС оперативного назначения.</p>","image":"assets/adrive-questions/q101700501.jpg"},{"id":101700502,"themeId":5,"group":1017005,"chapter":17,"chapters":[17],"q":"По какой траектории разрешено развернуться водителю синего легкового автомобиля?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из показанных на рисунке траекторий."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 5.3 «Дорога для автомобилей» информирует о том, что легковой автомобиль находится на дороге для автомобилей.<br> Согласно Правилам дорожного движения, на автомагистралях запрещается разворот и въезд в разрывы разделительной полосы, за исключением мест, обозначенных дорожными знаками 5.11.1 «Место для разворота» , 5.11.2 «Зона для разворота» .<br> Требования Правил дорожного движения, установленные для движения по автомагистрали, распространяются также на дороги, обозначенные дорожным знаком «Дорога для автомобилей».</p> <p>С данного направления только первый разрыв разделительной полосы обозначен дорожным знаком «Место для разворота».</p>","image":"assets/adrive-questions/q101700502.jpg"},{"id":101700503,"themeId":5,"group":1017005,"chapter":17,"chapters":[17],"q":"Разрешено ли в показанной ситуации развернуться водителям транспортных средств через разрыв разделительной полосы?","a":["Разрешено только водителю автомобиля скорой помощи с выключенными маячками синего цвета.","Разрешено только водителю грузового автомобиля дорожно-эксплуатационной службы с включённым маячком оранжевого цвета в ходе выполнения работ на дороге.","Разрешено водителям обоих транспортных средств.","Запрещено водителям обоих транспортных средств."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 5.3 «Дорога для автомобилей» информирует о том, что водители находятся на дороге для автомобилей.<br> Согласно Правилам дорожного движения, на автомагистралях запрещается разворот и въезд в разрывы разделительной полосы, за исключением мест, обозначенных дорожными знаками 5.11.1 «Место для разворота» , 5.11.2 «Зона для разворота» .<br> Требования Правил дорожного движения, установленные для движения по автомагистрали, распространяются также на дороги, обозначенные дорожным знаком «Дорога для автомобилей».</p> <p>Разрывы в разделительной полосе, не обозначенные дорожными знаками 5.11.1 «Место для разворота», 5.11.2 «Зона для разворота», являются технологическими и не предназначены для разворота транспортных средств, участвующих в дорожном движении.<br> Технологические разрывы предназначены для возможности движения дорожных машин, предназначенных для ремонтных и уборочных работ, а также для движения транспортных средств оперативного назначения. Все перечисленные ТС снабжены проблесковыми световыми сигналами (маячками), которые в целях обеспечения безопасности должны быть включены при движении через технологические разрывы.<br> Водитель автомобиля скорой помощи не включил маячок синего цвета, поэтому не имеет права отступать от требований главы 17 Правил дорожного движения.</p>","image":"assets/adrive-questions/q101700503.jpg"},{"id":101700601,"themeId":5,"group":1017006,"chapter":17,"chapters":[17],"q":"В каком месте на дороге, обозначенной дорожным знаком «Дорога для автомобилей», разрешена остановка мотоциклам без бокового прицепа?","a":["На площадке, обозначенной дорожным знаком «Место отдыха».","На обочине при условии видимости дороги не менее 100 метров в обоих направлениях.","В любом из указанных мест."],"c":0,"e":"<p>Согласно Правилам дорожного движения, на автомагистралях запрещается остановка транспортных средств вне площадок для стоянки, обозначенных дорожными знаками 5.15 «Место стоянки» , 6.11 «Место отдыха» .<br> Требования Правил дорожного движения, установленные для движения по автомагистрали, распространяются также на дороги, обозначенные дорожным знаком 5.3 «Дорога для автомобилей» .</p>","image":null},{"id":101700602,"themeId":5,"group":1017006,"chapter":17,"chapters":[17],"q":"Водитель какого транспортного средства совершил остановку на обочине, не нарушив Правила дорожного движения?","a":["Только водитель легкового автомобиля.","Водители мотоцикла и легкового автомобиля.","Только водитель мотоцикла для посадки пассажира.","Все водители не нарушили Правила дорожного движения в показанной ситуации.","Все водители нарушили Правила дорожного движения в показанной ситуации."],"c":4,"e":"<p>Согласно Правилам дорожного движения, на автомагистралях запрещается остановка транспортных средств вне площадок для стоянки, обозначенных дорожными знаками 5.15 «Место стоянки» , 6.11 «Место отдыха» .<br> Требования Правил дорожного движения, установленные для движения по автомагистрали, распространяются также на дороги, обозначенные дорожным знаком 5.3 «Дорога для автомобилей» .</p>","image":"assets/adrive-questions/q101700602.jpg"},{"id":101700701,"themeId":5,"group":1017007,"chapter":17,"chapters":[17],"q":"Кто в показанной ситуации нарушает Правила дорожного движения, при развороте въезжая в разрыв разделительной полосы?","a":["Водитель автомобиля скорой помощи с выключенным маячком синего цвета.","Водитель автомобиля, перевозящего опасный груз, с включённым маячком оранжевого цвета.","Оба водителя нарушают.","Оба водителя не нарушают."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 5.3 «Дорога для автомобилей» информирует о том, что водители находятся на дороге для автомобилей.<br> Согласно Правилам дорожного движения, на автомагистралях запрещается разворот и въезд в разрывы разделительной полосы, за исключением мест, обозначенных дорожными знаками 5.11.1 «Место для разворота» , 5.11.2 «Зона для разворота» .<br> Требования Правил дорожного движения, установленные для движения по автомагистрали, распространяются также на дороги, обозначенные дорожным знаком «Дорога для автомобилей».</p> <p>Разрывы в разделительной полосе, не обозначенные дорожными знаками 5.11.1 «Место для разворота», 5.11.2 «Зона для разворота», являются технологическими и не предназначены для разворота транспортных средств, участвующих в дорожном движении.<br> Технологические разрывы предназначены для возможности движения дорожных машин, предназначенных для ремонтных и уборочных работ, а также для движения транспортных средств оперативного назначения. Все перечисленные ТС снабжены проблесковыми световыми сигналами (маячками), которые в целях обеспечения безопасности должны быть включены при движении через технологические разрывы.<br> При этом включение маячка оранжевого цвета при перевозке опасных грузов не даёт возможности водителю отступать от требований Правил дорожного движения. Водитель автомобиля скорой помощи также не имеет права отступать от требований ПДД, так как не включил маячок синего цвета.</p>","image":"assets/adrive-questions/q101700701.jpg"},{"id":101700702,"themeId":5,"group":1017007,"chapter":17,"chapters":[17],"q":"Водителю какого транспортного средства разрешено развернуться в показанном месте?","a":["Водителю транспортного средства, перевозящего опасный груз с включённым маячком оранжевого цвета.","Водителю транспортного средства дорожно-эксплуатационной службы с выключенным маячком оранжевого цвета.","Обоим в показанной ситуации разворот разрешён.","Обоим в показанной ситуации разворот запрещён."],"c":3,"e":"<p>В показанной ситуации установленный дорожный знак 5.3 «Дорога для автомобилей» информирует о том, что водители находятся на дороге для автомобилей.<br> Согласно Правилам дорожного движения, на автомагистралях запрещается разворот и въезд в разрывы разделительной полосы, за исключением мест, обозначенных дорожными знаками 5.11.1 «Место для разворота» , 5.11.2 «Зона для разворота» .<br> Требования Правил дорожного движения, установленные для движения по автомагистрали, распространяются также на дороги, обозначенные дорожным знаком «Дорога для автомобилей».</p> <p>Разрывы в разделительной полосе, не обозначенные дорожными знаками 5.11.1 «Место для разворота», 5.11.2 «Зона для разворота», являются технологическими и не предназначены для разворота транспортных средств, участвующих в дорожном движении.<br> Технологические разрывы предназначены для возможности движения дорожных машин, предназначенных для ремонтных и уборочных работ, а также для движения транспортных средств оперативного назначения. Все перечисленные ТС снабжены проблесковыми световыми сигналами (маячками), которые в целях обеспечения безопасности должны быть включены при движении через технологические разрывы.<br> При этом включение маячка оранжевого цвета при перевозке опасных грузов не даёт возможности водителю отступать от требований Правил дорожного движения. Водитель автомобиля дорожно-эксплуатационной службы также не имеет права отступать от требований ПДД, так как не включил маячок оранжевого цвета.</p>","image":"assets/adrive-questions/q101700702.jpg"},{"id":101700801,"themeId":5,"group":1017008,"chapter":17,"chapters":[17],"q":"Каким образом должна быть проведена эвакуация (буксировка) неисправного транспортного средства методом частичной погрузки в показанной ситуации?","a":["Двигаться вперёд до ближайшего съезда с автомагистрали, на котором съехать с неё.","Двигаться назад до показанного на рисунке съезда с автомагистрали, на котором съехать с неё.","Двигаться по автомагистрали непосредственно до места назначения в показанной ситуации не запрещено."],"c":0,"e":"<p>Согласно Правилам дорожного движения, на автомагистралях запрещается движение задним ходом, а также буксировка механического транспортного средства (при его эвакуации необходимо покинуть автомагистраль на ближайшем съезде с неё).<br> Требование направлено на обеспечение безопасности дорожного движения на автомагистрали.</p>","image":"assets/adrive-questions/q101700801.jpg"},{"id":101700802,"themeId":5,"group":1017008,"chapter":17,"chapters":[17],"q":"Каким образом должна быть осуществлена буксировка неисправного транспортного средства по автомагистрали?","a":["Со скоростью не более 50 км/ч до ближайшего съезда с автомагистрали.","Со скоростью не менее 40 км/ч до ближайшего съезда с автомагистрали.","Со скоростью от 40 до 50 км/ч до ближайшего съезда с автомагистрали.","Если скорость движения при буксировке будет не менее 40 км/ч, съезжать с автомагистрали необязательно."],"c":0,"e":"<p>Согласно Правилам дорожного движения, на автомагистралях запрещается буксировка механического транспортного средства (при его эвакуации необходимо покинуть автомагистраль на ближайшем съезде с неё).<br> Требование направлено на обеспечение безопасности дорожного движения на автомагистрали.</p> <p>Вне населённых пунктов разрешается движение транспортным средствам, буксирующим механические транспортные средства, со скоростью не более 50 км/ч.</p>","image":"assets/adrive-questions/q101700802.jpg"},{"id":101700901,"themeId":5,"group":1017009,"chapter":17,"chapters":[17],"q":"Каким транспортным средствам из перечисленных ниже запрещается двигаться по автомагистрали?","a":["Мотоциклам без бокового прицепа.","Грузовым автомобилям при перевозке пассажиров в кузове-фургоне.","Грузовым автомобилям с технически допустимой общей массой более 3.5 тонны при буксировке прицепа.","Механическим транспортным средствам, управляемым водителями с водительским стажем менее двух лет.","Мопедам, имеющим максимальную конструктивную скорость движения 50 км/ч, определённую технической характеристикой мопеда."],"c":4,"e":"<p>Согласно Правилам дорожного движения, на автомагистралях запрещается движение на мопедах. Такие транспортные средства могут представлять препятствие для дорожного движения быстро передвигающимся механическим ТС.</p>","image":null},{"id":101700902,"themeId":5,"group":1017009,"chapter":17,"chapters":[17],"q":"Каким транспортным средствам из перечисленных ниже запрещается двигаться по автомагистрали?","a":["Мотоциклам с боковым прицепом.","Колёсным тракторам, осуществляющим буксировку прицепа.","Эвакуаторам при осуществлении эвакуации неисправных транспортных средств путём полной погрузки.","Механическим транспортным средствам, предназначенным для перевозки тяжеловесных и (или) крупногабаритных грузов.","Всем перечисленным транспортным средствам."],"c":1,"e":"<p>Согласно Правилам дорожного движения, на автомагистралях запрещается движение колёсных тракторов. Такие транспортные средства могут представлять препятствие для дорожного движения быстро передвигающимся механическим ТС.</p>","image":null},{"id":101700903,"themeId":5,"group":1017009,"chapter":17,"chapters":[17],"q":"Разрешено ли обучение управлению механическим транспортным средством на дороге, обозначенной дорожным знаком «Дорога для автомобилей»?","a":["Разрешено при неинтенсивном движении транспортных средств по дороге.","Разрешено при совершенствовании навыков вождения перед окончанием обучения.","Разрешено при переподготовке с одной категории транспортных средств на другую.","Запрещено в любом случае."],"c":3,"e":"<p>Согласно Правилам дорожного движения, на автомагистралях запрещается обучение управлению механическим транспортным средством. Такие транспортные средства могут представлять препятствие для дорожного движения быстро передвигающимся механическим ТС.<br> Требования Правил дорожного движения, установленные для движения по автомагистрали, распространяются также на дороги, обозначенные дорожным знаком 5.3 «Дорога для автомобилей» .</p>","image":null},{"id":101701131,"themeId":5,"group":1017011,"chapter":17,"chapters":[17],"q":"С какой максимальной скоростью разрешается буксировка прицепа легковым автомобилем на показанном участке дороги?","a":["50 км/ч.","60 км/ч.","70 км/ч.","80 км/ч.","100 км/ч."],"c":4,"e":"<p>Легковым автомобилям при их движении с прицепом на автомагистралях и дорогах для автомобилей разрешается движение со скоростью не более 100 км/ч.</p>","image":"assets/adrive-questions/q101701131.jpg"},{"id":101701231,"themeId":5,"group":1017012,"chapter":17,"chapters":[17],"q":"Какие действия запрещены водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны при движении по дороге, обозначенной дорожным знаком «Дорога для автомобилей»?","a":["Перевозка пассажиров в кабине.","Движение со скоростью 120 км/ч.","Опережение легковых автомобилей.","Остановка на обочине для высадки пассажиров."],"c":3,"e":"<p>Согласно Правилам дорожного движения, на автомагистралях запрещается остановка транспортных средств вне площадок для стоянки, обозначенных дорожными знаками 5.15 «Место стоянки» , 6.11 «Место отдыха» .<br> Требования Правил дорожного движения, установленные для движения по автомагистрали, распространяются также на дороги, обозначенные дорожным знаком 5.3 «Дорога для автомобилей» .</p>","image":null},{"id":101701232,"themeId":5,"group":1017012,"chapter":17,"chapters":[17],"q":"Какие действия запрещены водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны при движении по дороге, обозначенной дорожным знаком «Дорога для автомобилей», при отсутствии дорожных знаков, повышающих максимальную разрешённую скорость движения?","a":["Перевозка пассажиров в кузове-фургоне.","Опережение легковых автомобилей, движущихся со скоростью 120 км/ч.","Остановка на площадке для стоянки, обозначенной дорожным знаком «Место отдыха».","Движение по попутным полосам левее второй полосы движения, если две первые полосы движения равномерно заняты движущимися транспортными средствами."],"c":1,"e":"<p>Вне населённых пунктов грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны разрешается движение на автомагистралях со скоростью не более 120 км/ч.<br> Требования Правил дорожного движения, установленные для движения по автомагистрали, распространяются также на дороги, обозначенные дорожным знаком 5.3 «Дорога для автомобилей».<br> Поэтому, двигаясь по дороге для автомобилей со скоростью более 120 км/ч, водитель грузового автомобиля нарушит Правила дорожного движения.</p>","image":null},{"id":101800101,"themeId":5,"group":1018001,"chapter":18,"chapters":[18],"q":"При каких условиях разрешается движение грузовых автомобилей с технически допустимой общей массой не более 3.5 тонны по прилегающей территории?","a":["Если при этом не осуществляется транзитное движение.","Если водителями приняты все меры по обеспечению безопасности пешеходов.","Если водителями приняты все меры по обеспечению безопасности велосипедистов.","При выполнении всех перечисленных условий."],"c":3,"e":"<p>Движение транспортных средств в жилой и пешеходной зонах, на прилегающей территории допускается с учётом требований Правил дорожного движения при условии принятия водителями всех мер по обеспечению безопасности пешеходов, велосипедистов, иных участников дорожного движения.<br> Запрет транзитного движения в жилой и пешеходной зонах, а также на прилегающей территории направлен на создание безопасных и комфортных условий передвижения пешеходов в зонах проживания и отдыха.<br> Водители ТС не должны подвергать пешеходов опасности или ограничивать свободу их перемещения.</p>","image":null},{"id":101800102,"themeId":5,"group":1018001,"chapter":18,"chapters":[18],"q":"В каком из перечисленных ответов наиболее полно указаны условия для проезда грузового автомобиля с технически допустимой общей массой не более 3.5 тонны на территорию, обозначенную дорожным знаком «Жилая зона»?","a":["Только если водитель проживает в обозначенной дорожным знаком зоне.","Только при обслуживании торговых и других организаций в обозначенной дорожным знаком зоне.","Только если при этом не будет осуществляться транзитное движение."],"c":2,"e":"<p>Согласно Правилам дорожного движения, в жилой и пешеходной зонах, на прилегающей территории водителям механических транспортных средств запрещается транзитное движение.<br> Запрет транзитного движения в жилой и пешеходной зонах, а также на прилегающей территории направлен на создание безопасных и комфортных условий передвижения пешеходов в зонах проживания и отдыха.</p>","image":"assets/adrive-questions/q101800102.jpg"},{"id":101800201,"themeId":5,"group":1018002,"chapter":18,"chapters":[18],"q":"Разрешается ли водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны проехать прямо через показанный перекрёсток?","a":["Разрешается, если водитель работает в обозначенной зоне, при отсутствии иных возможностей подъезда.","Разрешается, если водитель проживает в обозначенной зоне, при отсутствии иных возможностей подъезда.","Разрешается в обоих перечисленных случаях."],"c":1,"e":"<p>Согласно Правилам дорожного движения, в пешеходной зоне допускается движение транспортных средств, принадлежащих гражданам, проживающим в этой зоне, при отсутствии иных возможностей их подъезда.</p>","image":"assets/adrive-questions/q101800201.jpg"},{"id":101800202,"themeId":5,"group":1018002,"chapter":18,"chapters":[18],"q":"Разрешается ли водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны проехать прямо через показанный перекрёсток?","a":["Разрешается только при обслуживании граждан, проживающих в обозначенной зоне, при отсутствии иных возможностей подъезда.","Разрешается только при обслуживании торговых и других организаций, расположенных в обозначенной зоне, при отсутствии иных возможностей подъезда.","Разрешается в обоих перечисленных случаях."],"c":2,"e":"<p>Согласно Правилам дорожного движения, в пешеходной зоне допускается движение транспортных средств, обслуживающих торговые и другие организации, расположенные в пешеходной зоне (граждан, проживающих в данной зоне), транспортных средств, принадлежащих гражданам, проживающим в этой зоне, при отсутствии иных возможностей их подъезда.</p>","image":"assets/adrive-questions/q101800202.jpg"},{"id":101800301,"themeId":5,"group":1018003,"chapter":18,"chapters":[18],"q":"Разрешается ли водителю грузового автомобиля коммунальной службы с технически допустимой общей массой не более 3.5 тонны проехать прямо через показанный перекрёсток при отсутствии иных возможностей подъезда к месту проведения работ?","a":["Разрешается.","Разрешается только при включении маячка оранжевого цвета.","Запрещается."],"c":0,"e":"<p>Согласно Правилам дорожного движения, в пешеходной зоне допускается движение транспортных средств дорожно-эксплуатационной и коммунальной служб.</p>","image":"assets/adrive-questions/q101800301.jpg"},{"id":101800302,"themeId":5,"group":1018003,"chapter":18,"chapters":[18],"q":"Разрешается ли водителю автомобиля скорой помощи проехать прямо через показанный перекрёсток при наличии иных возможностей подъезда к месту нахождения больного?","a":["Разрешается.","Разрешается только при включении маячка синего цвета.","Запрещается."],"c":1,"e":"<p>В данной ситуации имеются другие пути подъезда к месту нахождения больного, поэтому для проезда через пешеходную зону необходимо на транспортном средстве оперативного назначения включить маячки синего цвета.</p>","image":"assets/adrive-questions/q101800302.jpg"},{"id":101800401,"themeId":5,"group":1018004,"chapter":18,"chapters":[18],"q":"Кто из пешеходов при движении по прилегающей территории нарушает Правила дорожного движения?","a":["Пешеход, переходящий проезжую часть не по кратчайшей траектории.","Пешеход, движущийся по краю проезжей части дороги при наличии тротуара.","Оба пешехода нарушают Правила дорожного движения в показанной ситуации.","Оба пешехода не нарушают Правила дорожного движения в показанной ситуации."],"c":3,"e":"<p>Согласно Правилам дорожного движения, в жилой и пешеходной зонах, на прилегающей территории движение пешеходов разрешается по тротуару, обочине и по проезжей части дороги.<br> Пешеходы имеют преимущество перед транспортными средствами, но не должны необоснованно препятствовать их движению. Пешеходы не должны своими действиями создавать препятствие для движения ТС (например, стоять на проезжей части без необходимости, препятствуя своими действиями проезду ТС).</p>","image":"assets/adrive-questions/q101800401.jpg"},{"id":101800402,"themeId":5,"group":1018004,"chapter":18,"chapters":[18],"q":"Кто из пешеходов при движении по прилегающей территории нарушает Правила дорожного движения?","a":["Пешеход, движущийся по краю проезжей части дороги при наличии тротуара.","Пешеход, движущийся по центру проезжей части дороги при наличии тротуара, необоснованно создающий препятствие для движения автомобиля.","Оба пешехода нарушают Правила дорожного движения в показанной ситуации.","Оба пешехода не нарушают Правила дорожного движения в показанной ситуации."],"c":1,"e":"<p>Согласно Правилам дорожного движения, в жилой и пешеходной зонах, на прилегающей территории движение пешеходов разрешается по тротуару, обочине и по проезжей части дороги.<br> Пешеходы имеют преимущество перед транспортными средствами, но не должны необоснованно препятствовать их движению. Пешеходы не должны своими действиями создавать препятствие для движения ТС (например, стоять на проезжей части без необходимости, препятствуя своими действиями проезду ТС).</p>","image":"assets/adrive-questions/q101800402.jpg"},{"id":101800501,"themeId":5,"group":1018005,"chapter":18,"chapters":[18],"q":"Какому из показанных на рисунке пешеходов водитель обязан предоставить преимущество?","a":["Только пешеходу «А».","Только пешеходу «Б».","Обоим пешеходам."],"c":2,"e":"<p>В показанной ситуации водитель въезжает в жилую зону.<br> В жилой зоне пешеходы имеют преимущество перед транспортными средствами.</p>","image":"assets/adrive-questions/q101800501.jpg"},{"id":101800502,"themeId":5,"group":1018005,"chapter":18,"chapters":[18],"q":"Какому из показанных на рисунке пешеходов водитель обязан предоставить преимущество?","a":["Только пешеходу «А».","Только пешеходу «Б».","Обоим пешеходам."],"c":2,"e":"<p>В показанной ситуации водитель въезжает в жилую зону.<br> В жилой зоне пешеходы имеют преимущество перед транспортными средствами.</p>","image":"assets/adrive-questions/q101800502.jpg"},{"id":101800601,"themeId":5,"group":1018006,"chapter":18,"chapters":[18],"q":"При выезде с автозаправочной станции кому в показанной ситуации Вы обязаны уступить дорогу (предоставить преимущество)?","a":["Только пешеходу.","Только велосипедисту, движущемуся по тротуару.","Обоим участникам дорожного движения."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при выезде из жилой и пешеходной зон, прилегающей территории водители должны уступить дорогу транспортным средствам, движущимся <strong>по проезжей части дороги </strong>(а велосипедист движется по линии тротуаров), а также <strong>предоставить преимущество пешеходам</strong>, путь движения которых они пересекают.</p> <p>В свою очередь, велосипедист, пересекающий проезжую часть по линии тротуара, обязан уступить дорогу ТС.</p>","image":"assets/adrive-questions/q101800601.jpg"},{"id":101800602,"themeId":5,"group":1018006,"chapter":18,"chapters":[18],"q":"Кому в показанной ситуации водитель легкового автомобиля обязан уступить дорогу (предоставить преимущество)?","a":["Только пешеходу.","Только водителю мопеда.","Обоим участникам дорожного движения."],"c":2,"e":"<p>Согласно Правилам дорожного движения, при выезде из жилой и пешеходной зон, прилегающей территории водители должны уступить дорогу транспортным средствам, движущимся по пересекаемой проезжей части дороги, а также предоставить преимущество пешеходам, путь движения которых они пересекают.</p>","image":"assets/adrive-questions/q101800602.jpg"},{"id":101800641,"themeId":5,"group":1018006,"chapter":18,"chapters":[18],"q":"Должны ли Вы в показанной ситуации предоставить преимущество водителю средства персональной мобильности?","a":["Да, должны.","Нет, не должны."],"c":1,"e":"<p>При выезде из жилой и пешеходной зон, с прилегающей территории водители должны уступить дорогу транспортным средствам, движущимся по проезжей части дороги. Водитель средства персональной мобильности в показанной ситуации движется по тротуару.</p> <p>Водитель средства персональной мобильности при движении по линии тротуаров обязан уступить дорогу транспортным средствам, движущимся по дороге.</p> <p>Поэтому в показанной ситуации <strong>Вы пользуетесь преимуществом</strong>.</p>","image":"assets/adrive-questions/q101800641.jpg"},{"id":101800701,"themeId":5,"group":1018007,"chapter":18,"chapters":[18],"q":"При выезде с прилегающей территории водитель легкового автомобиля обязан уступить дорогу:","a":["Только велосипедисту.","Только водителю мопеда.","Обоим участникам дорожного движения."],"c":1,"e":"<p>Согласно Правилам дорожного движения, при выезде из жилой и пешеходной зон, прилегающей территории водители должны уступить дорогу транспортным средствам, движущимся по проезжей части дороги. Велосипедист движется по тротуару и будет пересекать проезжую часть дороги по линии тротуара, уступая дорогу легковому автомобилю.</p>","image":"assets/adrive-questions/q101800701.jpg"},{"id":101800702,"themeId":5,"group":1018007,"chapter":18,"chapters":[18],"q":"В какой последовательности транспортные средства должны проехать перекрёсток (мопед поворачивает налево)?","a":["Велосипед, мопед, автомобиль.","Велосипед, автомобиль, мопед.","Автомобиль, мопед, велосипед.","Мопед, велосипед, автомобиль.","Автомобиль, велосипед, мопед."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при выезде из жилой и пешеходной зон, прилегающей территории водители должны уступить дорогу транспортным средствам, движущимся по дороге.<br> Велосипедист при движении по проезжей части дороги должен руководствоваться правилом проезда нерегулируемых перекрёстков.</p> <p>Водитель мопеда обязан уступить дорогу велосипедисту, поворачивая налево на перекрёстке.</p>","image":"assets/adrive-questions/q101800702.jpg"},{"id":101800801,"themeId":5,"group":1018008,"chapter":18,"chapters":[18],"q":"Кому из пешеходов в показанной ситуации обязан предоставить преимущество водитель легкового автомобиля?","a":["Только пешеходу «А».","Только пешеходу «Б».","Обоим пешеходам."],"c":0,"e":"<p>В показанной ситуации пешеход «А» пересекает проезжую часть в месте выезда автомобиля из жилой зоны.</p> <p>Согласно Правилам дорожного движения, при выезде из жилой зоны водители должны предоставить преимущество пешеходам, путь движения которых они пересекают.</p> <p>Пешеход «Б» пересекает проезжую часть по линии тротуара в месте, где водитель не обязан предоставлять ему преимущество. Если пешеход «Б» всё же выйдет на проезжую часть дороги, водитель должен будет действовать как при появлении препятствия для движения.</p>","image":"assets/adrive-questions/q101800801.jpg"},{"id":101800901,"themeId":5,"group":1018009,"chapter":18,"chapters":[18],"q":"Разрешается ли водителю легкового автомобиля проехать в направлении стрелки, как показано на рисунке?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, в жилой и пешеходной зонах, на прилегающей территории водителям механических транспортных средств запрещается транзитное движение.</p>","image":"assets/adrive-questions/q101800901.jpg"},{"id":101800902,"themeId":5,"group":1018009,"chapter":18,"chapters":[18],"q":"Разрешается ли водителю легкового автомобиля проехать в направлении стрелки, как показано на рисунке, если ширина проезжей части дороги недостаточна для выполнения разворота в данном месте?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, в жилой и пешеходной зонах, на прилегающей территории водителям механических транспортных средств запрещается транзитное движение.</p>","image":"assets/adrive-questions/q101800902.jpg"},{"id":101801001,"themeId":5,"group":1018010,"chapter":18,"chapters":[18],"q":"С какой максимальной скоростью разрешено осуществлять буксировку механического транспортного средства по дороге, обозначенной дорожным знаком «Пешеходная зона»?","a":["20 км/ч.","40 км/ч.","50 км/ч.","60 км/ч."],"c":0,"e":"<p>Согласно Правилам дорожного движения, в жилой и пешеходной зонах, на прилегающей территории водителям механических транспортных средств запрещается движение со скоростью более 20 км/ч.<br> Требование направлено на обеспечение безопасности пешеходов в жилой зоне.<br> Для принудительного выполнения водителями транспортных средств данного предписания в жилой зоне проезжая часть может иметь прямолинейные участки ограниченной длины, искусственные неровности, иные планировочные решения, не позволяющие развить большую скорость.</p>","image":"assets/adrive-questions/q101801001.jpg"},{"id":101801002,"themeId":5,"group":1018010,"chapter":18,"chapters":[18],"q":"Разрешено ли осуществлять обучение управлению механическим транспортным средством на прилегающей территории в индивидуальном порядке?","a":["Разрешено при отсутствии на прилегающей территории пешеходов.","Разрешено при отсутствии на прилегающей территории транспортных средств.","Разрешено при выполнении перечисленных выше условий.","Запрещено."],"c":3,"e":"<p>Согласно Правилам дорожного движения, в жилой и пешеходной зонах, на прилегающей территории водителям механических транспортных средств запрещается обучение управлению механическим транспортным средством.<br> Учебная езда в жилой и пешеходной зонах, а также на прилегающей территории запрещена с целью обеспечения безопасности пешеходов, особенно детей, лиц преклонного возраста и лиц с ограниченными физическими возможностями, которые имеют преимущественное право передвигаться по тротуарам и проезжей части.<br> Обучаемый управлению механическим транспортным средством не обладает ещё достаточными навыками управления им для предотвращения опасных ситуаций и обеспечения надлежащего уровня безопасности дорожного движения.</p>","image":"assets/adrive-questions/q101801002.jpg"},{"id":101801003,"themeId":5,"group":1018010,"chapter":18,"chapters":[18],"q":"Разрешено ли в жилой зоне водителю мопеда двигаться со скоростью 30 км/ч?","a":["Разрешено.","Разрешено только лицам моложе 16 лет.","Разрешено только лицам от 16 лет и старше.","Разрешено только лицам моложе 16 лет в сопровождении взрослых.","Запрещено."],"c":4,"e":"<p>Согласно Правилам дорожного движения, в жилой и пешеходной зонах, на прилегающей территории водителям механических транспортных средств запрещается движение со скоростью более 20 км/ч.<br> Требование направлено на обеспечение безопасности пешеходов в жилой зоне.<br> Для принудительного выполнения водителями транспортных средств данного предписания в жилой зоне проезжая часть может иметь прямолинейные участки ограниченной длины, искусственные неровности, иные планировочные решения, не позволяющие развить большую скорость.</p>","image":null},{"id":101801341,"themeId":5,"group":1018013,"chapter":18,"chapters":[18],"q":"На показанном перекрёстке в жилой зоне Вы, управляя легковым автомобилем:","a":["Имеете преимущество перед велосипедистом, приближающимся слева.","Обязаны уступить дорогу велосипедисту, приближающемуся слева."],"c":1,"e":"<p>В жилой и пешеходной зонах, на прилегающей территории велосипедисты имеют преимущество перед транспортными средствами, но не должны необоснованно препятствовать их движению.</p>","image":"assets/adrive-questions/q101801341.jpg"},{"id":101801342,"themeId":5,"group":1018013,"chapter":18,"chapters":[18],"q":"На показанном перекрёстке в жилой зоне Вы, управляя легковым автомобилем:","a":["Имеете преимущество перед водителем средства персональной мобильности.","Обязаны предоставить преимущество водителю средства персональной мобильности."],"c":1,"e":"<p>В жилой и пешеходной зонах, на прилегающей территории водители <strong>средств персональной мобильности имеют преимущество перед транспортными средствами</strong>, но не должны необоснованно препятствовать их движению.</p>","image":"assets/adrive-questions/q101801342.jpg"},{"id":101801442,"themeId":5,"group":1018014,"chapter":18,"chapters":[18],"q":"Нарушает ли водитель средства персональной мобильности Правила дорожного движения, передвигаясь по проезжей части дороги в показанной ситуации?","a":["Да, нарушает.","Нет, не нарушает.","Нет, не нарушает, если только осуществляет движение не далее 1 метра от правого края проезжей части дороги."],"c":1,"e":"<p>В жилой зоне, на прилегающей территории движение водителей средств персональной мобильности разрешается по тротуару, обочине <strong>и по проезжей части дороги</strong>.</p>","image":"assets/adrive-questions/q101801442.jpg"},{"id":101801443,"themeId":5,"group":1018014,"chapter":18,"chapters":[18],"q":"Нарушает ли велосипедист Правила дорожного движения в показанной ситуации?","a":["Да, нарушает.","Нет, не нарушает.","Не нарушает только в случае, если осуществляет движение не далее 1 метра от правого края проезжей части дороги."],"c":1,"e":"<p>В жилой и пешеходной зонах, на прилегающей территории движение велосипедистов разрешается по тротуару, обочине и по проезжей части дороги на выбор.</p>","image":"assets/adrive-questions/q101801443.jpg"},{"id":101801542,"themeId":5,"group":1018015,"chapter":18,"chapters":[18],"q":"Разрешено ли в возрасте старше 14 лет передвигаться на средстве персональной мобильности по проезжей части дороги?","a":["Да, только в жилой и пешеходной зонах.","Да, только в жилой зоне и на прилегающей территории.","Нет, не разрешено."],"c":1,"e":"<p>В жилой зоне, на прилегающей территории движение на средствах персональной мобильности <strong>разрешается по тротуару, обочине и по проезжей части дороги</strong>.</p> <p>При этом водителю, не достигнувшему четырнадцати лет, запрещается управлять средством персональной мобильности на дороге <strong>без сопровождения совершеннолетнего лица</strong> (за исключением жилых зон).</p>","image":null},{"id":101801571,"themeId":5,"group":1018015,"chapter":18,"chapters":[18],"q":"Разрешено ли движение велосипедистов в пешеходной зоне?","a":["Разрешено.","Разрешено только в возрасте от 14 лет и старше.","Запрещено."],"c":0,"e":"<p>В пешеходной зоне движение велосипедистов разрешается по тротуару, обочине и проезжей части дороги. Велосипедисты имеют преимущество перед иными транспортными средствами, но не должны необоснованно препятствовать их движению.</p>","image":"assets/adrive-questions/q101801571.jpg"},{"id":101801653,"themeId":5,"group":1018016,"chapter":18,"chapters":[18],"q":"Разрешена ли стоянка грузовому автомобилю с технически допустимой общей массой не более 3.5 тонны в жилой зоне вне специально отведённых мест, обозначенных дорожным знаком «Место стоянки»?","a":["Разрешена, только если она связана с выполнением работ.","Разрешена во всех случаях.","Запрещена."],"c":0,"e":"<p>Если стоянка грузового автомобиля в жилой зоне <strong>связана с выполнением работ, то она разрешена</strong> вне мест, обозначенных дорожным знаком «5.15 Место стоянки».</p>","image":"assets/adrive-questions/q101801653.jpg"},{"id":102000101,"themeId":5,"group":1020001,"chapter":20,"chapters":[20],"q":"Разрешается ли движение на велосипеде по обочине при отсутствии велосипедной дорожки?","a":["Да, разрешается только по левой обочине.","Да, разрешается только по правой обочине.","Да, разрешается по правой или левой обочине.","Запрещается."],"c":2,"e":"<p>Согласно Правилам дорожного движения, движение на велосипеде должно осуществляться по велосипедной дорожке, а при её отсутствии — по обочине, тротуару или пешеходной дорожке, не создавая препятствия для безопасного движения пешеходов.</p> <p>В Правилах дорожного движения не оговорено, по какой обочине (правой или левой) должен двигаться велосипедист. Велосипедист может двигаться по любой обочине, если маршрут его движения не предполагает выезд на проезжую часть дороги.</p>","image":null},{"id":102000102,"themeId":5,"group":1020001,"chapter":20,"chapters":[20],"q":"В каком случае разрешается движение по обочине на велосипеде?","a":["При отсутствии велосипедной дорожки.","Только при отсутствии велосипедной дорожки и пешеходной дорожки.","Только при отсутствии тротуара, велосипедной дорожки и пешеходной дорожки."],"c":0,"e":"<p>Согласно Правилам дорожного движения, движение на велосипеде должно осуществляться по велосипедной дорожке, а при её отсутствии — по обочине, тротуару или пешеходной дорожке, не создавая препятствия для безопасного движения пешеходов.</p> <p>В Правилах дорожного движения не оговорено, по какой обочине (правой или левой) должен двигаться велосипедист. Велосипедист может двигаться по любой обочине, если маршрут его движения не предполагает выезд на проезжую часть дороги.</p>","image":null},{"id":102000202,"themeId":5,"group":1020002,"chapter":20,"chapters":[20],"q":"Выберите вариант ответа, где наиболее полно и правильно указано, в каких случаях велосипедисту разрешено двигаться по проезжей части дороги далее 1 метра от её правого края?","a":["Для объезда препятствия и в разрешённых случаях для поворота налево или разворота.","Для опережения, объезда препятствия и в разрешённых случаях для поворота налево или разворота.","Для опережения, остановки на левой стороне дороги, объезда препятствия и в разрешённых случаях для поворота налево или разворота."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при движении на велосипеде выезд далее 1 метра от правого края проезжей части дороги допускается лишь для объезда препятствия и в разрешённых случаях для поворота налево или разворота.</p> <p>Выезд велосипедиста далее 1 м от правого края проезжей части дороги для объезда препятствия допустим, если нет иной возможности объехать его или спешиться и обойти препятствие справа.</p> <p>Поворот налево или разворот разрешён только в случаях движения по дорогам, которые имеют не более одной полосы для движения в данном направлении, и которые не имеют трамвайного пути посередине дороги.</p>","image":null},{"id":102000231,"themeId":5,"group":1020002,"chapter":20,"chapters":[20],"q":"Как должно осуществляться движение на велосипедах по краю проезжей части дороги при отсутствии пешеходной и велосипедной дорожек, тротуара, обочины или при невозможности движения по ним (за исключением учебно-тренировочного процесса в случае сопровождения автомобилем прикрытия)?","a":["В один ряд не далее 1 метра от её правого края.","В один или два ряда не далее 1 метра от её правого края.","В один ряд не далее 1 метра от её левого края навстречу движению."],"c":0,"e":"<p>Согласно Правилам дорожного движения, движение на велосипеде должно осуществляться по велосипедной дорожке, а при её отсутствии — по обочине, тротуару или пешеходной дорожке, не создавая препятствия для безопасного движения пешеходов. При отсутствии указанных элементов дороги или невозможности движения по ним допускается движение велосипедистов по проезжей части дороги в один ряд не далее 1 метра от её правого края.</p> <p>Движение велосипедистов по проезжей части необходимо рассматривать как исключительный случай, который возникает при отсутствии велосипедной или пешеходной дорожки, тротуара или обочины или невозможности движения по ним, а также вне зоны с ограничением максимальной скорости движения. Только при перечисленных выше условиях допускается движение велосипедистов по проезжей части в один ряд не далее 1 метра от её правого края в попутном направлении.</p>","image":null},{"id":102000301,"themeId":5,"group":1020003,"chapter":20,"chapters":[20],"q":"Кто из велосипедистов в показанной ситуации нарушает Правила дорожного движения?","a":["Только велосипедист «А».","Только велосипедист «Б».","Оба велосипедиста нарушают Правила дорожного движения."],"c":2,"e":"<p>В показанной ситуации имеется обочина.</p> <p>Согласно Правилам дорожного движения, движение на велосипеде должно осуществляться по велосипедной дорожке, а при её отсутствии — по обочине, тротуару или пешеходной дорожке, не создавая препятствия для безопасного движения пешеходов.<br> В Правилах дорожного движения не оговорено, по какой обочине (правой или левой) должен двигаться велосипедист. Велосипедист может двигаться по любой обочине, если маршрут его движения не предполагает выезд на проезжую часть дороги.</p>","image":"assets/adrive-questions/q102000301.jpg"},{"id":102000401,"themeId":5,"group":1020004,"chapter":20,"chapters":[20],"q":"Кто из перечисленных участников дорожного движения не нарушает Правила дорожного движения?","a":["Велосипедист, движущийся по обочине в условиях снегопада.","Водитель мопеда, движущийся по краю проезжей части дороги в условиях гололедицы.","Водитель мотоцикла без бокового прицепа, движущийся по проезжей части дороги в условиях снегопада.","Все перечисленные участники дорожного движения нарушают Правила дорожного движения."],"c":2,"e":"<p>Велосипедисту, водителям средства персональной мобильности и мопеда запрещается двигаться по проезжей части дороги, обочине в условиях снегопада и (или) гололедицы.</p> <p>Специальные требования к водителям велосипеда, средства персональной мобильности и мопеда направлены как на обеспечение их собственной безопасности, так и безопасности других участников дорожного движения.<br> Перечисленные транспортные средства очень неустойчивы, а при движении в условиях снегопада и (или) гололедицы на дороге вероятность падения на скользком дорожном покрытии резко возрастает.<br> Мотоцикл без бокового прицепа более устойчив на скользкой дороге при правильном выборе зимних шин, поэтому в отношении их нет запрета на движение в условиях снегопада или гололедицы.</p>","image":null},{"id":102000402,"themeId":5,"group":1020004,"chapter":20,"chapters":[20],"q":"На каких транспортных средствах из перечисленных ниже запрещается движение в условиях снегопада и (или) гололедицы по проезжей части дороги?","a":["Только на велосипедах.","На велосипедах и мопедах.","На велосипедах, мопедах и гужевых транспортных средствах.","На велосипедах, мопедах и мотоциклах без бокового прицепа."],"c":1,"e":"<p>Велосипедисту, водителям средства персональной мобильности и мопеда запрещается двигаться по проезжей части дороги, обочине в условиях снегопада и (или) гололедицы.<br> Специальные требования к водителям велосипеда, средства персональной мобильности и мопеда направлены как на обеспечение их собственной безопасности, так и безопасности других участников дорожного движения. Велосипед, средство персональной мобильности и мопед очень неустойчивы, а при движении в условиях снегопада и (или) гололедицы на дороге вероятность падения на скользком дорожном покрытии резко возрастает.</p>","image":null},{"id":102000501,"themeId":5,"group":1020005,"chapter":20,"chapters":[20],"q":"Разрешается ли перевозка пассажиров на мопеде?","a":["Запрещается.","Разрешается, если перевозка пассажиров предусмотрена конструкцией мопеда.","Разрешается перевозка только детей в возрасте до семи лет на дополнительном специально оборудованном сиденье."],"c":1,"e":"<p>Согласно Правилам дорожного движения, водителю мопеда запрещается перевозить пассажиров, за исключением случаев, когда перевозка пассажиров предусмотрена конструкцией мопеда. При перевозке пассажиров на мопеде при отсутствии специально оборудованных мест для перевозки пассажиров вследствие дополнительной нагрузки значительно нарушается его устойчивость во время движения и затрудняется управление им.</p>","image":null},{"id":102000532,"themeId":5,"group":1020005,"chapter":20,"chapters":[20],"q":"Разрешается ли перевозка пассажиров на велосипеде?","a":["Запрещается.","Разрешается, если перевозка пассажиров предусмотрена конструкцией велосипеда.","Разрешается перевозка только детей в возрасте до семи лет в велосипедном шлеме на дополнительном специально оборудованном сиденье, фиксирующем (предохраняющем) ноги ребёнка."],"c":2,"e":"<p>Велосипедисту запрещается перевозить пассажиров, за исключением случаев перевозки на велосипеде детей в возрасте до семи лет в велосипедном шлеме на дополнительном специально оборудованном сиденье, фиксирующем (предохраняющем) ноги ребенка. Велосипед является транспортным средством индивидуального пользования, он не приспособлен для перевозки пассажиров. При перевозке пассажиров на велосипеде вследствие дополнительной нагрузки значительно нарушается его устойчивость во время движения и затрудняется управление им.</p>","image":null},{"id":102000641,"themeId":5,"group":1020006,"chapter":20,"chapters":[20],"q":"Разрешается ли водителю мопеда двигаться по обочине?","a":["Да, разрешается.","Да, только по асфальтированной обочине.","Нет, не разрешается."],"c":2,"e":"<p>Движение на мопеде должно осуществляться по проезжей части дороги не далее 1 метра от её правого края.</p> <p>Запрещается движение транспортных средств по обочинам.</p>","image":null},{"id":102000642,"themeId":5,"group":1020006,"chapter":20,"chapters":[20],"q":"Кто из водителей мопедов правильно осуществляет движение по дороге в показанной ситуации?","a":["Водитель мопеда, движущийся по обочине.","Водитель мопеда, движущийся по краю проезжей части дороги (не далее 1 метра от правого края).","Оба водителя осуществляют движение правильно.","Оба водителя осуществляют движение неправильно."],"c":1,"e":"<p>Движение на мопеде должно осуществляться по проезжей части дороги не далее 1 метра от её правого края.</p> <p>Движение по обочине запрещено.</p>","image":"assets/adrive-questions/q102000642.jpg"},{"id":102000741,"themeId":5,"group":1020007,"chapter":20,"chapters":[20],"q":"Нарушает ли велосипедист Правила дорожного движения в показанной ситуации?","a":["Да, нарушает.","Нет, не нарушает.","Не нарушает только в случае, если осуществляет движение не далее 1 метра от правого края проезжей части дороги."],"c":2,"e":"<p>Движение велосипедистов в зоне с ограничением максимальной скорости движения (вне зависимости от наличия велосипедной дорожки, обочины, тротуара) по проезжей части может осуществляться не далее 1 метра от её правого края в один ряд (а не по всей ширине проезжей части дороги).</p>","image":"assets/adrive-questions/q102000741.jpg"},{"id":102000771,"themeId":5,"group":1020007,"chapter":20,"chapters":[20],"q":"При каких условиях водителю средства персональной мобильности разрешается двигаться по проезжей части дороги (не далее 1 метра) вне жилых зон и зон с ограничением максимальной скорости движения?","a":["Если масса средства персональной мобильности превышает 35 кг.","Если отсутствуют велосипедная дорожка, пешеходная дорожка и обочина.","При выполнении обоих условий."],"c":2,"e":"<p>Движение на средстве персональной мобильности должно осуществляться по велосипедной дорожке, а при её отсутствии — по обочине, <strong>тротуару</strong> или пешеходной дорожке. При отсутствии указанных элементов дороги <strong>или невозможности движения по ним</strong> допускается движение водителей средств персональной мобильности по проезжей части дороги.</p> <p>В представленном в ответах перечне не учтено наличие тротуара. Так как водителю средства персональной мобильности <strong>запрещается двигаться по тротуару, если масса средства персональной мобильности превышает 35 кг</strong>, то даже при его наличии он должен двигаться по проезжей части дороги не далее 1 метра от края.</p>","image":"assets/adrive-questions/q102000771.jpg"},{"id":102000772,"themeId":5,"group":1020007,"chapter":20,"chapters":[20],"q":"Разрешено ли поставить на стоянку средство персональной мобильности так, как в показанной ситуации?","a":["Да, разрешено.","Нет, не разрешено."],"c":1,"e":"<p>Разрешено поставить средство персональной мобильности <strong>на стоянку на тротуаре</strong>, если это не создаст препятствия и опасности для дорожного движения. В показанной ситуации средство персональной мобильности <strong>создаёт препятствие движению пешеходов и велосипедистов</strong>.</p> <p>Запрещено оставлять средства персональной мобильности <strong>в местах, где это создает препятствия для движения</strong> иных участников дорожного движения.</p>","image":"assets/adrive-questions/q102000772.jpg"},{"id":102000773,"themeId":5,"group":1020007,"chapter":20,"chapters":[20],"q":"В каких случаях водитель средства персональной мобильности при движении по тротуару в населённом пункте нарушит Правила дорожного движения?","a":["Только если масса его транспортного средства превышает 35 кг.","Только если он будет двигаться со скоростью более 10 км/ч.","Нарушит в обоих перечисленных случаях."],"c":2,"e":"<p>Водителю средства персональной мобильности <strong>запрещается</strong> двигаться в населенном пункте <strong>со скоростью более 10 км/ч</strong>, за исключением движения по велосипедным дорожкам или проезжей части дороги, а также двигаться по тротуару, <strong>если масса средства персональной мобильности превышает 35 кг</strong>.</p>","image":"assets/adrive-questions/q102000773.jpg"},{"id":102000774,"themeId":5,"group":1020007,"chapter":20,"chapters":[20],"q":"До какой максимальной скорости разрешено ускориться водителю средства персональной мобильности в населённом пункте по велосипедной дорожке после пересечения проезжей части дороги по велосипедному переезду?","a":["До 10 км/ч.","До 25 км/ч.","Необходимо продолжать движение со скоростью идущего шагом пешехода."],"c":1,"e":"<p>Водителю средства персональной мобильности при движении по велосипедной дорожке в населённом пункте разрешается двигаться с максимальной скоростью, ограниченной технической характеристикой, т.е. <strong>до 25 км/ч</strong>. Ограничивать скорость до 10 км/ч на велосипедной дорожке необязательно.</p>","image":"assets/adrive-questions/q102000774.jpg"},{"id":102000775,"themeId":5,"group":1020007,"chapter":20,"chapters":[20],"q":"С какой максимальной скоростью разрешено двигаться водителю средства персональной мобильности в населённом пункте по тротуару?","a":["До 10 км/ч.","До 25 км/ч.","Необходимо двигаться со скоростью идущего шагом пешехода."],"c":0,"e":"<p>Водителю средства персональной мобильности при движении по тротуару в населённом пункте разрешается двигаться <strong>с максимальной скоростью до 10 км/ч</strong>.</p>","image":"assets/adrive-questions/q102000775.jpg"},{"id":102000776,"themeId":5,"group":1020007,"chapter":20,"chapters":[20],"q":"Если масса средства персональной мобильности превышает 35 кг, то движение на нём запрещено:","a":["Только по тротуару.","Только по пешеходной дорожке.","Только по велосипедной дорожке.","По всем перечисленным элементам дороги."],"c":0,"e":"<p>Водителю средства персональной мобильности <strong>запрещается двигаться по тротуару</strong>, если масса средства персональной мобильности превышает 35 кг.</p>","image":"assets/adrive-questions/q102000776.jpg"},{"id":102000841,"themeId":5,"group":1020008,"chapter":20,"chapters":[20],"q":"В зоне, обозначенной каким из показанных дорожных знаков, движение велосипедистов разрешается по всей ширине проезжей части дороги?","a":["Только в зоне, обозначенной знаком 1.","Только в зоне, обозначенной знаком 2.","Как в зоне, обозначенной знаком 1, так и в зоне, обозначенной знаком 2."],"c":1,"e":"<p>Движение велосипедистов по проезжей части может осуществляться в зоне с ограничением максимальной скорости движения не далее 1 метра от её правого края в один ряд (а не по всей ширине проезжей части дороги).</p> <p>В жилой и пешеходной зонах, на прилегающей территории движение велосипедистов разрешается по тротуару, обочине и по проезжей части дороги.</p>","image":"assets/adrive-questions/q102000841.jpg"},{"id":102000842,"themeId":5,"group":1020008,"chapter":20,"chapters":[20],"q":"Разрешается ли велосипедисту продолжить движение по проезжей части дороги в показанной ситуации?","a":["Да, разрешается не далее 1 метра от правого края проезжей части дороги.","Нет, не разрешается."],"c":0,"e":"<p>После выезда из жилой зоны движение велосипедиста в зоне с ограничением максимальной скорости движения по проезжей части может осуществляться не далее 1 метра от её правого края вне зависимости от наличия велосипедной дорожки, обочины, тротуара или пешеходной дорожки.</p>","image":"assets/adrive-questions/q102000842.jpg"},{"id":102000843,"themeId":5,"group":1020008,"chapter":20,"chapters":[20],"q":"Как следует поступить водителю средства персональной мобильности в показанной ситуации, если масса средства персональной мобильности превышает 35 кг?","a":["Продолжить движение по проезжей части дороги не далее 1 метра от её правого края.","Переместиться на тротуар."],"c":0,"e":"<p>Водителю средства персональной мобильности <strong>следует продолжать движение по проезжей части дороги</strong>, так как при массе средства персональной мобильности свыше 35 кг. движение по тротуару запрещено.</p>","image":"assets/adrive-questions/q102000843.jpg"},{"id":102000944,"themeId":5,"group":1020009,"chapter":20,"chapters":[20],"q":"Разрешено ли в возрасте до 14 лет передвигаться на средстве персональной мобильности по проезжей части дороги без сопровождения совершеннолетнего лица?","a":["Да, только в жилой зоне.","Да, в жилой зоне и на прилегающей территории.","Нет, не разрешено."],"c":0,"e":"<p>Запрещается передвигаться на средствах персональной мобильности на дороге в возрасте до четырнадцати лет (кроме жилых зон).</p>","image":null},{"id":102000971,"themeId":5,"group":1020009,"chapter":20,"chapters":[20],"q":"Если велосипедист не спешился и переезжает через проезжую часть по линии обочины:","a":["Он имеет преимущество перед транспортными средствами.","Он обязан уступить дорогу транспортным средствам."],"c":1,"e":"<p>Велосипедист имеет право пересекать проезжую часть дороги, не спешиваясь, по линии обочин, <strong>уступая дорогу иным транспортным средствам</strong>.</p> <p>При подъезде к пересечению с проезжей частью дороги в случае ее пересечения по линии обочин велосипедист обязан <strong>заблаговременно снизить скорость движения</strong> и, <strong>убедившись, что выезд на проезжую часть дороги безопасен</strong>, пересекать её <strong>со скоростью идущего шагом пешехода</strong>.</p>","image":"assets/adrive-questions/q102000971.jpg"},{"id":102000972,"themeId":5,"group":1020009,"chapter":20,"chapters":[20],"q":"Должен ли велосипедист спешиваться при проезде перекрёстка, двигаясь по линии обочин?","a":["Да, должен.","Нет, не должен."],"c":1,"e":"<p>Велосипедист <strong>имеет право пересекать проезжую часть дороги, не спешиваясь</strong>, по линии тротуаров или обочин, уступая дорогу иным транспортным средствам.</p> <p>При подъезде к пересечению с проезжей частью дороги в случае её пересечения по линии обочин велосипедист обязан заблаговременно снизить скорость движения и, убедившись, что выезд на проезжую часть дороги безопасен, <strong>пересекать её со скоростью идущего шагом пешехода</strong>.</p>","image":"assets/adrive-questions/q102000972.jpg"},{"id":102000973,"themeId":5,"group":1020009,"chapter":20,"chapters":[20],"q":"Разрешается ли велосипедисту в возрасте до 14 лет кататься по проезжей части дороги на территории садового товарищества?","a":["Да, разрешается.","Разрешается только в сопровождении совершеннолетнего лица.","Нет, не разрешается."],"c":0,"e":"<p>Водителю велосипеда запрещается, <strong>не достигнув четырнадцати лет</strong>, управлять велосипедом на дороге без сопровождения совершеннолетнего лица (<strong>кроме</strong> пешеходных и <strong>жилых зон</strong>, тротуаров, велосипедных и пешеходных дорожек).</p><p>Территория садоводческого товарищества считается жилой зоной.</p>","image":"assets/adrive-questions/q102000973.jpg"},{"id":102000974,"themeId":5,"group":1020009,"chapter":20,"chapters":[20],"q":"Разрешено ли в парке осуществлять движение на средстве персональной мобильности, если въезды в парк обозначены дорожными знаками «5.40 Пешеходная зона»?","a":["Разрешено только в возрасте до 14 лет.","Разрешено только в возрасте старше 14 лет.","Разрешено во всех случаях.","Запрещено."],"c":3,"e":"<p>Водителям средств персональной мобильности <strong>запрещено осуществлять движение в пешеходной зоне</strong>.</p>","image":"assets/adrive-questions/q102000974.jpg"},{"id":102001041,"themeId":5,"group":1020010,"chapter":20,"chapters":[20],"q":"Обязан ли водитель средства персональной мобильности, пересекая проезжую часть дороги по велосипедному переезду, в показанной ситуации двигаться со скоростью идущего шагом пешехода?","a":["Да, обязан.","Нет, не обязан."],"c":0,"e":"<p>Водитель средства персональной мобильности на велосипедном переезде обязан пересекать проезжую часть дороги со скоростью идущего шагом пешехода.</p>","image":"assets/adrive-questions/q102001041.jpg"},{"id":102001071,"themeId":5,"group":1020010,"chapter":20,"chapters":[20],"q":"Если водитель средства персональной мобильности спешился и переводит своё транспортное средство через проезжую часть по пешеходному переходу:","a":["Он имеет преимущество перед транспортными средствами.","Он обязан уступить дорогу транспортным средствам."],"c":0,"e":"<p>Перед пересечением проезжей части водитель средства персональной мобильности обязан спешиваться и переходить проезжую часть <strong>с соблюдением требований, предусмотренных для движения пешеходов</strong>.</p> <p>Пешеход на нерегулируемом пешеходном переходе <strong>пользуется преимуществом перед транспортными средствами</strong>.</p>","image":"assets/adrive-questions/q102001071.jpg"},{"id":102001072,"themeId":5,"group":1020010,"chapter":20,"chapters":[20],"q":"При пересечении проезжей части дороги на разрешающий сигнал пешеходного светофора по регулируемому пешеходному переходу водитель средства персональной мобильности:","a":["Должен спешиться.","Может не спешиваться."],"c":0,"e":"<p>Перед пересечением проезжей части по регулируемому пешеходному переходу на разрешающий сигнал водитель средства персональной мобильности <strong>обязан спешиваться и переходить проезжую часть</strong> с соблюдением требований, предусмотренных для движения пешеходов.</p>","image":"assets/adrive-questions/q102001072.jpg"},{"id":102001073,"themeId":5,"group":1020010,"chapter":20,"chapters":[20],"q":"Обязаны ли спешиваться велосипедист и водитель средства персональной мобильности, двигаясь на разрешающий сигнал на показанном велосипедном переезде?","a":["Да, обязаны.","Нет, не обязаны."],"c":1,"e":"<p>Перед пересечением проезжей части велосипедист и водитель средства персональной мобильности <strong>обязаны спешиваться</strong> и переходить проезжую часть с соблюдением требований, предусмотренных для движения пешеходов, <strong>за исключением случаев движения по велосипедному переезду при условии определения порядка проезда с использованием транспортных светофоров для регулирования движения велосипедистов</strong>.</p>","image":"assets/adrive-questions/q102001073.jpg"},{"id":102001074,"themeId":5,"group":1020010,"chapter":20,"chapters":[20],"q":"Обязан ли велосипедист при подъезде к пересечению с проезжей частью дороги в случае движения по краю проезжей части дороги пересекать её со скоростью идущего шагом пешехода?","a":["Да, обязан.","Нет, не обязан."],"c":1,"e":"<p>При подъезде к пересечению с проезжей частью дороги в случае её пересечения <strong>по велосипедному переезду, линии тротуаров или обочин</strong> велосипедист обязан заблаговременно снизить скорость движения и, убедившись, что выезд на проезжую часть дороги безопасен, <strong>пересекать её со скоростью идущего шагом пешехода</strong>.</p> <p>В приведённом перечне отсутствует случай движения по краю проезжей части дороги. Делаем вывод, что в таком случае <strong>снижать скорость движения до скорости пешехода нет необходимости</strong>.</p>","image":"assets/adrive-questions/q102001074.jpg"},{"id":102001075,"themeId":5,"group":1020010,"chapter":20,"chapters":[20],"q":"Мог ли водитель средства персональной мобильности в показанной ситуации не спешиваться перед пересечением проезжей части дороги?","a":["Да, мог, уступая дорогу транспортным средствам.","Нет, он обязан был спешиться и убедиться, что выход на проезжую часть дороги безопасен."],"c":1,"e":"<p>Водитель средства персональной мобильности перед пересечением проезжей части дороги обязан спешиваться и переходить проезжую часть дороги по пешеходному переходу, убедившись, что выход на проезжую часть дороги безопасен. Выход на проезжую часть дороги должен осуществляться с разумной осмотрительностью после оценки расстояния до приближающихся транспортных средств и их скорости.</p>","image":"assets/adrive-questions/q102001075.jpg"},{"id":102001076,"themeId":5,"group":1020010,"chapter":20,"chapters":[20],"q":"Нарушает ли велосипедист Правила дорожного движения, пересекая проезжую часть дороги по велосипедному переезду в показанной ситуации?","a":["Да, нарушает.","Не нарушает в любом случае.","Не нарушает, если пересекает проезжую часть дороги со скоростью идущего шагом пешехода."],"c":2,"e":"<p>Велосипедист <strong>может не спешиваться</strong> перед пересечением проезжей части дороги <strong>по велосипедному переезду</strong> при условии определения порядка проезда <strong>с использованием транспортных светофоров для регулирования движения велосипедистов</strong>. При подъезде к пересечению с проезжей частью дороги в случае ее пересечения по велосипедному переезду велосипедист обязан заблаговременно снизить скорость движения и, убедившись, что выезд на проезжую часть дороги безопасен, <strong>пересекать её со скоростью идущего шагом пешехода</strong>.</p>","image":"assets/adrive-questions/q102001076.jpg"},{"id":102001077,"themeId":5,"group":1020010,"chapter":20,"chapters":[20],"q":"С какой скоростью при включении разрешающего сигнала транспортного светофора, предназначенного для регулирования движения велосипедистов, водителю средства персональной мобильности разрешено пересечь проезжую часть дороги по велосипедному переезду?","a":["Со скоростью не более 10 км/ч.","Со скоростью не более 25 км/ч.","Со скоростью идущего шагом пешехода."],"c":2,"e":"<p>В случае пересечения проезжей части дороги по велосипедному переезду водитель средства персональной мобильности обязан, убедившись, что выезд на проезжую часть дороги безопасен, пересекать её <strong>со скоростью идущего шагом пешехода</strong>.</p>","image":"assets/adrive-questions/q102001077.jpg"},{"id":102001081,"themeId":5,"group":1020010,"chapter":20,"chapters":[20],"q":"В показанной ситуации водитель средства персональной мобильности спешился перед пешеходным переходом. Он:","a":["Обязан переходить проезжую часть дороги по пешеходному переходу, уступая дорогу иным транспортным средствам.","Обязан переходить проезжую часть дороги по пешеходному переходу, убедившись, что выход на проезжую часть дороги безопасен.","Обязан переходить проезжую часть дороги рядом с пешеходным переходом, убедившись, что выход на проезжую часть дороги безопасен."],"c":1,"e":"<p>Водитель средства персональной мобильности обязан переходить проезжую часть дороги по пешеходному переходу, <strong>убедившись, что выход на проезжую часть дороги безопасен</strong>. Выход на проезжую часть дороги должен осуществляться с разумной осмотрительностью после оценки расстояния до приближающихся транспортных средств и их скорости.</p>","image":"assets/adrive-questions/q102001081.jpg"},{"id":102001141,"themeId":5,"group":1020011,"chapter":20,"chapters":[20],"q":"При движении на средстве персональной мобильности:","a":["Водитель должен использовать шлем.","Водителю рекомендуется использовать шлем."],"c":1,"e":"<p>Водителю средства персональной мобильности <strong>рекомендуется</strong> использовать во время движения шлем.</p>","image":"assets/adrive-questions/q102001141.jpg"},{"id":102100101,"themeId":5,"group":1021001,"chapter":21,"chapters":[21],"q":"По достижении какого возраста разрешается управлять гужевым транспортным средством?","a":["С 12 лет.","С 14 лет.","С 16 лет.","С 18 лет."],"c":1,"e":"<p>Согласно Правилам дорожного движения, водители гужевых транспортных средств, всадники и погонщики скота должны быть не моложе четырнадцати лет. Введение нижней границы возраста для водителей гужевых ТС обусловлено необходимостью достижения ими определённого уровня физического и психофизиологического развития, который позволяет усвоить и соблюдать условия безопасности движения по дороге на гужевом ТС. Только с определённого возраста человек может правильно и своевременно реагировать на дорожно-транспортную ситуацию в случае возникновения опасности для движения или препятствия для дорожного движения, а также контролировать поведение животного и управлять им.</p>","image":"assets/adrive-questions/q102100101.jpg"},{"id":102100102,"themeId":5,"group":1021001,"chapter":21,"chapters":[21],"q":"Всадники и погонщики скота должны быть не моложе:","a":["10 лет.","12 лет.","14 лет.","16 лет.","18 лет."],"c":2,"e":"<p>Согласно Правилам дорожного движения, водители гужевых транспортных средств, всадники и погонщики скота должны быть не моложе четырнадцати лет. Только с определённого возраста человек может правильно и своевременно реагировать на дорожно-транспортную ситуацию в случае возникновения опасности для движения или препятствия для дорожного движения, а также контролировать поведение животного и управлять им.</p>","image":null},{"id":102100201,"themeId":5,"group":1021002,"chapter":21,"chapters":[21],"q":"Что из перечисленного ниже запрещается погонщикам скота?","a":["Водить животных по дорогам с усовершенствованным покрытием в населённых пунктах.","Перегонять животных через дорогу в специально оборудованном месте в тёмное время суток при включённом искусственном освещении.","Производить выпас животных в непосредственной близости от полосы земли, на которой размещаются дорога и все её сооружения.","Запрещается всё вышеперечисленное."],"c":1,"e":"<p>Согласно Правилам дорожного движения, водителям гужевых транспортных средств, всадникам и погонщикам скота запрещается:</p> <ul><li>водить животных по дорогам общего пользования с усовершенствованным покрытием вне населённых пунктов;</li> <li>оставлять животных без присмотра на дороге, перегонять их через железнодорожные пути и дороги вне специально оборудованных мест, согласованных в установленном порядке, а также в тёмное время суток и (или) при недостаточной видимости дороги;</li> <li>производить выпас животных в пределах полосы земли, на которой размещаются дорога и все её сооружения.<br> В тёмное время суток и в условиях недостаточной видимости дороги появление животных на проезжей части представляет собой опасность для дорожного движения, так как не позволяет водителю выполнить требования по обеспечению безопасности дорожного движения, возлагаемые на него требованиями Правил дорожного движения.</li></ul> <p>Обеспечить безопасность дорожного движения во время прогона животных в тёмное время суток и в условиях недостаточной видимости дороги не представляется возможным.</p>","image":null},{"id":102100202,"themeId":5,"group":1021002,"chapter":21,"chapters":[21],"q":"Разрешается ли перегонять животных через дорогу в условиях недостаточной видимости?","a":["Запрещается.","Разрешается только в населённых пунктах.","Разрешается только в специально оборудованных местах, согласованных в установленном порядке."],"c":0,"e":"<p>Согласно Правилам дорожного движения, водителям гужевых транспортных средств, всадникам и погонщикам скота запрещается перегонять животных через железнодорожные пути и дороги вне специально оборудованных мест, согласованных в установленном порядке, а также в тёмное время суток и (или) при недостаточной видимости дороги.<br> В тёмное время суток и в условиях недостаточной видимости дороги появление животных на проезжей части представляет собой опасность для дорожного движения, так как не позволяет водителю выполнить требования по обеспечению безопасности дорожного движения, возлагаемые на него требованиями Правил дорожного движения. Обеспечить безопасность дорожного движения во время прогона животных в тёмное время суток и в условиях недостаточной видимости дороги не представляется возможным.</p>","image":null},{"id":102100301,"themeId":5,"group":1021003,"chapter":21,"chapters":[21],"q":"Что из перечисленного ниже запрещается всадникам?","a":["Движение по обочине в два ряда.","Движение по дорожке для всадников в два ряда.","Движение по краю проезжей части дороги в два ряда.","Запрещается всё перечисленное."],"c":2,"e":"<p>Согласно Правилам дорожного движения, движение по проезжей части дороги на гужевых транспортных средствах и всадников разрешается только в один ряд на расстоянии не далее 1 метра от её правого края. Гужевые ТС и верховые животные не могут двигаться со скоростью общего потока транспортных средств, в силу чего, занимая полностью какую-нибудь полосу движения, представляют собой хоть и подвижное, но препятствие для дорожного движения. Поведение животных в ряде случаев непредсказуемо, поэтому Правила дорожного движения предусматривают ограничения относительно их расположения на проезжей части.</p>","image":null},{"id":102100302,"themeId":5,"group":1021003,"chapter":21,"chapters":[21],"q":"В каких случаях движение всадников разрешается далее 1 метра от правого края проезжей части дороги?","a":["Только для опережения.","Только для объезда препятствия.","Только для поворота налево и разворота в разрешённых случаях.","Во всех перечисленных случаях."],"c":2,"e":"<p>Согласно Правилам дорожного движения, всадникам разрешается движение далее 1 метра от правого края проезжей части дороги только для поворота налево и разворота на дорогах с одной полосой для движения в данном направлении и на дороге, не имеющей трамвайный путь.</p>","image":null},{"id":102100401,"themeId":5,"group":1021004,"chapter":21,"chapters":[21],"q":"В каких случаях запрещается разворот гужевому транспортному средству?","a":["Если видимость дороги хотя бы в одном направлении движения менее 100 метров.","Если на дороге имеется трамвайный путь или в данном направлении имеется более одной полосы движения.","Разворот запрещается в обоих перечисленных случаях."],"c":2,"e":"<p>Согласно Правилам дорожного движения, разворот любых транспортных средств запрещается в местах, где видимость дороги хотя бы в одном направлении движения менее 100 метров. Гужевым ТС и всадникам запрещается поворачивать налево или разворачиваться на дороге, имеющей трамвайный путь, и на дороге, имеющей более одной полосы для движения в данном направлении.</p>","image":null},{"id":102100402,"themeId":5,"group":1021004,"chapter":21,"chapters":[21],"q":"В каких случаях запрещается разворот гужевому транспортному средству?","a":["Если при наличии одной попутной полосы имеются две встречные полосы движения.","Если на дороге имеется трамвайный путь.","Разворот запрещается в обоих перечисленных случаях.","Разворот разрешается в обоих перечисленных случаях."],"c":1,"e":"<p>Согласно Правилам дорожного движения, гужевым транспортным средствам и всадникам запрещается поворачивать налево или разворачиваться на дороге, имеющей трамвайный путь, и на дороге, имеющей более одной полосы для движения в данном направлении.</p>","image":null},{"id":102100501,"themeId":5,"group":1021005,"chapter":21,"chapters":[21],"q":"В каком случае разрешается движение гужевых транспортных средств по обочине?","a":["Если это не создаст препятствия для безопасного движения пешеходов.","Если это не создаст препятствия для безопасного движения велосипедистов.","Если это не создаст препятствия для безопасного движения водителей средств персональной мобильности.","Разрешается при выполнении всех перечисленных выше условий."],"c":0,"e":"<p>Согласно Правилам дорожного движения, допускается движение гужевых транспортных средств и всадников по обочине, если это не создаёт препятствия для безопасного движения пешеходов. Движение по обочине гужевого ТС и всадника является предпочтительным, поскольку их скорость движения несоизмеримо меньше по сравнению со скоростью механических ТС, движущихся по дороге. Гужевое ТС или всадник на проезжей части в полосе движения механических ТС представляют собой подвижное (в попутном направлении) препятствие для дорожного движения. Критерием оценки обеспечения безопасности движения пешеходов по обочине водителями гужевых ТС служит ситуация, когда пешеходы могут двигаться без остановок в пределах обочины (без выхода на проезжую часть).</p>","image":"assets/adrive-questions/q102100501.jpg"},{"id":102100502,"themeId":5,"group":1021005,"chapter":21,"chapters":[21],"q":"В каком случае разрешается движение гужевых транспортных средств по обочине?","a":["Если это не создаст препятствия для безопасного движения пешеходов.","Если движение по краю проезжей части не представляется возможным.","Только при выполнении всего перечисленного."],"c":0,"e":"<p>Согласно Правилам дорожного движения, допускается движение гужевых транспортных средств и всадников по обочине, если это не создаёт препятствия для безопасного движения пешеходов. Движение по обочине гужевого ТС и всадника является предпочтительным, поскольку их скорость движения несоизмеримо меньше по сравнению со скоростью механических ТС, движущихся по дороге. Гужевое ТС или всадник на проезжей части в полосе движения механических ТС представляют собой подвижное (в попутном направлении) препятствие для дорожного движения. Критерием оценки обеспечения безопасности движения пешеходов по обочине водителями гужевых ТС служит ситуация, когда пешеходы могут двигаться без остановок в пределах обочины (без выхода на проезжую часть).</p>","image":null},{"id":102100601,"themeId":5,"group":1021006,"chapter":21,"chapters":[21],"q":"Что должен сделать водитель гужевого транспортного средства при выезде с дворовой территории на дорогу в условиях недостаточной видимости?","a":["Вести животное под уздцы.","Включить фонари, спереди излучающие белый свет, а сзади — красный свет.","Должен выполнить всё перечисленное."],"c":2,"e":"<p>Согласно Правилам дорожного движения, при движении по дороге в тёмное время суток и (или) при её недостаточной видимости на гужевом транспортном средстве спереди должен быть включён фонарь, излучающий белый свет, сзади — фонарь, излучающий красный свет. Водитель гужевого транспортного средства, всадник при выезде с второстепенной дороги на главную в тёмное время суток, при недостаточной видимости дороги или в местах с её ограниченной обзорностью обязаны вести животное под уздцы. Внезапное появление механических ТС в местах с ограниченной обзорностью дороги может привести к неконтролируемому перемещению животных вследствие испуга и создать опасность для дорожного движения. Поэтому принятие таких мер (вести животное под уздцы) обеспечивает надёжный контроль над поведением животного и лучшую обзорность дороги и дорожно-транспортной обстановки на ней.</p>","image":null},{"id":102100602,"themeId":5,"group":1021006,"chapter":21,"chapters":[21],"q":"Обязан ли водитель гужевого транспортного средства вести животное под уздцы при выезде на равнозначный перекрёсток в тёмное время суток?","a":["Да, обязан.","Нет, не обязан."],"c":1,"e":"<p>Согласно Правилам дорожного движения, водитель гужевого транспортного средства, всадник при выезде с второстепенной дороги на главную в тёмное время суток, при недостаточной видимости дороги или в местах с её ограниченной обзорностью обязаны вести животное под уздцы. Внезапное появление механических ТС в местах с ограниченной обзорностью дороги может привести к неконтролируемому перемещению животных вследствие испуга и создать опасность для дорожного движения. Поэтому принятие таких мер (вести животное под уздцы) обеспечивает надёжный контроль над поведением животного и лучшую обзорность дороги и дорожно-транспортной обстановки на ней.</p>","image":null},{"id":102200101,"themeId":5,"group":1022001,"chapter":22,"chapters":[22],"q":"Какие внешние световые приборы должны быть включены в обязательном порядке при движении в тёмное время суток на механическом транспортном средстве?","a":["Фары дальнего или ближнего света.","Противотуманные фары и задние противотуманные фонари.","Любые из перечисленных."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при движении в тёмное время суток и (или) при недостаточной видимости дороги независимо от её освещённости на механическом транспортном средстве должны быть включены фары дальнего или ближнего света. Если на ТС фары дальнего и ближнего света конструктивно не выполнены отдельно, то в фарах должен быть включён дальний или ближний свет. Дальний свет фар должен освещать дорогу на расстояние не менее 100 м, но по ряду причин это расстояние может быть большим. С целью лучшего освещения дороги перед ТС в ряде конструкций фар предусмотрено, что при включении дальнего света ближний свет в фаре не выключается. В этом случае считается, что включён дальний свет фар.</p>","image":null},{"id":102200102,"themeId":5,"group":1022001,"chapter":22,"chapters":[22],"q":"Какие внешние световые приборы должны быть включены в обязательном порядке при движении в условиях недостаточной видимости на механическом транспортном средстве?","a":["Фары дальнего или ближнего света.","Противотуманные фары и задние противотуманные фонари.","Любые из перечисленных."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при движении в тёмное время суток и (или) при недостаточной видимости дороги независимо от её освещённости на механическом транспортном средстве должны быть включены фары дальнего или ближнего света. Если на ТС фары дальнего и ближнего света конструктивно не выполнены отдельно, то в фарах должен быть включён дальний или ближний свет. Дальний свет фар должен освещать дорогу на расстояние не менее 100 м, но по ряду причин это расстояние может быть большим. С целью лучшего освещения дороги перед ТС в ряде конструкций фар предусмотрено, что при включении дальнего света ближний свет в фаре не выключается. В этом случае считается, что включён дальний свет фар.</p>","image":null},{"id":102200103,"themeId":5,"group":1022001,"chapter":22,"chapters":[22],"q":"Какие внешние световые приборы допускается включать самостоятельно на транспортном средстве после захода солнца до наступления полной темноты (во время вечерних сумерек)?","a":["Ближний свет фар.","Противотуманные фары.","Противотуманные фары или ближний свет фар.","Противотуманные фары, или ближний свет фар, или дневные ходовые огни."],"c":0,"e":"<p>Во время вечерних сумерек недостаточно включения внешних световых приборов только для обозначения движущегося транспортного средства, возникает ещё необходимость освещать дорогу. С такой задачей могут справиться только либо ближний, либо дальний свет фар.</p>","image":"assets/adrive-questions/q102200103.jpg"},{"id":102200121,"themeId":5,"group":1022001,"chapter":22,"chapters":[22],"q":"При включении каких внешних световых приборов из перечисленных разрешается движение механических транспортных средств в тёмное время суток?","a":["Только габаритных или стояночных огней.","Фар дальнего или ближнего света.","Задних противотуманных фонарей.","Всех перечисленных."],"c":1,"e":"<p>При движении в тёмное время суток независимо от освещённости дороги на механическом транспортном средстве должны быть включены фары дальнего или ближнего света. Наилучшим образом в направлении движения дорога освещается дальним светом фар, поэтому, если Правилами дорожного движения не установлено, что в конкретной ситуации должен быть включён ближний свет фар — предпочтительно осуществлять движение с включённым дальним светом.</p>","image":null},{"id":102200122,"themeId":5,"group":1022001,"chapter":22,"chapters":[22],"q":"Разрешено ли в светлое время суток осуществлять движение на механическом транспортном средстве с включённым ближним светом фар?","a":["Да, только при движении вне населённого пункта.","Да, только при движении в населённом пункте.","Разрешено в обоих перечисленных случаях."],"c":2,"e":"<p>Правилами дорожного движения не установлен запрет на использование ближнего света фар в светлое время суток.</p>","image":null},{"id":102200123,"themeId":5,"group":1022001,"chapter":22,"chapters":[22],"q":"Достаточно ли включить только дневные ходовые огни при движении на механическом транспортном средстве в условиях недостаточной видимости?","a":["Да, достаточно.","Да, только в светлое время суток.","Нет, недостаточно как в светлое, так и в тёмное время суток."],"c":2,"e":"<p>При движении в условиях недостаточной видимости дороги независимо от её освещённости на механическом транспортном средстве должны быть включены фары дальнего или ближнего света. Дневные ходовые огни не обладают достаточной яркостью для обозначения движущегося транспортного средства в условиях недостаточной видимости.</p>","image":null},{"id":102200201,"themeId":5,"group":1022002,"chapter":22,"chapters":[22],"q":"Обязаны ли Вы в показанной ситуации переключить дальний свет фар на ближний?","a":["Обязаны.","Не обязаны.","Обязаны только для исключения возможности ослепления водителей как встречных, так и попутных транспортных средств."],"c":0,"e":"<p>В показанной ситуации водитель въезжает в населённый пункт, где дорога освещена. Согласно Правилам дорожного движения, дальний свет фар должен быть переключен на ближний в населённом пункте, если дорога освещена. В населённых пунктах дорога освещается и, как правило, обеспечивается её видимость на расстоянии, позволяющем двигаться со скоростью 60 км/ч. При этом ближний свет в фарах выполняет не столько функцию освещения проезжей части, сколько обозначения движущегося транспортного средства. Вне населённых пунктов даже на освещённых участках дороги разрешается движение с дальним светом фар, если это не мешает другим водителям ТС.</p>","image":"assets/adrive-questions/q102200201.jpg"},{"id":102200202,"themeId":5,"group":1022002,"chapter":22,"chapters":[22],"q":"Обязаны ли Вы в показанной ситуации, двигаясь по дороге вне населённого пункта, переключить дальний свет фар на ближний?","a":["Обязаны.","Не обязаны."],"c":1,"e":"<p>Согласно Правилам дорожного движения, дальний свет фар должен быть переключен на ближний в населённом пункте, если дорога освещена. Вне населённых пунктов даже на освещённых участках дороги разрешается движение с дальним светом фар, если это не мешает другим водителям ТС.</p>","image":"assets/adrive-questions/q102200202.jpg"},{"id":102200221,"themeId":5,"group":1022002,"chapter":22,"chapters":[22],"q":"Какие внешние световые приборы должны быть включены на механическом транспортном средстве, движущемся в тёмное время суток на освещённом участке дороги в населённом пункте?","a":["Только габаритные огни.","Фары ближнего света.","Габаритные огни или фары ближнего света.","Фары дальнего или ближнего света."],"c":1,"e":"<p>При движении в тёмное время суток независимо от освещённости дороги на механическом транспортном средстве должны быть включены фары дальнего или ближнего света. Однако, в населённом пункте, если дорога освещена, дальний свет фар должен быть переключён на ближний. Это необходимо в том числе для обеспечения полноценного отдыха граждан в ночное время суток, чтобы дальний свет не освещал окна домов.</p>","image":null},{"id":102200222,"themeId":5,"group":1022002,"chapter":22,"chapters":[22],"q":"В каком из перечисленных случаев дальний свет фар должен быть переключен на ближний?","a":["Вне населённых пунктов, если дорога освещена.","В населённых пунктах, если дорога не освещена.","В населённых пунктах, если дорога освещена.","Вне населённых пунктов, если дорога не освещена.","Во всех вышеперечисленных случаях."],"c":2,"e":"<p>При движении в тёмное время суток независимо от освещённости дороги на механическом транспортном средстве должны быть включены фары дальнего или ближнего света. Однако, в населённом пункте, если дорога освещена, дальний свет фар должен быть переключён на ближний. Это необходимо для обеспечения в том числе полноценного отдыха граждан в ночное время суток, чтобы дальний свет не освещал окна домов.</p> <p>Если же дорога не имеет искусственного освещения, разрешается также осуществлять движение с включённым дальним светом фар, особенно на участках дорог, где разрешённая скорость движения повышена при помощи соответствующих дорожных знаков.</p>","image":null},{"id":102200251,"themeId":5,"group":1022002,"chapter":22,"chapters":[22],"q":"Обязаны ли Вы в показанной ситуации после проезда дорожного знака переключить дальний свет фар на ближний?","a":["Обязаны.","Не обязаны.","Обязаны только для исключения возможности ослепления водителей как встречных, так и попутных транспортных средств."],"c":2,"e":"<p>Несмотря на то, что Вы въезжаете в населённый пункт, так как его граница обозначена знаком с синим фоном, на данном участке дороги <strong>не действуют специальные правила движения в населённом пункте</strong>.</p> <p>Поэтому переключить дальний свет фар на ближний необходимо будет <strong>только для исключения возможности ослепления</strong> других водителей.</p>","image":"assets/adrive-questions/q102200251.jpg"},{"id":102200301,"themeId":5,"group":1022003,"chapter":22,"chapters":[22],"q":"Водитель какого транспортного средства из перечисленных переключил свет фар в соответствии с Правилами дорожного движения?","a":["Водитель автобуса, переключив ближний свет на дальний на расстоянии 300 метров до встречного автомобиля.","Водитель легкового автомобиля, переключив дальний свет фар на ближний на расстоянии 250 метров до встречного автомобиля.","Водитель грузового автомобиля, переключив дальний свет фар на ближний на расстоянии 450 метров до встречного автомобиля."],"c":2,"e":"<p>Согласно Правилам дорожного движения, дальний свет фар должен быть переключен на ближний при встречном разъезде на расстоянии не менее 300 метров до транспортного средства, а также на большем расстоянии, если водитель встречного транспортного средства периодическим переключением света фар покажет необходимость этого. Для обеспечения безопасности движения фары с включённым дальним светом должны освещать дорогу на расстояние не менее 100 м. В зависимости от регулировки и конструкции фар это расстояние может быть значительно большим, поэтому Правилами дорожного движения устанавливается минимальное расстояние в 300 метров до встречного ТС для переключения дальнего света фар на ближний во избежание ослепления его водителя. Переключать дальний свет на ближний свет необходимо и в других случаях, когда водитель встречного ТС сигнализирует об этом путём периодического переключения света фар.</p>","image":null},{"id":102200302,"themeId":5,"group":1022003,"chapter":22,"chapters":[22],"q":"На каком минимальном расстоянии до встречного транспортного средства необходимо переключить дальний свет фар на ближний?","a":["150 метров.","250 метров.","300 метров.","359 метров.","450 метров."],"c":2,"e":"<p>Согласно Правилам дорожного движения, дальний свет фар должен быть переключен на ближний при встречном разъезде на расстоянии не менее 300 метров до транспортного средства. Для обеспечения безопасности движения фары с включённым дальним светом должны освещать дорогу на расстояние не менее 100 м. В зависимости от регулировки и конструкции фар это расстояние может быть значительно большим, поэтому Правилами дорожного движения устанавливается минимальное расстояние в 300 метров до встречного ТС для переключения дальнего света фар на ближний во избежание ослепления его водителя.</p>","image":null},{"id":102200303,"themeId":5,"group":1022003,"chapter":22,"chapters":[22],"q":"Должен ли водитель автомобиля переключить дальний свет фар на ближний, если навстречу по обочине движется велосипедист?","a":["Да, должен.","Нет, не должен."],"c":0,"e":"<p>Согласно Правилам дорожного движения, дальний свет фар должен быть переключен на ближний при встречном разъезде на расстоянии не менее 300 метров до транспортного средства. Для обеспечения безопасности движения фары с включённым дальним светом должны освещать дорогу на расстояние не менее 100 м. В зависимости от регулировки и конструкции фар это расстояние может быть значительно большим, поэтому Правилами дорожного движения устанавливается минимальное расстояние в 300 метров до встречного ТС для переключения дальнего света фар на ближний во избежание ослепления его водителя.</p>","image":null},{"id":102200321,"themeId":5,"group":1022003,"chapter":22,"chapters":[22],"q":"На каком расстоянии до встречного транспортного средства Вы должны переключить дальний свет фар на ближний?","a":["Не менее чем за 150 метров.","Не менее чем за 300 метров.","По усмотрению водителя."],"c":1,"e":"<p>Дальний свет фар должен быть переключён на ближний свет при встречном разъезде на расстоянии не менее 300 метров до транспортного средства.</p> <p>Как правило, вежливые водители переключают дальний свет на ближний на гораздо большем расстоянии при встречном разъезде, что не является нарушением ПДД. Однако, если переключать дальний свет фар на ближний на значительно большем расстоянии и продолжать движение на высокой скорости, следует уяснить, что водитель будет двигаться практически вслепую, не будучи способным избежать наезда на внезапно появившееся неподвижное препятствие или пешехода без световозвращающих элементов.</p>","image":null},{"id":102200322,"themeId":5,"group":1022003,"chapter":22,"chapters":[22],"q":"Обязан ли водитель автомобиля в тёмное время суток переключить дальний свет фар на ближний, если навстречу по обочине движется пешеход?","a":["Да, обязан.","Нет, не обязан."],"c":1,"e":"<p>Дальний свет фар должен быть переключён на ближний свет при встречном разъезде на расстоянии не менее 300 метров до транспортного средства. При приближении к пешеходу водитель не обязан переключать дальний свет на ближний. Отчасти это обусловлено тем, чтобы не потерять контроль над положением и направлением движения пешехода. Но если водитель не хочет слепить пешехода, ему не запрещено переключить дальний свет фар на ближний при приближении к пешеходу.</p>","image":null},{"id":102200401,"themeId":5,"group":1022004,"chapter":22,"chapters":[22],"q":"Что может означать включение аварийной световой сигнализации водителем встречного автомобиля в тёмное время суток?","a":["Ослепление водителя дальним или ближним светом фар.","Просьбу о переключении дальнего света фар на ближний.","Всё вышеперечисленное."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при ослеплении водитель должен немедленно включить аварийную световую сигнализацию и, не перестраиваясь, снизить скорость движения и остановиться.</p> <p>Тормозить при ослеплении необходимо плавно, то есть в режиме «служебного торможения», чтобы избежать попутного столкновения с транспортными средствами, движущимися сзади по этой же полосе движения. При этом маневрировать до полной адаптации глаз запрещается, поскольку водитель не в состоянии оценить обстановку на соседней полосе движения или обочине, где может возникнуть препятствие для движения в виде движущихся велосипедистов, пешеходов, гужевых ТС и другие.</p>","image":"assets/adrive-questions/q102200401.jpg"},{"id":102200402,"themeId":5,"group":1022004,"chapter":22,"chapters":[22],"q":"Что может означать включение аварийной световой сигнализации водителем автомобиля, движущегося в попутном направлении в тёмное время суток?","a":["Ослепление водителя дальним или ближним светом фар.","Просьбу о переключении дальнего света фар на ближний.","Всё вышеперечисленное."],"c":2,"e":"<p>Согласно Правилам дорожного движения, в случае ослепления водителя светом фар (дальним или ближним) должна быть включена аварийная световая сигнализация. Кроме того, если дальний свет фар будет освещать движущееся в попутном направлении ТС или его водитель включением аварийной световой сигнализации покажет необходимость такого переключения, то дальний свет фар должен быть переключен на ближний.</p>","image":null},{"id":102200431,"themeId":5,"group":1022004,"chapter":22,"chapters":[22],"q":"Что Вы обязаны выполнить, если в тёмное время суток водитель встречного автомобиля начал периодически переключать свет фар?","a":["Выключить свет фар.","Снизить скорость движения.","Включить противотуманные фары.","Переключить дальний свет фар на ближний.","Включить аварийную световую сигнализацию и остановиться."],"c":3,"e":"<p>Кратковременное переключение света фар в тёмное время суток может использоваться для выражения просьбы о заблаговременном переключении дальнего света фар на ближний при встречном разъезде. Такие условия могут быть созданы при неправильной регулировке света фар, применении световых приборов, не предусмотренных конструкцией транспортного средства, при проезде поворотов дороги, подъёмов и спусков, перекрёстков.</p>","image":null},{"id":102200432,"themeId":5,"group":1022004,"chapter":22,"chapters":[22],"q":"Как Вам показать водителю встречного автомобиля необходимость переключения дальнего света фар на ближний свет для уменьшения слепящего действия на большем расстоянии, чем определено Правилами?","a":["Выключением света фар.","Включением звукового сигнала.","Включением дальнего света фар.","Периодическим переключением света фар.","Включением аварийной световой сигнализации."],"c":3,"e":"<p>Кратковременное переключение света фар в тёмное время суток может использоваться для выражения просьбы о заблаговременном переключении дальнего света фар на ближний при встречном разъезде. Такие условия могут быть созданы при неправильной регулировке света фар, применении световых приборов, не предусмотренных конструкцией транспортного средства, при проезде поворотов дороги, подъёмов и спусков, перекрёстков.</p>","image":null},{"id":102200501,"themeId":5,"group":1022005,"chapter":22,"chapters":[22],"q":"Как должен поступить водитель автомобиля, если его ослепил дальним светом автомобиль, движущийся навстречу?","a":["Включить дальний свет фар и продолжить движение в своей полосе до полного восстановления зрения.","Включить аварийную световую сигнализацию, снизить скорость движения и, съехав на обочину, остановиться.","Включить аварийную световую сигнализацию и, не перестраиваясь, снизить скорость движения и остановиться.","Включить аварийную световую сигнализацию и, съехав на обочину, снизить скорость движения и остановиться."],"c":2,"e":"<p>Согласно Правилам дорожного движения, при ослеплении водитель должен немедленно включить аварийную световую сигнализацию и, не перестраиваясь, снизить скорость движения и остановиться.</p> <p>Тормозить при ослеплении необходимо плавно, то есть в режиме «служебного торможения», чтобы избежать попутного столкновения с транспортными средствами, движущимися сзади по этой же полосе движения. При этом маневрировать до полной адаптации глаз запрещается, поскольку водитель не в состоянии оценить обстановку на соседней полосе движения или обочине, где может возникнуть препятствие для движения в виде движущихся велосипедистов, пешеходов, гужевых ТС, и другие.</p>","image":null},{"id":102200502,"themeId":5,"group":1022005,"chapter":22,"chapters":[22],"q":"Как должен поступить водитель автомобиля, если его ослепил дальним светом автомобиль, движущийся сзади в попутном направлении?","a":["Прибегнуть к экстренному торможению, после чего включить аварийную световую сигнализацию.","Включить аварийную световую сигнализацию, снизить скорость движения и, съехав на обочину, остановиться.","Включить аварийную световую сигнализацию и, не перестраиваясь, снизить скорость движения и остановиться.","Включить аварийную световую сигнализацию и, съехав на обочину, снизить скорость движения и остановиться."],"c":2,"e":"<p>Согласно Правилам дорожного движения, при ослеплении водитель должен немедленно включить аварийную световую сигнализацию и, не перестраиваясь, снизить скорость движения и остановиться.</p> <p>Тормозить при ослеплении необходимо плавно, то есть в режиме «служебного торможения», чтобы избежать попутного столкновения с транспортными средствами, движущимися сзади по этой же полосе движения. При этом маневрировать до полной адаптации глаз запрещается, поскольку водитель не в состоянии оценить обстановку на соседней полосе движения или обочине, где может возникнуть препятствие для движения в виде движущихся велосипедистов, пешеходов, гужевых ТС, и другие.</p>","image":null},{"id":102200521,"themeId":5,"group":1022005,"chapter":22,"chapters":[22],"q":"Как Вы должны поступить при ослеплении Вас дальним светом фар встречных или попутно движущихся транспортных средств?","a":["Включить аварийную световую сигнализацию, перестроиться по возможности вправо и остановиться.","Включить аварийную световую сигнализацию и, не перестраиваясь, снизить скорость движения и остановиться.","Подавая звуковой сигнал, остановиться."],"c":1,"e":"<p>При резкой смене освещённости человеческому глазу требуется некоторое время на то, чтобы адаптироваться к новым условиям. Так, при ослеплении фарами дальнего света среднестатистический водитель около 10 секунд будет ехать вслепую. Даже если скорость всего 60 км/ч, за это время автомобиль проедет более 100 м.</p> <p>Поэтому, при ослеплении водитель должен немедленно включить аварийную световую сигнализацию и, не перестраиваясь, снизить скорость движения и остановиться.</p>","image":null},{"id":102200601,"themeId":5,"group":1022006,"chapter":22,"chapters":[22],"q":"Обязан ли водитель включить габаритные или стояночные огни при остановке или стоянке в тёмное время суток на освещённом участке дороги (кроме жилых зон)?","a":["Да, обязан.","Нет, не обязан."],"c":1,"e":"<p>Согласно Правилам дорожного движения, при остановке, стоянке в тёмное время суток на неосвещённых участках дороги и (или) при её недостаточной видимости (кроме жилых зон) на транспортном средстве должны быть включены габаритные или стояночные огни.</p> <p>В условиях, когда видимость дороги в направлении движения менее 300 м, а также в тёмное время суток на участках дорог, не имеющих искусственного освещения, в целях обеспечения безопасности дорожного движения Правила дорожного движения предписывают обозначить транспортное средство указанными огнями с целью своевременного обнаружения его другими водителями ТС.</p>","image":null},{"id":102200602,"themeId":5,"group":1022006,"chapter":22,"chapters":[22],"q":"Обязан ли водитель включить габаритные или стояночные огни при остановке или стоянке в тёмное время суток на неосвещённом участке дороги (кроме жилых зон)?","a":["Да, обязан.","Нет, не обязан."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при остановке, стоянке в тёмное время суток на неосвещённых участках дороги и (или) при её недостаточной видимости (кроме жилых зон) на транспортном средстве должны быть включены габаритные или стояночные огни.</p> <p>В условиях, когда видимость дороги в направлении движения менее 300 м, а также в тёмное время суток на участках дорог, не имеющих искусственного освещения, в целях обеспечения безопасности дорожного движения Правила дорожного движения предписывают обозначить транспортное средство указанными огнями с целью своевременного обнаружения его другими водителями ТС.</p>","image":null},{"id":102200603,"themeId":5,"group":1022006,"chapter":22,"chapters":[22],"q":"Обязан ли водитель включить габаритные или стояночные огни при остановке или стоянке в тёмное время суток на неосвещённом участке дороги в жилой зоне?","a":["Да, обязан.","Нет, не обязан."],"c":1,"e":"<p>Согласно Правилам дорожного движения, при остановке, стоянке в тёмное время суток на неосвещённых участках дороги и (или) при её недостаточной видимости (кроме жилых зон) на транспортном средстве должны быть включены габаритные или стояночные огни.</p>","image":null},{"id":102200661,"themeId":5,"group":1022006,"chapter":22,"chapters":[22],"q":"При остановке и стоянке в жилой зоне в тёмное время суток на неосвещённых участках дороги или при недостаточной видимости на автомобиле, согласно Правилам дорожного движения:","a":["Должны быть включены габаритные или стояночные огни.","Должна быть включена аварийная световая сигнализация.","Должна быть включена аварийная световая сигнализация и незамедлительно выставлен знак аварийной остановки.","Не требуется включения внешних световых приборов."],"c":3,"e":"<p>При остановке, стоянке в тёмное время суток на неосвещённых участках дороги и (или) при её недостаточной видимости <strong>в жилых зонах</strong> на транспортном средстве <strong>не требуется включать габаритные или стояночные огни</strong>.</p>","image":"assets/adrive-questions/q102200661.jpg"},{"id":102200662,"themeId":5,"group":1022006,"chapter":22,"chapters":[22],"q":"При остановке и стоянке в тёмное время суток на освещённых участках дороги на автомобиле, согласно Правилам дорожного движения:","a":["Должны быть включены габаритные или стояночные огни.","Должна быть включена аварийная световая сигнализация.","Должна быть включена аварийная световая сигнализация и незамедлительно выставлен знак аварийной остановки.","Не требуется включения внешних световых приборов."],"c":3,"e":"<p>При остановке, стоянке в тёмное время суток <strong>на освещённых участках</strong> дороги на транспортном средстве <strong>не требуется включать габаритные или стояночные огни</strong>.</p>","image":"assets/adrive-questions/q102200662.jpg"},{"id":102200701,"themeId":5,"group":1022007,"chapter":22,"chapters":[22],"q":"Нужно ли включать внешние световые приборы на транспортном средстве при остановке в тёмное время суток на освещённом участке дороги вне населённого пункта?","a":["Необходимо включить габаритные или стояночные огни.","Необходимо включить противотуманные фары и фонари.","Необходимо включить аварийную световую сигнализацию.","Включение внешних световых приборов в данной ситуации не обязательно."],"c":3,"e":"<p>При остановке в тёмное время суток на освещённых участках дороги на автомобиле Правила дорожного движения не требуют включать внешние световые приборы.</p> <p>Водитель принимает решение о необходимости включения соответствующих фонарей сам, исходя из складывающейся конкретной ситуации. Например, если включено искусственное освещение, но густая листва деревьев затеняет отдельные участки на проезжей части дороги.</p>","image":null},{"id":102200702,"themeId":5,"group":1022007,"chapter":22,"chapters":[22],"q":"Как правильно обозначить транспортное средство при остановке в тёмное время суток на неосвещённом участке дороги вне населённого пункта?","a":["Включить габаритные или стояночные огни.","Включить противотуманные фары и фонари.","Включить аварийную световую сигнализацию.","Включение внешних световых приборов в данной ситуации необязательно."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при остановке в тёмное время суток на неосвещённых участках дороги и (или) при её недостаточной видимости (кроме жилых зон) на транспортном средстве должны быть включены габаритные или стояночные огни.</p> <p>В условиях, когда видимость дороги в направлении движения менее 300 м, а также в тёмное время суток на участках дорог, не имеющих искусственного освещения, в целях обеспечения безопасности дорожного движения Правила дорожного движения предписывают обозначить транспортное средство указанными огнями с целью своевременного обнаружения его другими водителями ТС.</p>","image":null},{"id":102200722,"themeId":5,"group":1022007,"chapter":22,"chapters":[22],"q":"Какие внешние световые приборы, согласно Правилам дорожного движения, должны быть включены на транспортном средстве при остановке или стоянке в тёмное время суток на неосвещённых участках дороги (кроме жилых зон)?","a":["Дальний свет фар.","Задние противотуманные фонари.","Габаритные или стояночные огни.","Противотуманные фары.","Ближний свет фар."],"c":2,"e":"<p>При остановке, стоянке в тёмное время суток на неосвещённых участках дороги на транспортном средстве должны быть включены габаритные или стояночные огни. Данное правило способствует возможности своевременного обнаружения остановившегося транспортного средства водителями прочих транспортных средств, движущихся по дороге.</p>","image":null},{"id":102200801,"themeId":5,"group":1022008,"chapter":22,"chapters":[22],"q":"Нарушит ли Правила дорожного движения водитель, поставив автомобиль на стоянку на освещённом участке дороги в условиях недостаточной видимости в населённом пункте вне жилой зоны, не включив габаритные или стояночные огни?","a":["Да, нарушит.","Нет, не нарушит."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при остановке, стоянке в тёмное время суток на неосвещённых участках дороги и (или) при её недостаточной видимости (кроме жилых зон) на транспортном средстве должны быть включены габаритные или стояночные огни.</p> <p>В условиях, когда видимость дороги в направлении движения менее 300 м, а также в тёмное время суток на участках дорог, не имеющих искусственного освещения, в целях обеспечения безопасности дорожного движения Правила дорожного движения предписывают обозначить транспортное средство указанными огнями с целью своевременного обнаружения его другими водителями ТС.</p>","image":null},{"id":102200803,"themeId":5,"group":1022008,"chapter":22,"chapters":[22],"q":"Нарушит ли Правила дорожного движения водитель, совершив остановку в условиях недостаточной видимости в населённом пункте вне жилой зоны на обочине, не включив габаритные или стояночные огни?","a":["Да, нарушит.","Нет, не нарушит."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при остановке, стоянке в тёмное время суток на неосвещённых участках дороги и (или) при её недостаточной видимости (кроме жилых зон) на транспортном средстве должны быть включены габаритные или стояночные огни.</p> <p>В условиях, когда видимость дороги в направлении движения менее 300 м, а также в тёмное время суток на участках дорог, не имеющих искусственного освещения, в целях обеспечения безопасности дорожного движения Правила дорожного движения предписывают обозначить транспортное средство указанными огнями с целью своевременного обнаружения его другими водителями ТС.</p>","image":null},{"id":102200821,"themeId":5,"group":1022008,"chapter":22,"chapters":[22],"q":"При остановке и стоянке в тёмное время суток на неосвещённых участках дороги или при её недостаточной видимости (кроме жилых зон) на автомобиле, согласно Правилам дорожного движения:","a":["Должны быть включены ближний свет фар и задние габаритные огни.","Должна быть включена аварийная световая сигнализация.","Должен быть включён ближний свет фар и незамедлительно выставлен знак аварийной остановки.","Должны быть включены габаритные или стояночные огни.","Включение внешних световых приборов не требуется."],"c":3,"e":"<p>При остановке, стоянке в тёмное время суток на неосвещённых участках дороги и (или) при её недостаточной видимости на транспортном средстве должны быть включены габаритные или стояночные огни. Данное правило способствует возможности своевременного обнаружения остановившегося транспортного средства водителями прочих транспортных средств, движущихся по дороге.</p>","image":null},{"id":102200822,"themeId":5,"group":1022008,"chapter":22,"chapters":[22],"q":"При остановке и стоянке в жилой зоне в тёмное время суток на неосвещённых участках дороги или при недостаточной видимости на автомобиле, согласно Правилам дорожного движения:","a":["Должны быть включены ближний свет фар и задние габаритные огни.","Должна быть включена аварийная световая сигнализация.","Должен быть включён ближний свет фар и незамедлительно выставлен знак аварийной остановки.","Должны быть включены габаритные или стояночные огни.","Включение внешних световых приборов не требуется."],"c":4,"e":"<p>При остановке, стоянке в тёмное время суток на неосвещённых участках дороги и (или) при её недостаточной видимости на транспортном средстве должны быть включены габаритные или стояночные огни.</p> <p>Однако на жилые зоны данное правило не распространяется. Транспортные средства могут храниться (находиться на длительной стоянке) на проездах в жилых зонах, и длительное включение габаритных (стояночных) огней приведёт к полной разрядке автомобильных аккумуляторов.</p>","image":null},{"id":102200921,"themeId":5,"group":1022009,"chapter":22,"chapters":[22],"q":"Двигаясь в тёмное время суток вне населённого пункта с включёнными фарами дальнего света, Вы догнали движущееся впереди транспортное средство. Ваши действия?","a":["Оставите включёнными габаритные огни, выключив фары дальнего света.","Переключите дальний свет фар на ближний.","Допускаются оба варианта действий."],"c":1,"e":"<p>Дальний свет фар должен быть переключён на ближний, если дальний свет фар будет освещать движущееся в попутном направлении транспортное средство, или его водитель включением аварийной световой сигнализации покажет необходимость такого переключения.</p>","image":"assets/adrive-questions/q102200921.jpg"},{"id":102200952,"themeId":5,"group":1022009,"chapter":22,"chapters":[22],"q":"Какое Ваше действие, как водителя обгоняемого автомобиля, будет противоречить требованиям Правил дорожного движения?","a":["Увеличение скорости движения.","Переключение дальнего света фар на ближний.","Смещение вправо к линии разметки, обозначающей край проезжей части дороги.","Все вышеперечисленные."],"c":0,"e":"<p>Водителю обгоняемого транспортного средства запрещается <strong>препятствовать обгону увеличением скорости</strong> движения или иными действиями.</p> <p>При этом следует <strong>двигаться ближе к правому краю</strong> проезжей части дороги и <strong>переключить дальний свет фар на ближний</strong>.</p>","image":"assets/adrive-questions/q102200952.jpg"},{"id":102201001,"themeId":5,"group":1022010,"chapter":22,"chapters":[22],"q":"В каком из перечисленных случаев противотуманные фары не могут использоваться вместо ближнего света фар?","a":["В условиях недостаточной видимости дороги.","При ухудшении видимости транспортного средства на дороге.","Во время обучения управлению механическим транспортным средством на дорогах.","Не могут использоваться во всех перечисленных случаях."],"c":0,"e":"<p>Согласно Правилам дорожного движения, противотуманные фары на транспортном средстве могут использоваться водителем в тёмное время суток и (или) при недостаточной видимости дороги только совместно с ближним или дальним светом фар.</p> <p>К противотуманным фарам относятся фары, предназначенные для улучшения освещения дороги в условиях тумана, снегопада, дождя и в других случаях, когда снижается прозрачность атмосферы.</p> <p>Эффект улучшения освещения дороги в такой фаре достигается широким световым лучом, направляемым под пелену тумана, нижняя кромка которого, как правило, не достигает поверхности дороги.</p>","image":null},{"id":102201002,"themeId":5,"group":1022010,"chapter":22,"chapters":[22],"q":"В каком из перечисленных случаев противотуманные фары могут использоваться вместо ближнего света фар в светлое время суток?","a":["На мотоцикле или мопеде.","При движении в транспортной колонне.","При ухудшении видимости транспортного средства на дороге.","Во время обучения управлению механическим транспортным средством на дорогах.","Могут использоваться во всех перечисленных случаях."],"c":4,"e":"<p>Согласно Правилам дорожного движения, противотуманные фары могут использоваться вместо ближнего света фар:</p> <ul><li>на мотоцикле и мопеде;</li> <li>при движении в транспортной колонне;</li> <li>на маршрутном транспортном средстве, движущемся по специально выделенной полосе навстречу движению;</li> <li>при организованной перевозке группы детей;</li> <li>при перевозке опасных грузов, движении тяжеловесных и (или) крупногабаритных транспортных средств;</li> <li>при буксировке (на буксирующем транспортном средстве);</li> <li>во время обучения управлению механическим транспортным средством на дорогах;</li> <li>на механических транспортных средствах при организации временного их движения по встречной полосе движения;</li> <li>в период проведения Министерством внутренних дел республиканских специальных комплексных мероприятий по обеспечению безопасности дорожного движения, предусматривающих движение транспортных средств в светлое время суток с включёнными ближним светом фар или дневными ходовыми огнями (при их наличии);</li> <li>при ухудшении видимости транспортного средства на дороге для его обозначения во время движения в светлое время суток.</li></ul>","image":null},{"id":102201021,"themeId":5,"group":1022010,"chapter":22,"chapters":[22],"q":"Разрешено ли в светлое время суток осуществлять движение на механическом транспортном средстве с включённым ближним светом фар?","a":["Да, только при движении на мотоцикле или мопеде.","Да, только при движении на легковом автомобиле.","Разрешено в любом случае."],"c":2,"e":"<p>Правилами дорожного движения не установлен запрет на использование ближнего света фар в светлое время суток в ситуациях, не описанных в главе 22. Наоборот, при ухудшении видимости автомобиля водитель может принять решение о включении ближнего света фар, противотуманных фар или дневных ходовых огней.</p> <p>Ухудшение видимости транспортного средства может наступить при въезде тёмного автомобиля в тень здания или деревьев, в случае движения в лучах заходящего или восходящего солнца и в прочих ситуациях. Водитель может даже не подозревать об ухудшении видимости своего транспортного средства.</p>","image":null},{"id":102201022,"themeId":5,"group":1022010,"chapter":22,"chapters":[22],"q":"Как следует поступить водителю для улучшения видимости его автомобиля в светлое время суток в показанной ситуации?","a":["Включить дневные ходовые огни.","Включить фары ближнего света.","Включить противотуманные фары.","Допустимо любое из перечисленных действий."],"c":3,"e":"<p>При ухудшении видимости транспортного средства на дороге для его обозначения во время движения в светлое время суток могут быть включены ближний свет фар или дневные ходовые огни (при их наличии), либо противотуманные фары.</p> <p>В показанной ситуации, при попадании тёмного автомобиля в теневую область, видимость транспортного средства на дороге ухудшилась, и водителю стоит обозначить автомобиль включением внешних световых приборов.</p>","image":"assets/adrive-questions/q102201022.jpg"},{"id":102201024,"themeId":5,"group":1022010,"chapter":22,"chapters":[22],"q":"В каком случае из перечисленных могут использоваться противотуманные фары?","a":["В тёмное время суток на неосвещённых участках дорог совместно с дальним светом фар.","Вместо ближнего света фар в светлое время при буксировке механических транспортных средств (на буксирующем транспортном средстве).","Вместо ближнего света фар в светлое время суток при ухудшении видимости транспортного средства на дороге.","Во всех перечисленных случаях."],"c":3,"e":"<p>Противотуманные фары на транспортном средстве могут использоваться водителем в тёмное время суток и (или) при недостаточной видимости дороги совместно с ближним или дальним светом фар.</p> <p>Также противотуманные фары могут использоваться вместо ближнего света фар в условиях, предусмотренных Правилами дорожного движения для обозначения движущегося транспортного средства в светлое время суток и в условиях ухудшения видимости транспортного средства на дороге.</p>","image":null},{"id":102201101,"themeId":5,"group":1022011,"chapter":22,"chapters":[22],"q":"Обязан ли водитель выключить противотуманные фары (включённые в дополнение к ближнему свету фар) при въезде в населённый пункт, если дорога освещена?","a":["Да, обязан.","Нет, не обязан."],"c":1,"e":"<p>В дополнение к ближнему свету фар могут использоваться противотуманные фары. В зависимости от условий видимости дороги водитель вправе сам принимать решение о том, какой свет в фарах (например, противотуманные фары совместно с ближним светом фар) он будет включать.</p> <p>Включение противотуманных фар совместно с ближним или дальним светом фар позволяет улучшить освещение проезжей части в непосредственной близости перед транспортным средством.</p>","image":"assets/adrive-questions/q102201101.jpg"},{"id":102201102,"themeId":5,"group":1022011,"chapter":22,"chapters":[22],"q":"Что недопустимо использовать для освещения дороги в тёмное время суток?","a":["Только ближний свет фар.","Только дальний свет фар.","Только противотуманные фары.","Противотуманные фары совместно с ближним светом фар.","Допустимо использовать любой из перечисленных вариантов."],"c":2,"e":"<p>Согласно Правилам дорожного движения, противотуманные фары на транспортном средстве могут использоваться водителем в тёмное время суток и (или) при недостаточной видимости дороги только совместно с ближним или дальним светом фар.</p> <p>Включение противотуманных фар совместно с ближним или дальним светом фар позволяет улучшить освещение проезжей части в непосредственной близости перед транспортным средством. Использования только противотуманных фар для полноценного освещения дороги недостаточно.</p>","image":null},{"id":102201121,"themeId":5,"group":1022011,"chapter":22,"chapters":[22],"q":"Какие внешние световые приборы из перечисленных может использовать водитель легкового автомобиля для освещения дороги, двигаясь в тёмное время суток?","a":["Фары ближнего света.","Фары дальнего света.","Противотуманные фары совместно с ближним светом фар.","Противотуманные фары совместно с дальним светом фар.","Любые из перечисленных."],"c":4,"e":"<p>При движении в тёмное время суток независимо от её освещённости на механическом транспортном средстве должны быть включены фары дальнего или ближнего света.</p> <p>Противотуманные фары на транспортном средстве могут использоваться водителем в тёмное время суток совместно с ближним или дальним светом фар.</p>","image":null},{"id":102201201,"themeId":5,"group":1022012,"chapter":22,"chapters":[22],"q":"Разрешается ли использовать противотуманные фары днём в условиях недостаточной видимости вместо ближнего света фар?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, противотуманные фары на транспортном средстве могут использоваться водителем в тёмное время суток и (или) при недостаточной видимости дороги совместно с ближним или дальним светом фар.</p> <p>Включение противотуманных фар совместно с ближним или дальним светом фар позволяет улучшить освещение проезжей части в непосредственной близости перед транспортным средством. Использование только противотуманных фар для полноценного освещения дороги или обозначения движущегося транспортного средства в условиях недостаточной видимости дороги недостаточно.</p>","image":null},{"id":102201202,"themeId":5,"group":1022012,"chapter":22,"chapters":[22],"q":"Разрешается ли выключить ближний свет фар днём в условиях сильного тумана, если на автомобиле дополнительно включены противотуманные фары?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, противотуманные фары на транспортном средстве могут использоваться водителем в тёмное время суток и (или) при недостаточной видимости дороги совместно с ближним или дальним светом фар.</p> <p>Включение противотуманных фар совместно с ближним или дальним светом фар позволяет улучшить освещение проезжей части в непосредственной близости перед транспортным средством. Использование только противотуманных фар для полноценного освещения дороги или обозначения движущегося транспортного средства в условиях недостаточной видимости дороги недостаточно.</p>","image":null},{"id":102201221,"themeId":5,"group":1022012,"chapter":22,"chapters":[22],"q":"Как при движении в тёмное время суток на неосвещённых участках дорог разрешено использовать противотуманные фары?","a":["Только отдельно от ближнего или дальнего света фар.","Только совместно с ближним или дальним светом фар.","Как отдельно, так и совместно с ближним или дальним светом фар."],"c":1,"e":"<p>Противотуманные фары на транспортном средстве могут использоваться водителем в тёмное время суток только совместно с ближним или дальним светом фар.</p> <p>Противотуманные фары не предназначены для освещения дороги в направлении движения на расстоянии более 20 метров и служат в большей степени для обозначения транспортного средства в условиях недостаточной видимости.</p>","image":null},{"id":102201222,"themeId":5,"group":1022012,"chapter":22,"chapters":[22],"q":"При движении в условиях недостаточной видимости противотуманные фары разрешено использовать:","a":["Как отдельно, так и совместно с ближним или дальним светом фар.","Только отдельно от ближнего или дальнего света фар.","Только совместно с ближним или дальним светом фар."],"c":2,"e":"<p>Противотуманные фары на транспортном средстве могут использоваться водителем при недостаточной видимости дороги только совместно с ближним или дальним светом фар.</p> <p>Противотуманные фары не предназначены для освещения дороги в направлении движения на расстоянии более 20 метров и служат в большей степени для обозначения транспортного средства в условиях недостаточной видимости.</p>","image":null},{"id":102201301,"themeId":5,"group":1022013,"chapter":22,"chapters":[22],"q":"Что должно быть включено при буксировке на буксирующем транспортном средстве в светлое время суток?","a":["Дальний свет фар.","Аварийная световая сигнализация.","Ближний свет фар или дневные ходовые огни.","Любое из вышеперечисленного."],"c":2,"e":"<p>Согласно Правилам дорожного движения, в светлое время суток для обозначения движущегося транспортного средства должны быть включены ближний свет фар или дневные ходовые огни (при их наличии) при буксировке (на буксирующем транспортном средстве).</p> <p>Движение сцепленных между собой механических транспортных средств создаёт определённые сложности для других участников дорожного движения в силу их увеличенных размеров по длине, низкой скорости движения и низкой манёвренной способности. Поэтому Правила дорожного движения требуют дополнительно обозначить буксирующее ТС путём включения ближнего света фар или дневных ходовых огней.</p>","image":null},{"id":102201302,"themeId":5,"group":1022013,"chapter":22,"chapters":[22],"q":"В каком из перечисленных случаев водитель правильно воспользовался внешними световыми приборами при движении в транспортной колонне в светлое время суток?","a":["Включил дальний свет вместо ближнего света фар.","Включил противотуманные фары вместо ближнего света фар.","Включил габаритные огни вместо ближнего света фар.","Включил аварийную световую сигнализацию вместо ближнего света фар."],"c":1,"e":"<p>При движении в составе транспортной колонны в целях информирования участников дорожного движения о принадлежности к транспортной колонне на механических транспортных средствах вместо ближнего света фар могут быть включены противотуманные фары. Данное требование в полной мере относится к ТС, движущимся в организованной транспортной колонне.</p>","image":null},{"id":102201401,"themeId":5,"group":1022014,"chapter":22,"chapters":[22],"q":"Что должно быть включено на транспортном средстве при организованной перевозке группы детей в светлое время суток, если движение осуществляется не в транспортной колонне?","a":["Дальний свет фар.","Ближний свет фар или дневные ходовые огни.","Включение внешних световых приборов необязательно."],"c":1,"e":"<p>Согласно Правилам дорожного движения, в светлое время суток для обозначения движущегося транспортного средства должны быть включены ближний свет фар или дневные ходовые огни (при их наличии) при организованной перевозке группы детей.</p> <p>При организованной перевозке групп детей включение фар является дополнительной мерой обеспечения безопасности дорожного движения наряду со специальным опознавательным знаком «Перевозка детей» .</p> <p>Свет фар привлекает внимание участников дорожного движения и регулировщиков к транспортным средствам, осуществляющим организованную перевозку детей.</p>","image":null},{"id":102201402,"themeId":5,"group":1022014,"chapter":22,"chapters":[22],"q":"Что должно быть включено на транспортном средстве при организованной перевозке группы детей в тёмное время суток, если движение осуществляется не в транспортной колонне?","a":["Ближний или дальний свет фар.","Ближний свет фар или дневные ходовые огни.","Ближний свет фар или противотуманные фары.","Противотуманные фары вместо ближнего света фар."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при движении в тёмное время суток и (или) при недостаточной видимости дороги независимо от её освещённости на механическом транспортном средстве должны быть включены фары дальнего или ближнего света.</p> <p>Если на транспортном средстве фары дальнего и ближнего света конструктивно не выполнены отдельно, то в фарах должен быть включён дальний или ближний свет.</p> <p>Дальний свет фар должен освещать дорогу на расстояние не менее 100 м, но по ряду причин это расстояние может быть большим. С целью лучшего освещения дороги перед транспортным средством в ряде конструкций фар предусмотрено, что при включении дальнего света ближний свет в фаре не выключается. В этом случае считается, что включён дальний свет фар.</p>","image":null},{"id":102201501,"themeId":5,"group":1022015,"chapter":22,"chapters":[22],"q":"Как правильно использовать внешние световые приборы при буксировке механических транспортных средств в светлое время суток?","a":["Включить на буксирующем и буксируемом транспортных средствах аварийную световую сигнализацию.","Включить на буксирующем и буксируемом транспортных средствах ближний свет фар или дневные ходовые огни.","Включить на буксирующем транспортном средстве ближний или дальний свет фар, а на буксируемом — габаритные огни.","Включить на буксирующем транспортном средстве ближний свет фар, или противотуманные фары, или дневные ходовые огни, а на буксируемом — аварийную световую сигнализацию."],"c":3,"e":"<p>Согласно Правилам дорожного движения, при буксировке на буксируемом транспортном средстве должна быть включена аварийная световая сигнализация, а на буксирующем ТС в светлое время суток должны быть включены ближний свет фар, либо противотуманные фары, либо дневные ходовые огни.</p> <p>Движение сцепленных между собой механических транспортных средств создаёт определённые сложности для других участников дорожного движения в силу их увеличенных размеров по длине, низкой скорости движения и низкой манёвренной способности. Поэтому Правила дорожного движения требуют дополнительно обозначить буксирующее и буксируемое ТС.</p>","image":null},{"id":102201502,"themeId":5,"group":1022015,"chapter":22,"chapters":[22],"q":"Что не может быть использовано вместо ближнего света фар в светлое время суток на буксирующем транспортном средстве при буксировке механического транспортного средства?","a":["Дальний свет фар.","Дневные ходовые огни.","Противотуманные фары.","Любое из перечисленного может быть использовано."],"c":0,"e":"<p>Согласно Правилам дорожного движения, при буксировке на буксирующем транспортном средстве в светлое время суток должны быть включены ближний свет фар, либо противотуманные фары, либо дневные ходовые огни.</p>","image":null},{"id":102201521,"themeId":5,"group":1022015,"chapter":22,"chapters":[22],"q":"Какие внешние световые приборы из перечисленных допускается включить на автомобиле, буксирующем другой автомобиль, в светлое время суток?","a":["Задние противотуманные фонари.","Аварийную световую сигнализацию.","Фары дальнего света.","Противотуманные фары вместо ближнего света фар."],"c":3,"e":"<p>В светлое время суток для обозначения буксировки на буксирующем транспортном средстве должны быть включены ближний свет фар или дневные ходовые огни (при их наличии).</p> <p>При этом вместо ближнего света фар при буксировке могут использоваться противотуманные фары.</p>","image":null},{"id":102201601,"themeId":5,"group":1022016,"chapter":22,"chapters":[22],"q":"Какие внешние световые приборы должны быть включены на буксирующем транспортном средстве в светлое время суток при буксировке механического транспортного средства?","a":["Только ближний свет фар.","Только дневные ходовые огни.","Только противотуманные фары.","Любые из перечисленных внешних световых приборов.","В светлое время суток разрешено движение без включения внешних световых приборов."],"c":3,"e":"<p>Согласно Правилам дорожного движения, при буксировке на буксирующем транспортном средстве в светлое время суток должны быть включены ближний свет фар, либо противотуманные фары, либо дневные ходовые огни.</p> <p>Движение сцепленных между собой механических транспортных средств создаёт определённые сложности для других участников дорожного движения в силу их увеличенных размеров по длине, низкой скорости движения и низкой манёвренной способности. Поэтому Правила дорожного движения требуют дополнительно обозначить буксирующее и буксируемое ТС.</p>","image":null},{"id":102201602,"themeId":5,"group":1022016,"chapter":22,"chapters":[22],"q":"Разрешается ли использовать противотуманные фары для обозначения транспортного средства, осуществляющего буксировку другого механического транспортного средства в светлое время суток?","a":["Разрешается вместо ближнего света фар.","Разрешается совместно с ближним светом фар.","Разрешается как совместно, так и вместо ближнего света фар.","Запрещается."],"c":0,"e":"<p>Согласно Правилам дорожного движения, в светлое время суток для обозначения движущегося транспортного средства вместо ближнего света фар могут быть включены противотуманные фары при буксировке (на буксирующем транспортном средстве).</p> <p>Движение сцепленных между собой механических транспортных средств создаёт определённые сложности для других участников дорожного движения в силу их увеличенных размеров по длине, низкой скорости движения и низкой манёвренной способности. Поэтому Правила дорожного движения требуют дополнительно обозначить буксирующее и буксируемое ТС.</p>","image":null},{"id":102201701,"themeId":5,"group":1022017,"chapter":22,"chapters":[22],"q":"На каком транспортном средстве не требуется при движении в светлое время суток включать ближний свет фар или дневные ходовые огни?","a":["На мопеде.","На мотоцикле.","На механическом транспортном средстве, управляемом водителем с водительским стажем менее двух лет.","На учебном транспортном средстве при обучении управлению механическим транспортным средством на дорогах.","Требуется включать на всех перечисленных транспортных средствах."],"c":2,"e":"<p>Согласно Правилам дорожного движения, в светлое время суток для обозначения движущегося транспортного средства должны быть включены ближний свет фар или дневные ходовые огни (при их наличии):</p> <ul><li>на мотоцикле и мопеде;</li> <li>при движении в транспортной колонне;</li> <li>на маршрутном транспортном средстве, движущемся по специально выделенной полосе навстречу движению;</li> <li>при организованной перевозке группы детей;</li> <li>при перевозке опасных грузов, движении тяжеловесных и (или) крупногабаритных транспортных средств;</li> <li>при буксировке (на буксирующем транспортном средстве);</li> <li>во время обучения управлению механическим транспортным средством на дорогах;</li> <li>на механических транспортных средствах при организации временного их движения по встречной полосе движения;</li> <li>ежегодно в периоды с 25 мая по 5 июня и с 25 августа по 5 сентября.</li></ul> <p>Следовательно, включение ближнего света фар или дневных ходовых огней в светлое время суток на механическом транспортном средстве, управляемом водителем с водительским стажем менее двух лет, необязательно.</p>","image":null},{"id":102201721,"themeId":5,"group":1022017,"chapter":22,"chapters":[22],"q":"Какие внешние световые приборы следует включать на мотоцикле в светлое время суток?","a":["Габаритные огни.","Фару ближнего света или противотуманную фару."],"c":1,"e":"<p>В светлое время суток для обозначения движущегося мотоцикла на нём должны быть включены ближний свет фар или дневные ходовые огни (при их наличии). Это обусловлено тем, что мотоцикл менее заметен на дороге из-за его небольших размеров, а также вследствие его высокой манёвренности и динамичности.</p>","image":null},{"id":102201722,"themeId":5,"group":1022017,"chapter":22,"chapters":[22],"q":"В каком случае из перечисленных не могут использоваться противотуманные фары в светлое время суток?","a":["При движении в транспортной колонне.","На маршрутном транспортном средстве, движущемся по специально выделенной полосе навстречу движению.","При организованной перевозке группы детей.","При буксировке (на буксируемом транспортном средстве).","Во время обучения управлению механическим транспортным средством на дорогах."],"c":3,"e":"<p>Противотуманные фары на транспортном средстве могут использоваться водителем вместо ближнего света фар во всех перечисленных случаях, за исключением буксируемого транспортного средства. На нём не требуется включения ближнего света фар, так как на буксируемом транспортном средстве должна быть включена аварийная световая сигнализация.</p>","image":null},{"id":102201732,"themeId":5,"group":1022017,"chapter":22,"chapters":[22],"q":"В каком случае в светлое время суток на учебном транспортном средстве при обучении управлению механическим транспортным средством, сдачи квалификационного практического экзамена на право управления механическим транспортным средством необходимо включать ближний свет фар или дневные ходовые огни?","a":["При движении по дорогам.","При движении по автодрому.","В обоих перечисленных случаях."],"c":0,"e":"<p>В светлое время суток для обозначения движущегося транспортного средства должны быть включены ближний свет фар или дневные ходовые огни (при их наличии) во время обучения управлению механическим транспортным средством, сдачи квалификационного практического экзамена на право управления механическим транспортным средством на дорогах.</p> <p>Включённый ближний свет на учебном транспортном средстве не только привлекает внимание водителей, но и информирует о том, что за рулём находится малоопытный водитель, который может совершить ошибки даже в простых дорожно-транспортных ситуациях.</p>","image":null},{"id":102201801,"themeId":5,"group":1022018,"chapter":22,"chapters":[22],"q":"На каком транспортном средстве не требуется при движении в светлое время суток включать ближний свет фар или дневные ходовые огни?","a":["На тихоходном транспортном средстве.","На тяжеловесном транспортном средстве.","На крупногабаритном транспортном средстве.","На транспортном средстве при перевозке опасных грузов.","Требуется включать на всех перечисленных транспортных средствах."],"c":0,"e":"<p>Согласно Правилам дорожного движения, в светлое время суток для обозначения движущегося транспортного средства должны быть включены ближний свет фар или дневные ходовые огни (при их наличии):</p> <ul><li>на мотоцикле и мопеде;</li> <li>при движении в транспортной колонне;</li> <li>на маршрутном транспортном средстве, движущемся по специально выделенной полосе навстречу движению;</li> <li>при организованной перевозке группы детей;</li> <li>при перевозке опасных грузов, движении тяжеловесных и (или) крупногабаритных транспортных средств;</li> <li>при буксировке (на буксирующем транспортном средстве);</li> <li>во время обучения управлению механическим транспортным средством на дорогах;</li> <li>на механических транспортных средствах при организации временного их движения по встречной полосе движения;</li> <li>ежегодно в периоды с 25 мая по 5 июня и с 25 августа по 5 сентября.</li></ul> <p>Следовательно, включение ближнего света фар или дневных ходовых огней в светлое время суток на тихоходном транспортном средстве необязательно.</p>","image":null},{"id":102201821,"themeId":5,"group":1022018,"chapter":22,"chapters":[22],"q":"Какие внешние световые приборы из перечисленных должны быть включены на механических транспортных средствах в светлое время суток при организации временного их движения по встречной полосе?","a":["Фары дальнего или ближнего света.","Фары ближнего света, или дневные ходовые огни (при их наличии), или противотуманные фары.","Габаритные огни.","Фары дальнего света."],"c":1,"e":"<p>В светлое время суток для обозначения движущихся механических транспортных средств при организации временного их движения по встречной полосе на них должны быть включены ближний свет фар или дневные ходовые огни (при их наличии).</p> <p>При этом вместо ближнего света фар на транспортном средстве могут использоваться противотуманные фары.</p>","image":null},{"id":102201822,"themeId":5,"group":1022018,"chapter":22,"chapters":[22],"q":"В каком случае из перечисленных в светлое время суток на механических транспортных средствах не требуется включение ближнего света фар или дневных ходовых огней?","a":["При движении в транспортной колонне.","При организации временного движения по встречной полосе движения.","При буксировке механических транспортных средств (на буксируемом транспортном средстве).","Во время обучения управлению механическим транспортным средством на дороге."],"c":2,"e":"<p>Ближний свет фар или дневные ходовые огни (при их наличии) должны быть включены во всех перечисленных случаях, за исключением буксируемого транспортного средства. На нём не требуется включения ближнего света фар, так как на буксируемом транспортном средстве должна быть включена аварийная световая сигнализация.</p>","image":null},{"id":102201901,"themeId":5,"group":1022019,"chapter":22,"chapters":[22],"q":"На каком транспортном средстве не требуется при движении в светлое время суток включать ближний свет фар или дневные ходовые огни?","a":["На мопеде.","При буксировке (на буксирующем транспортном средстве).","На маршрутном транспортном средстве, движущемся по специально выделенной полосе навстречу движению.","На неисправном транспортном средстве, следующем к месту стоянки или ремонта, в случаях, когда это не запрещено Правилами дорожного движения.","Требуется включать на всех перечисленных транспортных средствах."],"c":3,"e":"<p>Согласно Правилам дорожного движения, в светлое время суток для обозначения движущегося транспортного средства должны быть включены ближний свет фар или дневные ходовые огни (при их наличии):</p> <ul><li>на мотоцикле и мопеде;</li> <li>при движении в транспортной колонне;</li> <li>на маршрутном транспортном средстве, движущемся по специально выделенной полосе навстречу движению;</li> <li>при организованной перевозке группы детей;</li> <li>при перевозке опасных грузов, движении тяжеловесных и (или) крупногабаритных транспортных средств;</li> <li>при буксировке (на буксирующем транспортном средстве);</li> <li>во время обучения управлению механическим транспортным средством на дорогах;</li> <li>на механических транспортных средствах при организации временного их движения по встречной полосе движения;</li> <li>ежегодно в периоды с 25 мая по 5 июня и с 25 августа по 5 сентября.</li></ul> <p>Следовательно, включение ближнего света фар или дневных ходовых огней в светлое время суток на неисправном транспортом средстве, следующем к месту стоянки или ремонта, необязательно. При следовании к месту стоянки или ремонта следует включить аварийную световую сигнализацию.</p>","image":null},{"id":102201902,"themeId":5,"group":1022019,"chapter":22,"chapters":[22],"q":"На каком транспортном средстве требуется при движении в светлое время суток включать ближний свет фар или дневные ходовые огни?","a":["На тихоходном транспортном средстве, буксирующем прицеп.","На маршрутном транспортном средстве, движущемся по специально выделенной полосе навстречу движению.","На маршрутном транспортном средстве, движущемся по специально выделенной полосе в попутном направлении движения.","На механических транспортных средствах при организации временного их движения в объезд ремонтируемого участка дороги.","Требуется включать на всех перечисленных транспортных средствах."],"c":1,"e":"<p>Согласно Правилам дорожного движения, в светлое время суток для обозначения движущегося транспортного средства должны быть включены ближний свет фар или дневные ходовые огни (при их наличии):</p> <ul><li>на мотоцикле и мопеде;</li> <li>при движении в транспортной колонне;</li> <li>на маршрутном транспортном средстве, движущемся по специально выделенной полосе навстречу движению;</li> <li>при организованной перевозке группы детей;</li> <li>при перевозке опасных грузов, движении тяжеловесных и (или) крупногабаритных транспортных средств;</li> <li>при буксировке (на буксирующем транспортном средстве);</li> <li>во время обучения управлению механическим транспортным средством на дорогах;</li> <li>на механических транспортных средствах при организации временного их движения по встречной полосе движения;</li> <li>ежегодно в периоды с 25 мая по 5 июня и с 25 августа по 5 сентября.</li></ul><br> <p>Маршрутные транспортные средства, например автобусы или троллейбусы, движущиеся по специально выделенной полосе движения навстречу основному потоку ТС, представляют определённую опасность для движения водителей других транспортных средств. Движение с включённым светом фар привлекает их внимание. Оно необходимо для того, чтобы участники дорожного движения могли своевременно заметить движущееся навстречу маршрутное ТС.</p> <p>Для водителей движущееся им навстречу маршрутное транспортное средство без света фар может быть неожиданным, особенно в случае, если горизонтальная дорожная разметка слабо различима по погодным условиям (плохо видна на грязной или заснеженной проезжей части).</p>","image":null},{"id":102201921,"themeId":5,"group":1022019,"chapter":22,"chapters":[22],"q":"В каком случае из перечисленных не обязательно включение ближнего света фар на механическом транспортном средстве в светлое время суток при отсутствии на нём дневных ходовых огней?","a":["При движении в транспортной колонне.","При организации временного движения по встречной полосе.","При движении со скоростью менее 40 км/ч на дороге с интенсивным движением.","Во время обучения управлению механическим транспортным средством на дорогах.","При буксировке автомобиля на гибкой сцепке (на буксирующем автомобиле)."],"c":2,"e":"<p>Ближний свет фар или дневные ходовые огни (при их наличии) должны быть включены во всех перечисленных случаях, за исключением движения со скоростью менее 40 км/ч на дорогах с интенсивным движением.</p> <p>В данном случае не требуется включение внешних световых приборов на транспортном средстве в светлое время суток.</p>","image":null},{"id":102201941,"themeId":5,"group":1022019,"chapter":22,"chapters":[22],"q":"Когда в светлое время суток для обозначения движущегося транспортного средства должны быть включены ближний свет фар или дневные ходовые огни (при их наличии)?","a":["Ежегодно в период с 5 июня по 5 сентября.","Ежегодно в период с 25 августа по 25 мая.","Ежегодно в период с 25 мая по 5 сентября.","Ежегодно в периоды с 25 мая по 5 июня и с 25 августа по 5 сентября."],"c":3,"e":"<p>В светлое время суток для обозначения движущегося транспортного средства должны быть включены ближний свет фар или дневные ходовые огни (при их наличии) ежегодно в периоды с 25 мая по 5 июня и с 25 августа по 5 сентября.</p>","image":null},{"id":102202101,"themeId":5,"group":1022021,"chapter":22,"chapters":[22],"q":"В каком из перечисленных случаев водитель неправильно воспользовался внешними световыми приборами?","a":["Включил противотуманные фары совместно с дальним светом фар в тёмное время суток.","Включил противотуманные фары совместно с ближним светом фар в светлое время суток во время снегопада.","Включил противотуманные фары вместо дальнего света фар в тёмное время суток в условиях сильного тумана.","Во всех перечисленных случаях водитель не нарушил Правила дорожного движения."],"c":2,"e":"<p>Согласно Правилам дорожного движения, противотуманные фары на транспортном средстве могут использоваться водителем в тёмное время суток и (или) при недостаточной видимости дороги совместно с ближним или дальним светом фар. Следовательно, в тёмное время суток использование противотуманных фар вместо дальнего света фар запрещено.</p> <p>Включение противотуманных фар совместно с ближним или дальним светом фар позволяет улучшить освещение проезжей части в непосредственной близости перед транспортным средством. Использования только противотуманных фар для полноценного освещения дороги недостаточно.</p>","image":null},{"id":102202102,"themeId":5,"group":1022021,"chapter":22,"chapters":[22],"q":"Разрешено ли Вам двигаться только с включёнными противотуманными фарами по дороге с искусственным освещением в населённом пункте после захода солнца?","a":["Нет, не разрешено.","Разрешено, если дорога хорошо освещена.","Не разрешено только если дорога недостаточно освещена."],"c":0,"e":"<p>Согласно Правилам дорожного движения, противотуманные фары на транспортном средстве могут использоваться водителем в тёмное время суток и (или) при недостаточной видимости дороги совместно с ближним или дальним светом фар. Следовательно, в тёмное время суток использование противотуманных фар вместо дальнего или ближнего света фар запрещено.</p> <p>Включение противотуманных фар совместно с ближним или дальним светом фар позволяет улучшить освещение проезжей части в непосредственной близости перед транспортным средством.</p>","image":"assets/adrive-questions/q102202102.jpg"},{"id":102202201,"themeId":5,"group":1022022,"chapter":22,"chapters":[22],"q":"В каких условиях на автомобиле могут применяться задние противотуманные фонари?","a":["В тёмное время суток.","При недостаточной видимости дороги.","При ухудшении видимости транспортного средства в светлое время суток.","Во всех перечисленных случаях."],"c":1,"e":"<p>Согласно Правилам дорожного движения, задние противотуманные фонари на транспортных средствах могут применяться только при недостаточной видимости дороги.</p> <p>Задние противотуманные фонари — это дополнительные световые приборы, устанавливаемые сзади автомобиля и имеющие большую яркость, чем задние габаритные огни. Задние противотуманные фонари должны включаться только при пониженной прозрачности атмосферы в условиях недостаточной видимости дороги (туман, снегопад, пыль).</p> <p>Применение задних противотуманных фонарей связано с необходимостью раннего обнаружения сигнала водителями транспортных средств, движущихся попутно в условиях интенсивного движения, при ухудшении видимости дороги в направлении движения по причине снижения прозрачности атмосферы.</p>","image":null},{"id":102202221,"themeId":5,"group":1022022,"chapter":22,"chapters":[22],"q":"В каких перечисленных случаях одновременно с ближним светом фар могут быть включены противотуманные фары и задние противотуманные фонари (противотуманный фонарь)?","a":["В условиях ограниченной обзорности.","В условиях недостаточной видимости.","В тёмное время суток.","Во всех перечисленных случаях."],"c":1,"e":"<p>Правилами дорожного движения не установлено запрета на использование противотуманных фар совместно с ближним светом фар, но противотуманные фонари (устанавливаются на транспортные средства сзади) могут быть включены только в условиях недостаточной видимости дороги.</p>","image":null},{"id":102202302,"themeId":5,"group":1022023,"chapter":22,"chapters":[22],"q":"В каком из перечисленных случаев водитель правильно воспользовался внешними световыми приборами?","a":["Включил дальний свет фар совместно с противотуманными фарами при движении по дороге без искусственного освещения в населённом пункте в тёмное время суток.","Включил задние противотуманные фонари на дороге во время движения в условиях недостаточной видимости одновременно с ближним светом фар.","Включил фару-искатель при движении по грунтовой дороге вне населённого пункта в тёмное время суток при отсутствии встречных транспортных средств.","Во всех перечисленных случаях водитель правильно воспользовался внешними световыми приборами."],"c":3,"e":"<p>В ответах:</p> <ul><li>Включил дальний свет фар совместно с противотуманными фарами при движении по дороге без искусственного освещения в населённом пункте.<br> На дороге без искусственного освещения в населённом пункте в тёмное время суток и (или) при недостаточной видимости дороги на механическом транспортном средстве должны быть включены фары дальнего или ближнего света. Также разрешается применение дальнего или ближнего света фар совместно с противотуманными фарами.<br> Включение противотуманных фар совместно с ближним или дальним светом фар позволяет улучшить освещение проезжей части в непосредственной близости перед ТС.</li> <li>Включил задние противотуманные фонари на дороге во время движения в условиях недостаточной видимости одновременно с ближним светом фар.<br> Задние противотуманные фонари на транспортных средствах могут применяться только при недостаточной видимости дороги.<br> Задние противотуманные фонари — это дополнительные световые приборы, устанавливаемые сзади автомобиля и имеющие большую яркость, чем задние габаритные огни.<br> Задние противотуманные фонари должны включаться только при пониженной прозрачности атмосферы в условиях недостаточной видимости дороги (туман, снегопад, пыль). Применение задних противотуманных фонарей связано с необходимостью раннего обнаружения сигнала водителями транспортных средств, движущихся попутно в условиях интенсивного движения, при ухудшении видимости дороги в направлении движения по причине снижения прозрачности атмосферы.</li> <li>Включил фару-искатель при движении по грунтовой дороге вне населённого пункта в тёмное время суток при отсутствии встречных транспортных средств.<br> Фарой-искателем разрешается пользоваться только вне населённых пунктов при отсутствии встречных транспортных средств.<br> Фара-искатель является дополнительным прибором внешнего освещения. Она обладает относительно узким лучом света, действующим на расстояние 150–200 метров.<br> При использовании не по назначению она может привести к ослеплению водителей других ТС.</li></ul>","image":null},{"id":102202401,"themeId":5,"group":1022024,"chapter":22,"chapters":[22],"q":"В каком из перечисленных случаев водитель неправильно воспользовался внешними световыми приборами?","a":["Включил задние противотуманные фонари в условиях недостаточной видимости.","Включил противотуманные фары совместно с дальним светом фар в тёмное время суток.","Переключил дальний свет фар на ближний, не осветив дальним светом движущееся в попутном направлении транспортное средство.","Во всех перечисленных случаях водитель правильно воспользовался внешними световыми приборами."],"c":3,"e":"<p>В ответах:</p> <ul><li>Включил задние противотуманные фонари в условиях недостаточной видимости.<br> Задние противотуманные фонари на транспортных средствах могут применяться только при недостаточной видимости дороги.<br> Задние противотуманные фонари — это дополнительные световые приборы, устанавливаемые сзади автомобиля и имеющие большую яркость, чем задние габаритные огни.<br> Задние противотуманные фонари должны включаться только при пониженной прозрачности атмосферы в условиях недостаточной видимости дороги (туман, снегопад, пыль). Применение задних противотуманных фонарей связано с необходимостью раннего обнаружения сигнала водителями транспортных средств, движущихся попутно в условиях интенсивного движения, при ухудшении видимости дороги в направлении движения по причине снижения прозрачности атмосферы.</li> <li>Включил противотуманные фары совместно с дальним светом фар в тёмное время суток.<br> Разрешается применение дальнего или ближнего света фар совместно с противотуманными фарами. Включение противотуманных фар совместно с ближним или дальним светом фар позволяет улучшить освещение проезжей части в непосредственной близости перед ТС.</li> <li>Переключил дальний свет фар на ближний, не осветив дальним светом движущееся в попутном направлении транспортное средство.<br> Требование направлено на снижение вероятности ослепления водителей ТС, движущихся в попутном направлении, через зеркала заднего вида.</li></ul>","image":null},{"id":102202501,"themeId":5,"group":1022025,"chapter":22,"chapters":[22],"q":"В каком из перечисленных случаев водитель правильно воспользовался звуковым сигналом?","a":["Применил звуковой сигнал для предупреждения о намерении произвести обгон в населённом пункте.","Применил звуковой сигнал для предупреждения о намерении произвести обгон вне населённого пункта.","Применил звуковой сигнал для привлечения внимания участников дорожного движения в ситуации, не связанной с предотвращением дорожно-транспортного происшествия.","Во всех перечисленных случаях водитель правильно воспользовался звуковым сигналом."],"c":1,"e":"<p>Согласно Правилам дорожного движения, звуковой сигнал может применяться для предупреждения других водителей о намерении произвести обгон вне населённых пунктов.</p> <p>При обгоне звуковой сигнал необходимо подавать до начала выполнения обгона, чтобы водитель обгоняемого транспортного средства был заблаговременно предупреждён о том, что его обгоняют.</p>","image":null},{"id":102202502,"themeId":5,"group":1022025,"chapter":22,"chapters":[22],"q":"В каком из перечисленных случаев водитель правильно воспользовался звуковым сигналом?","a":["Применил звуковой сигнал для предупреждения о намерении произвести обгон вне населённого пункта.","Применил звуковой сигнал для предотвращения дорожно-транспортного происшествия в населённом пункте.","Применил звуковой сигнал для предотвращения дорожно-транспортного происшествия вне населённого пункта.","Во всех перечисленных случаях водитель правильно воспользовался звуковым сигналом."],"c":3,"e":"<p>Согласно Правилам дорожного движения, звуковые сигналы могут применяться только для:</p> <ul><li>предупреждения других водителей о намерении произвести обгон вне населённых пунктов;</li> <li>предотвращения дорожно-транспортного происшествия.</li></ul> <p>При обгоне звуковой сигнал необходимо подавать до начала выполнения обгона, чтобы водитель обгоняемого транспортного средства был заблаговременно предупреждён о том, что его обгоняют.</p> <p>Звуковой сигнал также может быть применён, если его подача позволит привлечь внимание конкретного участника дорожного движения к складывающейся дорожно-транспортной ситуации с целью его отказа от выполнения определённых действий, которые могут привести к ДТП (например, отказа от выполнения манёвра, выхода на проезжую часть дороги и тому подобное).</p> <p>Подача звукового сигнала не даёт преимущества водителю ТС, который его подал.</p>","image":null},{"id":102202521,"themeId":5,"group":1022025,"chapter":22,"chapters":[22],"q":"Разрешается ли Вам использовать звуковой сигнал в зоне действия показанного дорожного знака?","a":["Разрешается только для предупреждения об обгоне.","Разрешается только для предотвращения ДТП.","Разрешается во всех перечисленных случаях."],"c":1,"e":"<p>Звуковые сигналы могут применяться только для предотвращения дорожно-транспортного происшествия, а также для предупреждения других водителей о намерении произвести обгон, но только вне населённых пунктов.</p> <p>В данном случае — въезд в населённый пункт.</p>","image":"assets/adrive-questions/q102202521.jpg"},{"id":102202522,"themeId":5,"group":1022025,"chapter":22,"chapters":[22],"q":"В каком случае разрешено применять звуковые сигналы в населённых пунктах?","a":["Только для предупреждения о намерении произвести обгон.","Только для предотвращения дорожно-транспортного происшествия.","В обоих перечисленных случаях."],"c":1,"e":"<p>Звуковые сигналы в населённых пунктах могут применяться только для предотвращения дорожно-транспортного происшествия. Это обусловлено профилактикой шумового загрязнения территорий населённых пунктов.</p>","image":null},{"id":102202601,"themeId":5,"group":1022026,"chapter":22,"chapters":[22],"q":"Для чего разрешается использовать звуковой сигнал после проезда показанного на рисунке дорожного знака?","a":["Только для предотвращения дорожно-транспортного происшествия.","Только для предупреждения других водителей о намерении произвести обгон.","Разрешается использовать звуковой сигнал в обоих перечисленных случаях."],"c":2,"e":"<p>В показанной ситуации дорожный знак 5.23.1 «Конец населённого пункта» информирует водителя о том, что он будет двигаться по дороге вне населённого пункта.</p> <p>Согласно Правилам дорожного движения, звуковые сигналы могут применяться только для:</p> <ul><li>предупреждения других водителей о намерении произвести обгон вне населённых пунктов;</li> <li>предотвращения дорожно-транспортного происшествия.</li></ul> <p>При обгоне звуковой сигнал необходимо подавать до начала выполнения обгона, чтобы водитель обгоняемого ТС был заблаговременно предупреждён о том, что его обгоняют.</p> <p>Звуковой сигнал также может быть применён, если его подача позволит привлечь внимание конкретного участника дорожного движения к складывающейся дорожно-транспортной ситуации с целью его отказа от выполнения определённых действий, которые могут привести к ДТП (например, отказа от выполнения манёвра, выхода на проезжую часть дороги пешеходов и тому подобное).</p> <p>Подача звукового сигнала не даёт преимущества водителю ТС, который его подал.</p>","image":"assets/adrive-questions/q102202601.jpg"},{"id":102202602,"themeId":5,"group":1022026,"chapter":22,"chapters":[22],"q":"Разрешается ли водителю легкового автомобиля подать звуковой сигнал для предупреждения водителя грузового автомобиля о намерении произвести обгон вне населённого пункта?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Согласно Правилам дорожного движения, звуковой сигнал может применяться для предупреждения других водителей о намерении произвести обгон вне населённых пунктов.</p> <p>При обгоне звуковой сигнал необходимо подавать до начала выполнения обгона, чтобы водитель обгоняемого транспортного средства был заблаговременно предупреждён о том, что его обгоняют.</p>","image":"assets/adrive-questions/q102202602.jpg"},{"id":102202621,"themeId":5,"group":1022026,"chapter":22,"chapters":[22],"q":"Какие сигналы из перечисленных могут применяться Вами для предупреждения других водителей о намерении произвести обгон вне населённого пункта?","a":["Звуковой сигнал.","Периодическое кратковременное включение и выключение света фар в светлое время суток.","Периодическое переключение фар с ближнего на дальний свет в тёмное время суток.","Могут применяться все перечисленные сигналы."],"c":3,"e":"<p>Во избежание неожиданного маневрирования и непреднамеренного создания препятствия обгоняемым автомобилем, водителя такого транспортного средства можно предупредить, что по отношению к его транспортному средству будет совершён обгон.</p> <p>Для предупреждения других водителей о намерении произвести обгон вне населённых пунктов могут применяться звуковые сигналы.</p> <p>Также для предупреждения об обгоне вместо звукового сигнала (или совместно с ним) может подаваться световой сигнал, который представляет собой в светлое время суток периодическое кратковременное включение и выключение света фар, а в тёмное время суток — периодическое переключение фар с ближнего света на дальний.</p>","image":null},{"id":102202622,"themeId":5,"group":1022026,"chapter":22,"chapters":[22],"q":"Для предупреждения об обгоне при движении в населённом пункте в светлое время суток разрешено воспользоваться:","a":["Звуковым сигналом.","Периодическим кратковременным включением и выключением света фар.","Периодическим кратковременным включением и выключением света фар совместно со звуковым сигналом.","Любым способом из перечисленных."],"c":1,"e":"<p>Для предупреждения об обгоне в населённом пункте может подаваться световой сигнал, который представляет собой в светлое время суток периодическое кратковременное включение и выключение света фар, а в тёмное время суток — периодическое переключение фар с ближнего света на дальний.</p> <p>Подача звукового сигнала для предупреждения об обгоне в населённом пункте запрещена.</p>","image":null},{"id":102202623,"themeId":5,"group":1022026,"chapter":22,"chapters":[22],"q":"В зоне действия каких знаков Правила дорожного движения разрешают подачу звуковых сигналов только для предотвращения дорожно-транспортного происшествия?","a":["Только в зоне действия знака 1.","Только в зоне действия знака 2.","Только в зоне действия знаков 1 и 2.","Только в зоне действия знаков 1 и 3.","В зоне действия всех показанных знаков."],"c":2,"e":"<p>Звуковой сигнал может применяться только для предотвращения ДТП в населённых пунктах. Начало населённого пункта, в котором действуют специальные требования Правил, устанавливающие порядок дорожного движения в населённых пунктах, обозначается дорожным знаком 1 — «Начало населённого пункта».</p> <p>Дорожный знак 2 — «Подача звукового сигнала запрещена». В зоне действия данного знака также запрещается пользоваться звуковым сигналом, кроме случая подачи его для предотвращения дорожно-транспортного происшествия.</p>","image":"assets/adrive-questions/q102202623.jpg"},{"id":102300021,"themeId":5,"group":1023000,"chapter":23,"chapters":[23],"q":"Разрешена ли перевозка пассажиров в легковом автомобиле, если при этом его фактическая масса превысит технически допустимую общую массу данного автомобиля?","a":["Да, если количество пассажиров не превысит количество мест для сидения.","Да, при условии перевозки пассажиров на незначительные расстояния.","Нет, не разрешена."],"c":2,"e":"<p>При перевозке пассажиров фактическая масса транспортного средства не должна превышать технически допустимую общую массу транспортного средства, установленную изготовителем. При превышении технически допустимой общей массы может произойти нарушение устойчивости и управляемости транспортного средства, возможен выход из строя рабочей тормозной системы, элементов подвески и прочее.</p>","image":null},{"id":102300101,"themeId":5,"group":1023001,"chapter":23,"chapters":[23],"q":"Разрешается ли водителю с водительским стажем до двух лет перевозить пассажиров в кузове грузового автомобиля, не оборудованном для перевозки пассажиров?","a":["Разрешается только лиц, следующих за получением груза или сопровождающих его, при условии, что они обеспечены местами для сидения, расположенными ниже уровня бортов.","Разрешается только лиц, следующих за получением груза или сопровождающих его, при условии, что они обеспечены местами для сидения, расположенными не выше уровня бортов.","Нет, не разрешается."],"c":2,"e":"<p>Требования, касающееся допуска водителя с определённым стажем управления транспортным средством данной категории, означает, что водитель, которому может быть доверена перевозка пассажиров в кузове грузового автомобиля, должен иметь водительский стаж управления ТС данной категории не менее трёх лет, что связано с особой ответственностью при перевозке пассажиров в кузове грузового автомобиля.</p>","image":null},{"id":102300102,"themeId":5,"group":1023001,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозить пассажиров в кузове грузового автомобиля, не оборудованном для перевозки пассажиров?","a":["Разрешается только лиц, следующих после сопровождения и разгрузки груза, при условии, что они обеспечены местами для сидения, расположенными ниже уровня бортов.","Разрешается только лиц, следующих за получением груза или сопровождающих его, при условии, что они обеспечены местами для сидения, расположенными ниже уровня бортов.","Разрешается в обоих перечисленных случаях."],"c":1,"e":"<p>Согласно Правилам дорожного движения, перевозить пассажиров в кузове грузового автомобиля, не оборудованном для перевозки пассажиров, разрешается только тех лиц, которые следуют за получением груза или сопровождающих его, при условии, что они обеспечены местами для сидения, расположенными ниже уровня бортов.</p>","image":null},{"id":102300121,"themeId":5,"group":1023001,"chapter":23,"chapters":[23],"q":"Разрешена ли перевозка пассажира в грузовом автомобиле с технически допустимой общей массой не более 3.5 тонны, если у водителя имеется водительское удостоверение только на право управления механическим транспортным средством категории «B» и водительский стаж управления механическим транспортным средством этой категории более трёх лет?","a":["Да, только в кабине.","Нет, необходимо также водительское удостоверение на право управления механическим транспортным средством категории «C»."],"c":0,"e":"<p>Перевозка пассажиров в кузове грузового автомобиля должна осуществляться водителями, имеющими стаж управления механическим транспортным средством данной категории более трёх лет и водительское удостоверение на право управления механическим транспортным средством категории «C».</p> <p>При перевозке более 8 человек, включая пассажиров в кабине, необходимо водительское удостоверение на право управления механическим транспортным средством категорий «C» и «D». Поэтому при наличии водительского удостоверения лишь категории «B» перевозить пассажиров разрешено только в кабине.</p>","image":null},{"id":102300122,"themeId":5,"group":1023001,"chapter":23,"chapters":[23],"q":"Разрешена ли перевозка пассажира в кузове грузового автомобиля с технически допустимой общей массой не более 3.5 тонны, если у водителя имеется водительское удостоверение только на право управления механическим транспортным средством категории «B» и водительский стаж управления механическим транспортным средством этой категории более трёх лет?","a":["Да, разрешено, но не более 8 человек, включая пассажиров в кабине.","Нет, необходимо также водительское удостоверение на право управления механическим транспортным средством категории «C»."],"c":1,"e":"<p>Перевозка пассажиров в кузове грузового автомобиля должна осуществляться водителями, имеющими стаж управления механическим транспортным средством данной категории более трёх лет и водительское удостоверение на право управления механическим транспортным средством категории «C».</p> <p>При перевозке более 8 человек, включая пассажиров в кабине, необходимо водительское удостоверение на право управления механическим транспортным средством категорий «C» и «D».</p>","image":null},{"id":102300123,"themeId":5,"group":1023001,"chapter":23,"chapters":[23],"q":"Разрешена ли перевозка пассажиров в кузове грузового автомобиля с технически допустимой общей массой не более 3.5 тонны, если водитель имеет право на управление механическими транспортными средствами категорий «B» и «C», при условии, что водительский стаж управления механическим транспортным средством категории «B» составляет более трёх лет, а механическими транспортными средствами категории «C» — не более одного года?","a":["Да, разрешена.","Разрешена, но не более восьми человек, включая пассажиров в кабине.","Нет, не разрешена."],"c":1,"e":"<p>При наличии водительского удостоверения категории «B» и стажа управления транспортным средством этой категории более трёх лет разрешено перевозить пассажиров в кузове грузового автомобиля, но не более восьми человек, включая пассажиров в кабине. При этом обязательно также наличие права управления механическим транспортным средством категории «C», однако продолжительность стажа управления этой категорией не оговаривается.</p> <p>При перевозке пассажиров в грузовом автомобиле с технически допустимой общей массой не более 3.5 тонны более 8 человек, включая пассажиров в кабине, необходимо водительское удостоверение на право управления механическим транспортным средством категорий «B», «C» и «D».</p>","image":null},{"id":102300124,"themeId":5,"group":1023001,"chapter":23,"chapters":[23],"q":"Разрешена ли перевозка пассажиров в кузове грузового автомобиля с технически допустимой общей массой не более 3.5 тонны, если водитель имеет право на управление механическими транспортными средствами категорий «B» и «C», при условии, что водительский стаж управления механическим транспортным средством категории «B» составляет не более одного года, а механическим транспортным средством категории «C» — более трёх лет?","a":["Да, разрешена.","Разрешена, но не более восьми человек, включая пассажиров в кабине.","Нет, не разрешена."],"c":2,"e":"<p>При наличии водительского удостоверения категории «B» и стажа управления транспортным средством этой категории не более трёх лет запрещено перевозить пассажиров в кузове грузового автомобиля данной категории независимо от наличия права управления транспортными средствами других категорий.</p>","image":null},{"id":102300202,"themeId":5,"group":1023002,"chapter":23,"chapters":[23],"q":"Каким образом разрешается перевозка ребёнка в возрасте от 5 до 12 лет на заднем сиденье легкового автомобиля?","a":["Разрешается при условии, что он пристёгнут ремнём безопасности, если его рост превышает 150 сантиметров.","Разрешается с использованием специального детского удерживающего устройства, соответствующего весу и росту ребёнка.","Разрешается с использованием бустеров, специальных подушек для сидения, дополнительных сидений, позволяющих безопасно пристегнуть ребёнка с помощью ремней безопасности.","Разрешается во всех перечисленных случаях."],"c":3,"e":"<p>Перевозка ребёнка в возрасте от 5 до 12 лет на заднем сиденье легкового автомобиля разрешается:</p> <ul><li>при условии, что он пристёгнут ремнём безопасности, если его рост превышает 150 сантиметров;</li> <li>с использованием специального детского удерживающего устройства, соответствующего весу и росту ребёнка;</li> <li>с использованием бустеров, специальных подушек для сидения, дополнительных сидений, позволяющих безопасно пристегнуть ребёнка с помощью ремней безопасности.</li></ul>","image":null},{"id":102300231,"themeId":5,"group":1023002,"chapter":23,"chapters":[23],"q":"Каким образом разрешается перевозка ребёнка в возрасте до 5 лет на заднем сиденье легкового автомобиля (за исключением автомобиля-такси), оборудованного ремнями безопасности?","a":["Разрешается при условии, что он пристёгнут ремнём безопасности.","Разрешается с использованием детского удерживающего устройства.","Разрешается на коленях у совершеннолетнего пассажира при условии, что названный пассажир пристёгнут ремнём безопасности.","Разрешается во всех перечисленных случаях."],"c":1,"e":"<p>Согласно Правилам дорожного движения, перевозка ребёнка в возрасте до 5 лет на заднем сиденье легкового автомобиля разрешается только с использованием специального детского удерживающего устройства, соответствующего весу и росту ребёнка.</p>","image":null},{"id":102300232,"themeId":5,"group":1023002,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозить ребёнка до 12 лет в салоне легкового автомобиля, оборудованного ремнями безопасности (за исключением автомобиля-такси), на коленях у совершеннолетнего пассажира?","a":["Разрешается на заднем сиденье при условии, что совершеннолетний пассажир пристёгнут ремнём безопасности.","Разрешается на переднем сиденье при условии, что совершеннолетний пассажир пристёгнут ремнём безопасности.","Разрешается в обоих перечисленных случаях.","Нет, не разрешается."],"c":3,"e":"<p>Запрещается перевозить детей на коленях у водителя и у пассажира на переднем сиденье легкового автомобиля. Что касается заднего сиденья — Правила дорожного движения не уточняют этот момент, однако мы помним, что водитель не имеет права перевозить пассажиров, не пристёгнутых ремнями безопасности.</p> <p>Пристёгивать двух пассажиров одним ремнём крайне небезопасно. К тому же общее количество пассажиров легкового автомобиля не должно превышать количества посадочных мест.</p>","image":null},{"id":102300301,"themeId":5,"group":1023003,"chapter":23,"chapters":[23],"q":"Обязан ли водитель легкового автомобиля перед поездкой проинструктировать пассажиров о порядке их посадки (размещения и высадки), а также о правилах поведения во время движения?","a":["Обязан.","Не обязан.","Обязан только в случае, если пассажиры ему не знакомы или он впервые осуществляет их перевозку."],"c":1,"e":"<p>Согласно Правилам дорожного движения, водитель легкового автомобиля не обязан перед поездкой проинструктировать пассажиров о порядке их посадки (размещения и высадки), а также о правилах поведения во время движения.</p>","image":null},{"id":102300302,"themeId":5,"group":1023003,"chapter":23,"chapters":[23],"q":"Что из перечисленного ниже не входит в обязанности водителя?","a":["Начинать движение только с закрытыми дверями.","Не открывать двери транспортного средства до полной остановки.","Не курить, если в салоне автомобиля находятся несовершеннолетние в возрасте до 12 лет.","Осуществлять посадку (высадку) пассажиров только после полной остановки транспортного средства."],"c":2,"e":"<p>В обязанности водителя входит:</p> <ul><li>начинать движение только с закрытыми дверями;</li> <li>не открывать двери транспортного средства до полной остановки;</li> <li>осуществлять посадку (высадку) пассажиров только после полной остановки транспортного средства.</li></ul> <p>При этом, несмотря на отсутствие запрещения, водитель должен понимать, что курение вредит не только его здоровью, но и здоровью окружающих.</p>","image":null},{"id":102300321,"themeId":5,"group":1023003,"chapter":23,"chapters":[23],"q":"Что из нижеперечисленного не требуется от водителя легкового автомобиля при перевозке пассажиров?","a":["Перед поездкой проинструктировать пассажиров о порядке их посадки (размещения и высадки), а также о правилах поведения во время движения.","Осуществлять посадку (высадку) пассажиров только после полной остановки транспортного средства, не открывать двери до полной остановки.","Начинать движение только с закрытыми дверями."],"c":0,"e":"<p>Водитель любого транспортного средства обязан осуществлять посадку (высадку) пассажиров только после полной остановки транспортного средства, а начинать движение — только с закрытыми дверями, и не открывать их до полной остановки.</p> <p>Перед поездкой проинструктировать пассажиров о порядке их посадки (размещения и высадки) в кузов, а также о правилах поведения во время движения обязан только водитель грузового автомобиля, ввиду отсутствия его личного контроля поведения пассажиров во время движения.</p>","image":null},{"id":102300401,"themeId":5,"group":1023004,"chapter":23,"chapters":[23],"q":"Может ли быть разрешена перевозка пассажиров в кузове грузового мотоцикла?","a":["Да, если количество пассажиров не превышает количество посадочных мест.","Да, если кузов оборудован местами для сидения, расположенными ниже уровня бортов.","Да, если стаж управления транспортными средствами данной категории у водителя превышает три года.","Перевозка пассажиров может быть разрешена при выполнении всего перечисленного.","Перевозка пассажиров в кузове грузового мотоцикла запрещена."],"c":4,"e":"<p>Согласно Правилам дорожного движения, перевозка пассажиров в кузове грузового мотоцикла запрещена, даже если такой кузов оборудован для перевозки пассажиров.</p>","image":null},{"id":102300402,"themeId":5,"group":1023004,"chapter":23,"chapters":[23],"q":"В каком из перечисленных случаев может быть разрешена перевозка пассажиров при наличии мест, оборудованных для сидения?","a":["В кузове грузового мотоцикла.","В кабине самоходной машины.","На прицепе колёсного трактора.","В кузове грузового автомобиля-самосвала.","На прицепе-фургоне к легковому автомобилю."],"c":1,"e":"<p>Согласно Правилам дорожного движения, перевозка пассажиров в кабине самоходной машины не запрещена при наличии мест, оборудованных для сидения.</p>","image":null},{"id":102300421,"themeId":5,"group":1023004,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозка пассажиров на грузовом прицепе?","a":["Разрешается при условии, что он обеспечен местами для сидения, расположенными ниже уровня бортов.","Нет, не разрешается."],"c":1,"e":"<p>Запрещается перевозить пассажиров на прицепе любого типа, независимо от того, имеются ли места для сидения в прицепе или нет.</p>","image":"assets/adrive-questions/q102300421.jpg"},{"id":102300422,"themeId":5,"group":1023004,"chapter":23,"chapters":[23],"q":"Нарушит ли водитель Правила дорожного движения, если будет перевозить на прицепе пассажира, следующего за получением груза?","a":["Да, нарушит.","Не нарушит, если пассажир будет обеспечен местом для сидения, расположенным на уровне бортов.","Не нарушит, если пассажир будет обеспечен местом для сидения, расположенным ниже уровня бортов."],"c":0,"e":"<p>Запрещается перевозить пассажиров на прицепе, даже если прицеп оборудован местами для сидения.</p>","image":null},{"id":102300423,"themeId":5,"group":1023004,"chapter":23,"chapters":[23],"q":"Разрешается ли водителю, имеющему водительское удостоверение соответствующих категорий и стаж вождения более трёх лет, перевозить пассажиров на прицепе к грузовому автомобилю?","a":["Да, разрешается.","Разрешается только лиц, следующих за получением груза или сопровождающих его, при условии, что они обеспечены местами для сидения, расположенными ниже уровня бортов.","Разрешается только лиц, следующих за получением груза или сопровождающих его, при условии, что они обеспечены местами для сидения, расположенными выше уровня бортов.","Нет, не разрешается."],"c":3,"e":"<p>Запрещается перевозить пассажиров на прицепе любого типа, независимо от того, имеются ли места для сидения в прицепе или нет, в том числе при перевозке различных грузов.</p>","image":null},{"id":102300424,"themeId":5,"group":1023004,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозить пассажиров в кузове грузового мотоцикла?","a":["Разрешается, если кузов оборудован местами для сидения.","Разрешается только лиц, следующих за получением груза или сопровождающих его, при условии, что они обеспечены местами для сидения, расположенными ниже уровня бортов.","Разрешается в обоих перечисленных случаях.","Нет, не разрешается."],"c":3,"e":"<p>Запрещается перевозить пассажиров в кузове грузового мотоцикла, даже если он оборудован местами для перевозки пассажиров.</p>","image":null},{"id":102300501,"themeId":5,"group":1023005,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозить пассажиров в кузове-фургоне грузового автомобиля, оборудованном для перевозки пассажиров?","a":["Разрешается, за исключением детей.","Разрешается, за исключением детей, инвалидов и лиц престарелого возраста.","Разрешается, за исключением детей без сопровождающих совершеннолетних из расчёта: не менее одного сопровождающего на двадцать детей.","Запрещается."],"c":0,"e":"<p>Перевозить пассажиров в кузове-фургоне грузового автомобиля, оборудованном для перевозки пассажиров, разрешается, за исключением детей.</p>","image":null},{"id":102300502,"themeId":5,"group":1023005,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозить пассажиров в прицепе-фургоне к легковому автомобилю, оборудованном для перевозки пассажиров?","a":["Разрешается, за исключением детей.","Разрешается, за исключением детей без сопровождающего.","Разрешается, за исключением детей, инвалидов и лиц престарелого возраста.","Запрещается."],"c":3,"e":"<p>Согласно Правилам дорожного движения, перевозить пассажиров в любом прицепе, в том числе в прицепе-фургоне к легковому автомобилю, оборудованном для перевозки пассажиров запрещается.</p>","image":null},{"id":102300521,"themeId":5,"group":1023005,"chapter":23,"chapters":[23],"q":"Каким образом разрешается перевозка пассажиров в показанной ситуации?","a":["Разрешается только в салоне автомобиля.","Разрешается только в прицепе, оборудованном местами для сидения.","Разрешается как в салоне автомобиля, так и в прицепе.","Запрещается как в салоне автомобиля, так и в прицепе."],"c":0,"e":"<p>Запрещается перевозить пассажиров вне салона (кабины) автомобиля, а также на (в) прицепе, даже если прицеп оборудован местами для сидения.</p>","image":"assets/adrive-questions/q102300521.jpg"},{"id":102300522,"themeId":5,"group":1023005,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозить пассажиров в прицепе-фургоне к легковому автомобилю, оборудованному местами для сидения?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Запрещается перевозить пассажиров на прицепе любого типа, независимо от того, имеются ли места для сидения в прицепе или нет.</p>","image":"assets/adrive-questions/q102300522.jpg"},{"id":102300601,"themeId":5,"group":1023006,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозка пассажира, следующего за получением груза, в кузове-фургоне грузового автомобиля при наличии свободного места в кабине автомобиля?","a":["Запрещается.","Разрешается при наличии места, оборудованного для сидения."],"c":1,"e":"<p>Согласно Правилам дорожного движения, перевозка пассажира, следующего за получением груза, в кузове-фургоне грузового автомобиля разрешается при наличии места, оборудованного для сидения в кузове, вне зависимости, есть ли свободное место в кабине автомобиля.</p>","image":null},{"id":102300602,"themeId":5,"group":1023006,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозка пассажира, следующего за получением груза, в кузове прицепа к грузовому автомобилю?","a":["Разрешается при наличии места для сидения, оборудованного ниже уровня бортов.","Разрешается при наличии у водителя водительского стажа управления данной категории транспортного средства более трёх лет.","Разрешается после проведения водителем инструктажа о порядке посадки (размещения и высадки) в кузов, а также о правилах поведения во время движения.","Разрешается при выполнении всех перечисленных условий.","Запрещается."],"c":4,"e":"<p>Перевозка пассажиров, в том числе пассажира, следующего за получением груза, в кузове прицепа к грузовому автомобилю запрещается.</p>","image":null},{"id":102300621,"themeId":5,"group":1023006,"chapter":23,"chapters":[23],"q":"Разрешается ли водителю с водительским стажем до двух лет, имеющему право на управление механическими транспортными средствами соответствующих категорий, перевозить пассажира в кузове с бортовой платформой грузового автомобиля с технически допустимой общей массой не более 3.5 тонны, не оборудованном для перевозки пассажиров?","a":["Да, разрешается.","Разрешается только пассажира, следующего за получением груза или сопровождающего его, при условии, что он обеспечен местом для сидения, расположенном ниже уровня бортов.","Разрешается только пассажира, следующего за получением груза или сопровождающего его, при условии, что он обеспечен местом для сидения, расположенном выше уровня бортов.","Нет, не разрешается."],"c":3,"e":"<p>При наличии водительского удостоверения категории «B» и стажа управления транспортным средством этой категории до двух лет запрещено перевозить пассажиров в кузове грузового автомобиля, даже при наличии права управления механическим транспортным средством категории «C».</p>","image":null},{"id":102300622,"themeId":5,"group":1023006,"chapter":23,"chapters":[23],"q":"Разрешается ли водителю, имеющему право на управление механическими транспортными средствами категорий «B» и «C», со стажем управления механическим транспортным средством категории «B» более трёх лет перевозить пассажира в кузове с бортовой платформой грузового автомобиля с технически допустимой общей массой не более 3.5 тонны, не оборудованном для перевозки пассажиров?","a":["Да, разрешается.","Разрешается только пассажира, следующего за получением груза или сопровождающего его, при условии, что он обеспечен местом для сидения, расположенном ниже уровня бортов.","Разрешается только пассажира, следующего за получением груза или сопровождающего его, при условии, что он обеспечен местом для сидения, расположенном выше уровня бортов.","Нет, не разрешается."],"c":1,"e":"<p>Проезд в кузове грузового автомобиля с бортовой платформой, не оборудованном для перевозки пассажиров, разрешается только лицам, следующим за получением груза или сопровождающим его, при условии, что они обеспечены местами для сидения, расположенными ниже уровня бортов.</p>","image":null},{"id":102300701,"themeId":5,"group":1023007,"chapter":23,"chapters":[23],"q":"Как следует перевозить ребёнка в возрасте до пяти лет в легковом автомобиле, оборудованном ремнями безопасности?","a":["С использованием детских удерживающих устройств, соответствующих весу и росту ребёнка.","С использованием детских удерживающих устройств, соответствующих весу и росту ребёнка, а также иных средств (бустеров, специальных подушек для сидения, дополнительных сидений), позволяющих безопасно пристегнуть ребёнка с помощью ремней безопасности, предусмотренных конструкцией транспортного средства."],"c":0,"e":"<p>Перевозка детей в возрасте до пяти лет в легковом автомобиле, оборудованном ремнями безопасности, должна осуществляться только с использованием детских удерживающих устройств, соответствующих весу и росту ребёнка.</p>","image":null},{"id":102300801,"themeId":5,"group":1023008,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозить пассажиров сверх количества, предусмотренного технической характеристикой транспортного средства?","a":["Разрешается при оборудовании транспортного средства дополнительными местами для сидения.","Запрещается, за исключением детей в возрасте до 12 лет при перевозке на коленях у совершеннолетнего пассажира.","Разрешается, если при этом фактическая масса транспортного средства не превысит технически допустимую общую массу.","Запрещается в любом случае."],"c":3,"e":"<p>Перевозить пассажиров сверх количества, предусмотренного технической характеристикой транспортного средства, запрещается.</p>","image":null},{"id":102300821,"themeId":5,"group":1023008,"chapter":23,"chapters":[23],"q":"Разрешено ли перевозить на переднем сиденье грузового автомобиля двух пассажиров?","a":["Нет, не разрешено.","Разрешено, если такое количество пассажиров предусмотрено технической характеристикой автомобиля."],"c":1,"e":"<p>Запрещается перевозить пассажиров сверх количества, предусмотренного технической характеристикой транспортного средства.</p>","image":"assets/adrive-questions/q102300821.jpg"},{"id":102300832,"themeId":5,"group":1023008,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозить ребёнка в возрасте до 12 лет на коленях у совершеннолетнего пассажира на заднем сиденье легкового автомобиля (за исключением автомобиля-такси), оборудованного ремнями безопасности?","a":["Разрешается, при условии, что совершеннолетний пассажир пристёгнут ремнём безопасности.","Запрещается."],"c":1,"e":"<p>Согласно Правилам дорожного движения, перевозить ребёнка в возрасте до 12 лет на коленях у совершеннолетнего пассажира на заднем сиденье легкового автомобиля, оборудованного ремнями безопасности, запрещается.</p>","image":"assets/adrive-questions/q102300832.jpg"},{"id":102300901,"themeId":5,"group":1023009,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозить ребёнка в возрасте до 12 лет (рост ребёнка не превышает 150 см.) на переднем сиденье грузового автомобиля, оборудованного ремнями безопасности, при отсутствии специального детского удерживающего устройства либо иного средства, позволяющего безопасно пристегнуть ребёнка с помощью ремней безопасности?","a":["Разрешается.","Разрешается только на коленях у пассажира.","Запрещается."],"c":2,"e":"<p>Перевозить ребёнка в возрасте до 12 лет на переднем сиденье автомобиля <strong>при отсутствии специального детского удерживающего устройства запрещается</strong>.<br> При этом, если перевозка осуществляется в легковом автомобиле-такси или рост ребёнка превышает 150 сантиметров, его перевозка может быть осуществлена при условии его пристёгивания ремнём безопасности (то есть без применения дополнительных удерживающих и иных устройств, позволяющих безопасно пристегнуть ребёнка).</p>","image":null},{"id":102300902,"themeId":5,"group":1023009,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозить по трое детей (при перевозке группы детей) в возрасте до 12 лет на сдвоенном сиденье автобуса?","a":["Разрешается, если это не создаёт неудобств детям.","Разрешается при отсутствии дополнительных мест для сидения.","Запрещается."],"c":2,"e":"<p>Согласно Правилам дорожного движения, при перевозке группы детей в автобусе каждый ребёнок должен быть обеспечен отдельным посадочным местом.</p>","image":null},{"id":102300921,"themeId":5,"group":1023009,"chapter":23,"chapters":[23],"q":"С какого возраста допускается перевозить ребёнка в легковом автомобиле, оборудованном ремнями безопасности, без использования детских удерживающих устройств, соответствующих весу и росту ребёнка, иных средств, позволяющих безопасно пристегнуть ребёнка с помощью ремней безопасности, предусмотренных конструкцией транспортного средства?","a":["С 5 лет.","С 7 лет.","С 8 лет.","С 10 лет.","С 12 лет."],"c":4,"e":"<p>Допускается перевозить детей в возрасте от 12 лет без детских удерживающих устройств, соответствующих весу и росту ребёнка, иных средств (бустеров, специальных подушек для сидения, дополнительных сидений), позволяющих безопасно пристегнуть ребёнка с помощью ремней безопасности, предусмотренных конструкцией транспортного средства, а также и в ином возрасте, если рост ребёнка превышает 150 сантиметров.</p> <p>Следует учитывать, что если рост ребёнка в возрасте 12 лет значительно меньше 150 сантиметров, то, несмотря на разрешение Правил дорожного движения, не следует торопиться выбрасывать бустер, если на автомобиле отсутствует возможность отрегулировать высоту ремня безопасности для безопасной перевозки ребёнка.</p>","image":null},{"id":102300922,"themeId":5,"group":1023009,"chapter":23,"chapters":[23],"q":"В каких случаях допускается перевозить детей в возрасте до 12 лет в легковом автомобиле, оборудованном ремнями безопасности, без использования детских удерживающих устройств и иных средств, позволяющих безопасно пристегнуть ребёнка с помощью ремней безопасности?","a":["Если рост ребёнка превышает 150 сантиметров.","Если перевозка осуществляется в автомобиле-такси.","В любом случае из вышеперечисленных."],"c":2,"e":"<p>Допускается перевозить детей в возрасте до двенадцати лет без детских удерживающих устройств, соответствующих весу и росту ребёнка, — в возрасте до пяти лет, а также без детских удерживающих устройств, соответствующих весу и росту ребёнка, иных средств (бустеров, специальных подушек для сидения, дополнительных сидений), позволяющих безопасно пристегнуть ребёнка с помощью ремней безопасности, предусмотренных конструкцией транспортного средства, — в возрасте от 5 до 12 лет в случае, если рост ребёнка превышает 150 сантиметров, а также в автомобиле-такси.</p> <p>При росте ребёнка свыше 150 сантиметров считается, что безопасно пристёгиваться штатным ремнём безопасности, поэтому разрешено отказаться от специальных средств: бустеров, специальных подушек для сидения, дополнительных сидений.</p> <p>При перевозке ребёнка ростом не более 150 сантиметров в автомобиле-такси учтите, что у водителя может не быть в комплекте детских удерживающих устройств, либо их нет в необходимом количестве для перевозки нескольких детей. Поэтому, если Вы заботитесь о безопасности своих детей, предупреждайте диспетчера при вызове такси о необходимости укомплектования такси необходимым количеством детских удерживающих устройств или иных средств, позволяющих безопасно пристегнуть ребёнка с помощью ремней безопасности, либо воспользуйтесь безопасным общественным транспортом.</p>","image":null},{"id":102301021,"themeId":5,"group":1023010,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозка пассажиров в учебном автомобиле, управляемом лицом, сдающим квалификационный практический экзамен на право управления механическим транспортным средством?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Разрешается перевозить пассажиров на учебном механическом транспортном средстве, управляемом лицом, обучаемым управлению механическим транспортным средством, в случаях приёма квалификационного практического экзамена на право управления механическим транспортным средством и проведения контрольных проверок учебной организации.</p>","image":"assets/adrive-questions/q102301021.jpg"},{"id":102301031,"themeId":5,"group":1023010,"chapter":23,"chapters":[23],"q":"В каких случаях разрешается перевозка пассажиров на учебном механическом транспортном средстве, управляемом лицом, обучаемым управлению механическим транспортным средством?","a":["Разрешается при движении по автодрому.","Разрешается в случае проведения администрацией учебной организации контроля за обучением управлению механическим транспортным средством.","Разрешается при совершенствовании навыков вождения в конце курса обучения.","Разрешается во всех перечисленных случаях.","Запрещается во всех перечисленных случаях."],"c":1,"e":"<p>Перевозка пассажиров на учебном механическом транспортном средстве, управляемом лицом, обучаемым управлению механическим транспортным средством, разрешается, в частности, в случае проведения администрацией учебной организации контроля за обучением управлению механическим транспортным средством.</p>","image":null},{"id":102301032,"themeId":5,"group":1023010,"chapter":23,"chapters":[23],"q":"В каких случаях разрешается перевозка пассажиров на учебном механическом транспортном средстве, управляемом лицом, обучаемым управлению механическим транспортным средством?","a":["Разрешается в случае проведения администрацией учебной организации контроля за обучением управлению механическим транспортным средством.","Разрешается в случае приёма квалификационного практического экзамена на право управления механическим транспортным средством.","Разрешается во всех перечисленных случаях.","Запрещается во всех перечисленных случаях."],"c":2,"e":"<p>Перевозка пассажиров на учебном механическом транспортном средстве, управляемом лицом, обучаемым управлению механическим транспортным средством, разрешается в случаях проведения администрацией учебной организации контроля за обучением управлению механическим транспортным средством и приема квалификационного практического экзамена на право управления механическим транспортным средством.</p>","image":"assets/adrive-questions/q102301032.jpg"},{"id":102301101,"themeId":5,"group":1023011,"chapter":23,"chapters":[23],"q":"В каком из перечисленных случаев запрещено перевозить ребёнка на переднем сиденье легкового автомобиля?","a":["В возрасте 13 лет при отсутствии специального детского удерживающего устройства.","В возрасте до двух лет при наличии специального детского удерживающего устройства, спинка которого развёрнута от лобового стекла транспортного средства.","В возрасте до одного года на коленях у совершеннолетнего пассажира при условии, что названный пассажир пристёгнут ремнём безопасности.","Запрещено во всех перечисленных случаях."],"c":2,"e":"<p>Запрещено перевозить любого ребёнка на коленях у пассажира. Ребёнок должен быть размещён в легковом автомобиле только в соответствии с п.178 Правил дорожного движения.</p>","image":null},{"id":102301102,"themeId":5,"group":1023011,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозить ребёнка на коленях у совершеннолетнего пассажира на переднем сиденье легкового автомобиля?","a":["Разрешается только перевозка детей в возрасте до двух лет.","Разрешается при условии, что названный пассажир пристёгнут ремнём безопасности.","Разрешается только при отсутствии спереди подушки безопасности или при условии, что она отключена.","Запрещается."],"c":3,"e":"<p>Перевозить ребёнка на коленях у пассажира на любом сиденье легкового автомобиля запрещается.</p>","image":null},{"id":102301121,"themeId":5,"group":1023011,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозка в легковом автомобиле ребёнка на переднем сиденье показанным способом, если переднее сиденье имеет подушку безопасности, которая не отключается?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Запрещается перевозка детей на переднем сиденье легкового автомобиля с использованием детских удерживающих устройств, соответствующих весу и росту ребёнка, спинка которых развёрнута к лобовому стеклу транспортного средства, если переднее сиденье имеет подушку безопасности, за исключением случая, когда механизм фронтальной подушки безопасности отключён.</p> <p>В случае срабатывания подушки безопасности, ребёнок может быть травмирован частями конструкции детского удерживающего устройства. Поэтому, если отсутствует возможность отключения подушки безопасности, перевозка ребёнка показанным способом запрещается.</p>","image":"assets/adrive-questions/q102301121.jpg"},{"id":102301122,"themeId":5,"group":1023011,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозка в легковом автомобиле ребёнка на переднем сиденье показанным способом, если переднее сиденье имеет подушку безопасности?","a":["Да, разрешается.","Разрешается при условии, что механизм фронтальной подушки безопасности отключён.","Нет, не разрешается."],"c":1,"e":"<p>Запрещается перевозка детей на переднем сиденье легкового автомобиля с использованием детских удерживающих устройств, соответствующих весу и росту ребёнка, спинка которых развёрнута к лобовому стеклу транспортного средства, если переднее сиденье имеет подушку безопасности, за исключением случая, когда механизм фронтальной подушки безопасности отключён.</p> <p>В случае срабатывания подушки безопасности, ребёнок может быть травмирован частями конструкции детского удерживающего устройства.</p>","image":"assets/adrive-questions/q102301122.jpg"},{"id":102301123,"themeId":5,"group":1023011,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозка в легковом автомобиле ребёнка на переднем сиденье показанным способом, если переднее сиденье имеет подушку безопасности?","a":["Да, разрешается.","Разрешается при условии, что механизм фронтальной подушки безопасности отключён.","Нет, не разрешается."],"c":0,"e":"<p>Запрещается перевозка детей на переднем сиденье легкового автомобиля с использованием детских удерживающих устройств в том случае, если спинка развёрнута к лобовому стеклу транспортного средства, переднее сиденье имеет подушку безопасности, а механизм фронтальной подушки безопасности не отключён.</p> <p>В показанной же ситуации спинка детского удерживающего устройства развёрнута к спинке сиденья, следовательно, такая перевозка не запрещена.</p>","image":"assets/adrive-questions/q102301123.jpg"},{"id":102301201,"themeId":5,"group":1023012,"chapter":23,"chapters":[23],"q":"С какого возраста разрешается перевозка ребёнка на переднем сиденье легкового автомобиля (кроме автомобиля-такси) без специального детского удерживающего устройства или иных средств, позволяющих безопасно его пристегнуть, если рост ребёнка не превышает 150 сантиметров?","a":["С 6 лет.","С 8 лет.","С 10 лет.","С 12 лет.","С 14 лет."],"c":3,"e":"<p>Перевозка на переднем сиденье легкового автомобиля (кроме автомобиля-такси) без специального детского удерживающего устройства или иных средств, позволяющих безопасно пристегнуть ребёнка с помощью ремней безопасности, если его рост не превышает 150 сантиметров, разрешается с 12 лет.</p>","image":null},{"id":102301232,"themeId":5,"group":1023012,"chapter":23,"chapters":[23],"q":"С какого возраста ребёнка разрешается его перевозка на мотоцикле?","a":["С 10 лет.","С 12 лет.","С 14 лет.","С 15 лет.","С 16 лет."],"c":1,"e":"<p>Перевозка ребёнка на мотоцикле разрешается с 12 лет.</p>","image":null},{"id":102301233,"themeId":5,"group":1023012,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозка ребёнка на мопеде?","a":["Разрешается, за исключением детей в возрасте до двенадцати лет.","Разрешается, когда перевозка пассажиров предусмотрена конструкцией мопеда.","Разрешается при выполнении вышеперечисленных условий.","Запрещается."],"c":2,"e":"<p>Перевозка ребёнка на мопеде разрешается только с 12 лет, когда перевозка пассажиров предусмотрена конструкцией мопеда.</p>","image":null},{"id":102301234,"themeId":5,"group":1023012,"chapter":23,"chapters":[23],"q":"С какого возраста разрешается перевозить детей на мопеде, если перевозка пассажиров предусмотрена конструкцией мопеда?","a":["С 5 лет.","С 7 лет.","С 8 лет.","С 10 лет.","С 12 лет."],"c":4,"e":"<p>Перевозка ребёнка на мопеде (если перевозка пассажиров предусмотрена конструкцией мопеда) разрешается с 12 лет.</p>","image":null},{"id":102301235,"themeId":5,"group":1023012,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозить ребёнка в возрасте до двенадцати лет на мотоцикле, мопеде?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается только в боковом прицепе к мотоциклу."],"c":1,"e":"<p>Запрещается перевозить детей до двенадцати лет на мотоцикле, мопеде.</p>","image":null},{"id":102301301,"themeId":5,"group":1023013,"chapter":23,"chapters":[23],"q":"Требуется ли на легковом автомобиле при перевозке детей устанавливать опознавательный знак «Перевозка детей»?","a":["Требуется устанавливать только сзади.","Требуется устанавливать спереди и сзади.","Не требуется."],"c":2,"e":"<p>При перевозке детей на легковом автомобиле устанавливать опознавательный знак «Перевозка детей» не требуется.</p>","image":null},{"id":102301302,"themeId":5,"group":1023013,"chapter":23,"chapters":[23],"q":"Разрешается ли перевозить ребёнка на коленях у водителя?","a":["Разрешается только перевозка детей в возрасте до четырёх лет.","Разрешается при условии, что водитель пристёгнут ремнём безопасности.","Разрешается только на дворовой территории при скорости движения не более 20 км/ч.","Запрещается."],"c":3,"e":"<p>Согласно Правилам дорожного движения, перевозить ребёнка на коленях у водителя запрещается.</p>","image":null},{"id":102301321,"themeId":5,"group":1023013,"chapter":23,"chapters":[23],"q":"В каких случаях из перечисленных ниже разрешена перевозка ребёнка в возрасте до 12 лет в легковом автомобиле, оборудованном ремнями безопасности?","a":["На переднем сиденье легкового автомобиля с использованием детского удерживающего устройства, соответствующего весу и росту ребёнка.","На коленях у пассажира на переднем сиденье в автомобиле-такси.","Разрешена в обоих случаях.","Запрещена в обоих случаях."],"c":0,"e":"<p>Перевозка детей в легковом автомобиле, оборудованном ремнями безопасности (независимо от месторасположения сидений: передний, задний или средний ряд), должна осуществляться с использованием:</p> <ul><li>детских удерживающих устройств, соответствующих весу и росту ребёнка, — в возрасте до пяти лет;</li> <li>детских удерживающих устройств, соответствующих весу и росту ребёнка, иных средств (бустеров, специальных подушек для сидения, дополнительных сидений), позволяющих безопасно пристегнуть ребёнка с помощью ремней безопасности, предусмотренных конструкцией транспортного средства, — в возрасте от пяти до двенадцати лет.</li></ul> <p>При этом запрещается перевозить детей на коленях у водителя и у пассажира на переднем сиденье легкового автомобиля.</p>","image":null},{"id":102400101,"themeId":5,"group":1024001,"chapter":24,"chapters":[24],"q":"В каком из перечисленных случаев запрещена перевозка груза транспортным средством?","a":["Если груз ограничивает водителю обзорность дороги.","Если груз закрывает световозвращатели транспортного средства.","Если масса перевозимого груза превышает величину, установленную изготовителем для данного транспортного средства.","Во всех перечисленных случаях перевозка груза запрещена."],"c":3,"e":"<p>Перевозка груза транспортным средством запрещена:</p> <ul><li>если груз ограничивает водителю обзорность дороги;</li> <li>если груз закрывает внешние световые приборы и световозвращатели транспортного средства;</li> <li>если масса перевозимого груза превышает величину, установленную изготовителем для данного транспортного средства.</li></ul>","image":null},{"id":102400102,"themeId":5,"group":1024001,"chapter":24,"chapters":[24],"q":"В каком из перечисленных случаев запрещена перевозка груза транспортным средством?","a":["Если груз нарушает устойчивость транспортного средства.","Если груз закрывает опознавательный знак «Ограничение скорости».","Если распределение нагрузки по осям превышает величины, установленные изготовителем для данного транспортного средства.","Во всех перечисленных случаях перевозка груза запрещена."],"c":3,"e":"<p>Перевозка груза транспортным средством запрещена:</p> <ul><li>если груз нарушает устойчивость транспортного средства;</li> <li>если груз закрывает опознавательные знаки транспортного средства;</li> <li>если распределение нагрузки по осям превышает величины, установленные изготовителем для данного транспортного средства.</li></ul>","image":null},{"id":102400103,"themeId":5,"group":1024001,"chapter":24,"chapters":[24],"q":"В каком из перечисленных случаев не запрещена перевозка груза транспортным средством?","a":["Если груз создаёт шум, но при этом не загрязняет дорогу и окружающую среду.","Если груз не закреплён, но при этом не создаёт угрозу безопасности дорожного движения.","Если распределение нагрузки по осям превышает величины, установленные изготовителем для данного транспортного средства, но при этом масса перевозимого груза не превышает величину, установленную для него изготовителем.","Во всех перечисленных случаях перевозка груза запрещена."],"c":1,"e":"<p>Перевозка груза транспортным средством не запрещена, если груз не закреплён, но при этом не создаёт угрозу безопасности дорожного движения (то есть исключено повреждение груза, его падение на проезжую часть дороги и тому подобное).</p>","image":null},{"id":102400121,"themeId":5,"group":1024001,"chapter":24,"chapters":[24],"q":"Разрешается ли перевозить груз, масса которого превышает величину, установленную изготовителем для данного транспортного средства?","a":["Разрешается, если перевозка груза осуществляется на незначительное расстояние.","Разрешается, если перевозка груза осуществляется на автомобиле индивидуального владельца.","Разрешается, если перевозка груза осуществляется на транспортном средстве с включённым проблесковым маячком оранжевого цвета.","Нет, не разрешается."],"c":3,"e":"<p>При перевозке груза одним из основных условий является то, что масса перевозимого груза и распределение нагрузки по осям не должны превышать величин, установленных изготовителем для данного транспортного средства. При этом запрещение на такую перевозку действует независимо от целей, расстояния перевозки и типа транспортного средства.</p>","image":null},{"id":102400201,"themeId":5,"group":1024002,"chapter":24,"chapters":[24],"q":"Как должен поступить водитель, если масса груза, который необходимо перевезти, превышает величину, установленную изготовителем для данного транспортного средства?","a":["Получить разрешение в ГАИ на движение тяжеловесного транспортного средства.","Обозначить транспортное средство опознавательным знаком «Транспортное средство большой грузоподъёмности».","При перевозке груза включить ближний свет фар, по возможности при движении не прибегать к резкому торможению.","Перевезти груз по частям, при перевозке которых не будут нарушены нормы, установленные изготовителем."],"c":3,"e":"<p>Водитель обязан перевезти груз (если груз разборный) по частям, при перевозке которых не будут нарушены нормы, установленные изготовителем, если масса груза, который необходимо перевезти, превышает величину, установленную изготовителем для данного транспортного средства.</p>","image":null},{"id":102400202,"themeId":5,"group":1024002,"chapter":24,"chapters":[24],"q":"В каком из перечисленных случаев не запрещена перевозка груза?","a":["Если груз затрудняет управление транспортным средством на скоростях больше 60 км/ч.","Если груз закрывает правые передние внешние световые приборы в светлое время суток.","Если груз выступает спереди на 0.6 метра, но не ограничивает водителю обзорность дороги.","Если груз выступает спереди на 0.5 метра и ограничивает водителю обзорность дороги вправо.","Во всех перечисленных случаях перевозка груза запрещена."],"c":2,"e":"<p>Перевозка груза разрешена, если груз выступает спереди до 1 метра, но не ограничивает водителю обзорность дороги, не закрывает внешние световые приборы и световозвращатели.</p>","image":null},{"id":102400221,"themeId":5,"group":1024002,"chapter":24,"chapters":[24],"q":"Разрешается ли перевозить груз, масса которого превышает величину, установленную изготовителем для данного транспортного средства?","a":["Да, только если груз не ограничивает водителю обзорность дороги.","Да, только если груз не создаёт угрозу безопасности дорожного движения.","Да, только если груз не затрудняет управление транспортным средством и не нарушает его устойчивость.","Разрешается только при соблюдении всех вышеперечисленных условий.","Нет, не разрешается."],"c":4,"e":"<p>При перевозке груза одним из основных условий является то, что масса перевозимого груза и распределение нагрузки по осям не должны превышать величин, установленных изготовителем для данного транспортного средства.</p>","image":null},{"id":102400222,"themeId":5,"group":1024002,"chapter":24,"chapters":[24],"q":"Разрешается ли перевозить груз, если он нарушает устойчивость транспортного средства?","a":["Разрешается, если он надёжно закреплён во избежание его смещения или падения.","Разрешается, если масса перевозимого груза не превышает величину, установленную изготовителем для данного транспортного средства.","Разрешается при соблюдении обоих вышеперечисленных условий.","Нет, не разрешается."],"c":3,"e":"<p>Перевозка груза запрещается, если он затрудняет управление транспортным средством, нарушает его устойчивость. Под продольной устойчивостью понимают способность автомобиля сохранять устойчивость в продольном направлении (вдоль дороги) при преодолении подъёмов и движении на спусках. Способность автомобиля сохранять устойчивость в поперечном направлении (поперёк дороги) называется поперечной устойчивостью, например при движении по дороге с поперечным уклоном или по косогору. Значительное повышение центра тяжести вследствие высоты груза снижает поперечную устойчивость автомобиля.</p>","image":"assets/adrive-questions/q102400222.jpg"},{"id":102400321,"themeId":5,"group":1024003,"chapter":24,"chapters":[24],"q":"В каком случае из перечисленных допускается перевозка груза?","a":["Груз ограничивает водителю обзорность дороги.","Груз выступает за габариты транспортного средства.","Груз создаёт шум, но не угрожает безопасности дорожного движения.","Груз закрывает внешние световые приборы, препятствует восприятию сигналов, подаваемых рукой.","Груз затрудняет управление транспортным средством, но не нарушает его устойчивость."],"c":1,"e":"<p>Перевозка груза запрещается, если он:</p> <ul><li>создаёт угрозу безопасности дорожного движения;</li> <li>ограничивает водителю обзорность дороги;</li> <li>затрудняет управление транспортным средством, нарушает его устойчивость;</li> <li>закрывает внешние световые приборы и световозвращатели, регистрационные, временные номерные и опознавательные знаки транспортных средств, а также препятствует восприятию сигналов, подаваемых рукой при неисправных (отсутствующих) световых указателях поворотов;</li> <li>создаёт шум, пылит, загрязняет дорогу и окружающую среду.</li></ul> <p>При этом не запрещается перевозить груз, выступающий за габариты транспортного средства. Если груз выступает за габариты более чем определено Правилами дорожного движения, в некоторых случаях достаточно его обозначить соответствующим образом, в иных — получить специальное разрешение для такой транспортировки груза.</p>","image":null},{"id":102400322,"themeId":5,"group":1024003,"chapter":24,"chapters":[24],"q":"Какое из перечисленных требований не является обязательным при перевозке груза?","a":["Груз не должен ограничивать водителю обзорность дороги.","Груз не должен выступать за габариты транспортного средства.","Груз не должен нарушать устойчивость транспортного средства.","Груз не должен создавать шум.","Груз не должен закрывать внешние световые приборы и световозвращатели."],"c":1,"e":"<p>Если перевозимый груз выступает незначительно за габариты транспортного средства, его перевозка не запрещена.</p> <p>Груз, выступающий за габариты транспортного средства спереди или сзади более чем на 1 метр или сбоку более чем на 0.4 метра от внешнего края габаритного огня, должен быть обозначен опознавательными знаками «Крупногабаритный груз», а в тёмное время суток и (или) при недостаточной видимости дороги, кроме того, спереди — фонарём, излучающим белый свет, сзади — фонарём, излучающим красный свет.</p> <p>Если груз выступает за габариты транспортного средства по длине на 2 метра и более, то это транспортное средство относится к категории крупногабаритных.</p>","image":null},{"id":102400323,"themeId":5,"group":1024003,"chapter":24,"chapters":[24],"q":"Перевозка груза запрещается, если он:","a":["Выступает более чем на один метр за габариты транспортного средства спереди или сзади и обозначен в соответствии с Правилами дорожного движения.","Закрывает регистрационные, временные номерные и опознавательные знаки.","Установлен и закреплён на сиденье для пассажиров (пассажиры в салоне отсутствуют).","Запрещается во всех перечисленных случаях."],"c":1,"e":"<p>В перечисленных случаях перевозка груза запрещена, только если он закрывает регистрационные, временные номерные и опознавательные знаки. Более того, запрещается участвовать в дорожном движении с загрязнениями (наслоениями), не позволяющими видеть информацию на регистрационном знаке (временном номерном знаке) с расстояния 40 метров и менее.</p>","image":null},{"id":102400401,"themeId":5,"group":1024004,"chapter":24,"chapters":[24],"q":"Нарушает ли Правила дорожного движения водитель грузового автомобиля, перевозя груз так, как показано, в светлое время суток?","a":["Да, нарушает.","Нет, не нарушает."],"c":1,"e":"<p>В показанной ситуации водитель грузового автомобиля не нарушает Правила дорожного движения, так как перевозимый груз в светлое время суток выступает за габариты ТС по длине на 0.8 метра (не более 1 метра).</p>","image":"assets/adrive-questions/q102400401.jpg"},{"id":102400402,"themeId":5,"group":1024004,"chapter":24,"chapters":[24],"q":"Нарушает ли Правила дорожного движения водитель грузового автомобиля, перевозя груз так, как показано, в светлое время суток?","a":["Да, нарушает.","Нет, не нарушает."],"c":1,"e":"<p>В показанной ситуации водитель грузового автомобиля не нарушает Правила дорожного движения, так как перевозимый груз в светлое время суток выступает за габариты ТС по длине на 0.6 метра (не более 1 метра).</p>","image":"assets/adrive-questions/q102400402.jpg"},{"id":102400501,"themeId":5,"group":1024005,"chapter":24,"chapters":[24],"q":"Нарушает ли водитель Правила дорожного движения, перевозя таким образом груз на багажнике сверху, если ширина транспортного средства с грузом не превышает 2.55 м?","a":["Да, нарушает.","Нет, не нарушает."],"c":1,"e":"<p>В показанной ситуации водитель автомобиля не нарушает Правила дорожного движения, так как ширина транспортного средства с грузом не превышает 2.55 м и перевозимый груз выступает за габариты транспортного средства по ширине на 0.35 метра (не более 0.4 метра).</p>","image":"assets/adrive-questions/q102400501.jpg"},{"id":102400502,"themeId":5,"group":1024005,"chapter":24,"chapters":[24],"q":"Нарушает ли водитель Правила дорожного движения, перевозя таким образом груз на багажнике сверху, если ширина транспортного средства с грузом не превышает 2.55 м?","a":["Да, нарушает.","Нет, не нарушает."],"c":0,"e":"<p>В показанной ситуации водитель автомобиля нарушает Правила дорожного движения, так как перевозимый груз выступает за габариты транспортного средства по ширине на 0.45 метра (более 0.4 метра) и должен быть обозначен опознавательным знаком «Крупногабаритный груз» .</p>","image":"assets/adrive-questions/q102400502.jpg"},{"id":102400601,"themeId":5,"group":1024006,"chapter":24,"chapters":[24],"q":"На какое наибольшее расстояние может выступать груз сбоку от внешнего края габаритного огня, при котором необязательно обозначать его опознавательным знаком «Крупногабаритный груз»?","a":["0.4 метра.","0.6 метра.","0.8 метра.","1 метр."],"c":0,"e":"<p>Груз может выступать сбоку от внешнего края габаритного огня на расстояние, при котором необязательно обозначать его опознавательным знаком «Крупногабаритный груз» , не более чем 0.4 метра.</p>","image":null},{"id":102400602,"themeId":5,"group":1024006,"chapter":24,"chapters":[24],"q":"На какое наибольшее расстояние может выступать груз спереди транспортного средства, при котором необязательно обозначать его опознавательным знаком «Крупногабаритный груз»?","a":["0.4 метра.","0.6 метра.","0.8 метра.","1 метр."],"c":3,"e":"<p>Груз может выступать спереди транспортного средства на расстояние, при котором необязательно обозначать его опознавательным знаком «Крупногабаритный груз» , не более чем 1 метр.</p>","image":null},{"id":102400701,"themeId":5,"group":1024007,"chapter":24,"chapters":[24],"q":"Требуется ли специальное разрешение для грузового автомобиля, у которого при перевозке груза габаритная высота составляет 3.2 метра, ширина — 2.38 метра, длина — 8 метров, груз выступает сзади на 1.4 метра?","a":["Да, требуется.","Нет, не требуется."],"c":1,"e":"<p>Для перевозки груза на грузовом автомобиле, габаритная высота которого составляет 3.2 метра, ширина — 2.38 метра, длина — 8 метров, груз выступает сзади на 1.4 метра, специальное разрешение не требуется, так как ни один из перечисленных параметров не превышает максимально допустимые Правилами дорожного движения значения.</p>","image":null},{"id":102400801,"themeId":5,"group":1024008,"chapter":24,"chapters":[24],"q":"Требуется ли специальное разрешение для грузового автомобиля, у которого при перевозке груза общая габаритная длина составляет 11 метров, а груз выступает сзади на 1.4 метра?","a":["Да, требуется.","Нет, не требуется."],"c":1,"e":"<p>Для перевозки груза на грузовом автомобиле, общая габаритная длина которого составляет 11 метров, а груз выступает сзади на 1.4 метра, не требуется специальное разрешение, так как ни один из перечисленных параметров не превышает максимально допустимые Правилами дорожного движения значения.</p>","image":null},{"id":102400802,"themeId":5,"group":1024008,"chapter":24,"chapters":[24],"q":"Требуется ли специальное разрешение для грузового автомобиля, у которого при перевозке груза общая габаритная длина составляет 11 метров, а груз выступает сзади на 2.1 метра?","a":["Да, требуется.","Нет, не требуется."],"c":0,"e":"<p>Для перевозки груза, который выступает сзади на 2.1 метра (на два метра и более), требуется специальное разрешение.</p>","image":null},{"id":102400803,"themeId":5,"group":1024008,"chapter":24,"chapters":[24],"q":"Требуется ли специальное разрешение для грузового автомобиля, у которого при перевозке груза общая габаритная длина составляет 13 метров, а груз выступает сзади на 1.2 метра?","a":["Да, требуется.","Нет, не требуется."],"c":0,"e":"<p>Для перевозки груза на грузовом автомобиле, общая габаритная длина которого составляет 13 метров (общая длина автомобиля более 12 метров) требуется специальное разрешение.</p>","image":null},{"id":102400821,"themeId":5,"group":1024008,"chapter":24,"chapters":[24],"q":"Как следует перевозить показанный груз в условиях недостаточной видимости, если общая длина автомобиля с грузом не превышает 12 метров?","a":["В соответствии со специальными разрешением и правилами.","Обозначив груз опознавательным знаком «Крупногабаритный груз».","Обозначив груз опознавательным знаком «Крупногабаритный груз» и фонарём, излучающим красный свет."],"c":2,"e":"<p>В светлое время суток груз, выступающий за габариты транспортного средства спереди или сзади более чем на 1 метр, должен быть обозначен опознавательными знаками «Крупногабаритный груз». В условиях недостаточной видимости дороги дополнительно груз должен быть обозначен спереди фонарём, излучающим белый свет, сзади — фонарём, излучающим красный свет.</p> <p>Это необходимо, чтобы он был хорошо виден прочим участникам дорожного движения, так как может представлять опасность для движения.</p>","image":"assets/adrive-questions/q102400821.jpg"},{"id":102400822,"themeId":5,"group":1024008,"chapter":24,"chapters":[24],"q":"Разрешена ли перевозка груза в светлое время суток показанным способом, если ширина транспортного средства с грузом превышает 2.55 метра?","a":["Да, разрешена.","Может быть разрешена только в соответствии со специальными разрешением и правилами.","Разрешена, если выступающий груз обозначить опознавательными знаками «Крупногабаритный груз».","Нет, не разрешена."],"c":1,"e":"<p>В соответствии со специальными разрешением на проезд крупногабаритных транспортных средств по автомобильным дорогам общего пользования Республики Беларусь и правилами производится движение транспортного средства, габаритные размеры которого с грузом или без груза превышают по ширине 2.55 метра.</p>","image":"assets/adrive-questions/q102400822.jpg"},{"id":102400901,"themeId":5,"group":1024009,"chapter":24,"chapters":[24],"q":"Вам необходимо перевезти доски длиной 2.7 метра. Как их закрепить на багажнике на крыше легкового автомобиля, чтобы не было необходимости получать специальное разрешение на перевозку груза?","a":["Вдоль кузова автомобиля.","Поперёк кузова автомобиля.","В любом случае необходимо получить специальное разрешение и двигаться в соответствии со специальными правилами."],"c":0,"e":"<p>Чтобы не было необходимости получать специальное разрешение на перевозку груза, для перевозки досок длиной 2.7 метра необходимо закрепить их на багажнике на крыше легкового автомобиля вдоль кузова таким образом, чтобы груз не выступал за габариты транспортного средства по длине на 2 метра и более.<br> Если закрепить груз поперёк кузова, то габариты автомобиля с грузом превысят допустимый размер в 2.55 метра по ширине.</p>","image":null},{"id":102400902,"themeId":5,"group":1024009,"chapter":24,"chapters":[24],"q":"Какова максимально допустимая ширина перевозимого легковым автомобилем груза, при которой разрешается двигаться по дорогам без специального разрешения?","a":["2.25 метра.","2.35 метра.","2.45 метра.","2.55 метра.","2.65 метра."],"c":3,"e":"<p>Максимально допустимая ширина перевозимого легковым автомобилем груза, при которой разрешается двигаться по дорогам без специального разрешения, составляет 2.55 метра.</p>","image":null},{"id":102400921,"themeId":5,"group":1024009,"chapter":24,"chapters":[24],"q":"Нарушает ли водитель Правила дорожного движения, осуществляя перевозку груза так, как в показанной ситуации, если ширина транспортного средства с грузом не превышает 2.55 метра?","a":["Да, нарушает.","Нет, не нарушает."],"c":0,"e":"<p>Груз, выступающий за габариты транспортного средства сбоку более чем на 0.4 метра от внешнего края габаритного огня, в светлое время суток должен быть обозначен опознавательными знаками «Крупногабаритный груз».</p>","image":"assets/adrive-questions/q102400921.jpg"},{"id":102400922,"themeId":5,"group":1024009,"chapter":24,"chapters":[24],"q":"Разрешается ли водителю перевозить груз в светлое время суток так, как в показанной ситуации, если общая ширина автомобиля с грузом не превышает 2.55 метра?","a":["Да, разрешается.","Разрешается только в случае, если груз будет обозначен опознавательными знаками «Крупногабаритный груз».","Разрешается только в соответствии со специальными разрешением и правилами.","Нет, не разрешается."],"c":1,"e":"<p>Груз, выступающий за габариты транспортного средства сбоку более чем на 0.4 метра от внешнего края габаритного огня, в светлое время суток должен быть обозначен опознавательными знаками «Крупногабаритный груз».</p>","image":"assets/adrive-questions/q102400922.jpg"},{"id":102400923,"themeId":5,"group":1024009,"chapter":24,"chapters":[24],"q":"Может ли быть Вам разрешена перевозка груза в светлое время суток показанным способом, если ширина транспортного средства с грузом превышает 2.55 метра?","a":["Может быть разрешена только в соответствии со специальными разрешением и правилами.","Может быть разрешена, если выступающие части груза обозначить опознавательными знаками «Крупногабаритный груз».","Нет, не может быть разрешена."],"c":0,"e":"<p>В соответствии со специальными разрешением на проезд крупногабаритных транспортных средств по автомобильным дорогам общего пользования Республики Беларусь и правилами производится движение транспортного средства, габаритные размеры которого с грузом или без груза превышают по ширине 2.55 метра.</p>","image":"assets/adrive-questions/q102400923.jpg"},{"id":102401002,"themeId":5,"group":1024010,"chapter":24,"chapters":[24],"q":"Разрешается ли показанным на рисунке способом перевозить крупногабаритный груз на крыше легкового автомобиля в светлое время суток?","a":["Разрешается.","Разрешается только в соответствии со специальным разрешением и правилами.","Запрещается."],"c":0,"e":"<p>В показанной ситуации груз на крыше автомобиля, выступающий за габариты транспортного средства по длине на 1.6 метра, водитель обозначил опознавательным знаком «Крупногабаритный груз» , поэтому таким образом перевозить крупногабаритный груз на крыше легкового автомобиля в светлое время суток разрешено.</p>","image":"assets/adrive-questions/q102401002.jpg"},{"id":102401021,"themeId":5,"group":1024010,"chapter":24,"chapters":[24],"q":"Разрешается ли водителю перевозить груз так, как в показанной ситуации?","a":["Да, разрешено.","Разрешено только если груз будет обозначен опознавательным знаком «Крупногабаритный груз».","Разрешено только в соответствии со специальными разрешением и правилами.","Нет, не разрешено."],"c":1,"e":"<p>Груз, выступающий за габариты транспортного средства спереди или сзади более чем на 1 метр, в светлое время суток должен быть обозначен опознавательными знаками «Крупногабаритный груз».</p>","image":"assets/adrive-questions/q102401021.jpg"},{"id":102401022,"themeId":5,"group":1024010,"chapter":24,"chapters":[24],"q":"Должен ли водитель обозначить груз, выступающий за габарит транспортного средства сверху более чем на 0.4 метра, если общая высота транспортного средства с грузом не превышает 4 метра от поверхности дороги?","a":["Да, должен обозначить опознавательным знаком «Крупногабаритный груз».","Нет, не должен."],"c":1,"e":"<p>Правилами дорожного движения не установлено требований, регламентирующих обозначение груза, выступающего вверх за габарит транспортного средства. Поэтому водитель не должен обозначать части груза, выступающие вверх.</p>","image":"assets/adrive-questions/q102401022.jpg"},{"id":102401101,"themeId":5,"group":1024011,"chapter":24,"chapters":[24],"q":"Разрешено ли водителю грузового автомобиля в светлое время суток перевозить груз так, как показано на рисунке?","a":["Разрешено.","Запрещено."],"c":1,"e":"<p>В показанной ситуации водителю грузового автомобиля перевозить груз таким образом запрещено, так как груз закрывает внешние световые приборы и не обозначен опознавательным знаком «Крупногабаритный груз» .</p>","image":"assets/adrive-questions/q102401101.jpg"},{"id":102401102,"themeId":5,"group":1024011,"chapter":24,"chapters":[24],"q":"Разрешено ли водителю грузового автомобиля в светлое время суток перевозить груз так, как показано на рисунке, при наличии пассажиров в кузове-фургоне?","a":["Разрешено, если груз выступает не далее 1 метра от внешнего края открытой и зафиксированной в таком положении задней двери.","Разрешено, если он будет обозначен опознавательным знаком «Крупногабаритный груз».","Запрещено."],"c":2,"e":"<p>В показанной ситуации водитель автомобиля перевозит пассажиров в кузове-фургоне с открытыми дверями, что запрещено правилами перевозки пассажиров.</p>","image":"assets/adrive-questions/q102401102.jpg"},{"id":102401201,"themeId":5,"group":1024012,"chapter":24,"chapters":[24],"q":"Относится ли показанное транспортное средство к категории крупногабаритных?","a":["Да, относится.","Нет, не относится."],"c":1,"e":"<p>Показанное транспортное средство не относится к категории крупногабаритных, так как груз выступает за габариты транспортного средства по длине сзади на 1.9 метра (менее 2 метров), и автомобиль с грузом не превышает по длине 12 метров.</p>","image":"assets/adrive-questions/q102401201.jpg"},{"id":102401202,"themeId":5,"group":1024012,"chapter":24,"chapters":[24],"q":"Относится ли показанное транспортное средство к категории крупногабаритных?","a":["Да, относится.","Нет, не относится."],"c":0,"e":"<p>Показанное транспортное средство относится к категории крупногабаритных, так как груз выступает за габариты транспортного средства по длине сзади на 2.1 метра (на 2 метра и более).</p>","image":"assets/adrive-questions/q102401202.jpg"},{"id":102401222,"themeId":5,"group":1024012,"chapter":24,"chapters":[24],"q":"Может ли быть разрешена перевозка груза без специального разрешения автомобилем категории «В» в светлое время суток, если ширина транспортного средства с грузом превысит 2.65 метра?","a":["Да, может быть разрешена.","Может быть разрешена только легковым автомобилем.","Может быть разрешена только грузовым автомобилем.","Нет, не может быть разрешена."],"c":3,"e":"<p>В соответствии со специальными разрешением на проезд крупногабаритных транспортных средств по автомобильным дорогам общего пользования Республики Беларусь и правилами производится движение транспортного средства, габаритные размеры которого с грузом или без груза превышают по ширине 2.55 метра, для транспортных средств с изотермическим кузовом – 2.6 метра.</p>","image":null},{"id":102401301,"themeId":5,"group":1024013,"chapter":24,"chapters":[24],"q":"Нарушает ли водитель Правила дорожного движения, перевозя груз так, как показано, в тёмное время суток?","a":["Да, нарушает.","Нет, не нарушает."],"c":0,"e":"<p>В показанной ситуации водитель автомобиля нарушает Правила дорожного движения, так как перевозимый в тёмное время суток груз, который выступает за габариты транспортного средства по длине на 1.2 метра, дополнительно должен быть обозначен сзади фонарём, излучающим красный свет.</p>","image":"assets/adrive-questions/q102401301.jpg"},{"id":102401302,"themeId":5,"group":1024013,"chapter":24,"chapters":[24],"q":"Нарушает ли водитель Правила дорожного движения, перевозя груз так, как показано, в светлое время суток в условиях недостаточной видимости?","a":["Да, нарушает.","Нет, не нарушает."],"c":0,"e":"<p>В показанной ситуации водитель автомобиля нарушает Правила дорожного движения, так как перевозимый в светлое время суток в условиях недостаточной видимости груз, который выступает за габариты транспортного средства по длине на 1.2 метра, дополнительно должен быть обозначен сзади фонарём, излучающим красный свет.</p>","image":"assets/adrive-questions/q102401302.jpg"},{"id":102401303,"themeId":5,"group":1024013,"chapter":24,"chapters":[24],"q":"Нарушает ли водитель Правила дорожного движения, перевозя груз так, как показано, в светлое время суток?","a":["Да, нарушает.","Нет, не нарушает."],"c":1,"e":"<p>В показанной ситуации водитель автомобиля не нарушает Правила дорожного движения, так как перевозимый в светлое время суток груз, который выступает за габариты транспортного средства по длине на 1.2 метра, обозначен опознавательным знаком «Крупногабаритный груз» .</p>","image":"assets/adrive-questions/q102401303.jpg"},{"id":102401401,"themeId":5,"group":1024014,"chapter":24,"chapters":[24],"q":"Требуется ли специальное разрешение для грузового автомобиля с изотермическим кузовом с прицепом, у которого при перевозке груза габаритная высота составляет 3 метра, ширина — 2.58 метра, длина — 12 метров?","a":["Да, требуется.","Нет, не требуется."],"c":1,"e":"<p>Для перевозки груза на грузовом автомобиле с изотермическим кузовом с прицепом, у которого при перевозке груза габаритная высота составляет 3 метра, ширина — 2.58 метра, длина — 12 метров, не требуется специальное разрешение, так как ни один из перечисленных параметров не превышает максимально допустимые Правилами дорожного движения значения.</p>","image":null},{"id":102401402,"themeId":5,"group":1024014,"chapter":24,"chapters":[24],"q":"Требуется ли специальное разрешение для грузового автомобиля с изотермическим кузовом с прицепом, у которого при перевозке груза габаритная высота составляет 2.95 метра, ширина — 2.64 метра, длина — 13 метров?","a":["Да, требуется.","Нет, не требуется."],"c":0,"e":"<p>Для перевозки груза на грузовом автомобиле с изотермическим кузовом с прицепом, у которого при перевозке груза габаритная ширина составляет — 2.64 метра (более 2.6 метра для изотермических кузовов), требуется специальное разрешение.</p>","image":null},{"id":102401421,"themeId":5,"group":1024014,"chapter":24,"chapters":[24],"q":"Разрешается ли участвовать в дорожном движении показанному легковому автомобилю с прицепом, если общая длина автопоезда с выступающим на 0.9 метра грузом составляет 12.5 метров?","a":["Да, разрешается.","Да, только в соответствии со специальными разрешением и правилами.","Нет, не разрешается."],"c":0,"e":"<p>В соответствии со специальными разрешением на проезд крупногабаритных транспортных средств по автомобильным дорогам общего пользования Республики Беларусь и правилами производится движение автопоезда, габаритные размеры которого с грузом или без груза превышают по длине 20 метров.</p>","image":"assets/adrive-questions/q102401421.jpg"},{"id":102401441,"themeId":5,"group":1024014,"chapter":24,"chapters":[24],"q":"Требуется ли специальное разрешение на проезд крупногабаритного транспортного средства по автомобильным дорогам общего пользования при буксировке легкового автомобиля грузовым, если длина состава транспортных средств составляет 21 метр?","a":["Да, требуется.","Нет, не требуется."],"c":1,"e":"<p>В соответствии со специальными разрешением на проезд крупногабаритных транспортных средств по автомобильным дорогам общего пользования Республики Беларусь и правилами осуществляется движение комбинированного транспортного средства, габаритные размеры которого по длине с грузом или без груза превышают 24 метра.</p>","image":null},{"id":102401501,"themeId":5,"group":1024015,"chapter":24,"chapters":[24],"q":"Как должен обозначить водитель груз, перевозимый в светлое время суток на багажнике сверху, выступающий сбоку более чем на 0.4 метра от внешнего края габаритного огня, если ширина транспортного средства с грузом не превышает 2.55 метра?","a":["Обозначить груз опознавательными знаками «Крупногабаритный груз».","Обозначить выступающие за габарит автомобиля части груза световозвращающими элементами (полосами) красного цвета.","Обозначить выступающие за габарит автомобиля части груза световозвращающими элементами (полосами) оранжевого цвета.","Обозначить груз опознавательными знаками «Крупногабаритный груз» и спереди — фонарём, излучающим белый свет, сзади — фонарём, излучающим красный свет."],"c":0,"e":"<p>Водитель должен обозначить груз, перевозимый в светлое время суток на багажнике сверху, выступающий сбоку более чем на 0.4 метра от внешнего края габаритного огня, опознавательными знаками «Крупногабаритный груз» .</p>","image":"assets/adrive-questions/q102401501.jpg"},{"id":102401502,"themeId":5,"group":1024015,"chapter":24,"chapters":[24],"q":"Как должен обозначить водитель груз, перевозимый в тёмное время суток на багажнике сверху, выступающий сбоку более чем на 0.4 метра от внешнего края габаритного огня, если ширина транспортного средства с грузом не превышает 2.55 метра?","a":["Обозначить груз опознавательными знаками «Крупногабаритный груз».","Обозначить выступающие за габарит автомобиля части груза световозвращающими элементами (полосами) красного цвета.","Обозначить выступающие за габарит автомобиля части груза световозвращающими элементами (полосами) оранжевого цвета.","Обозначить груз опознавательными знаками «Крупногабаритный груз» и спереди — фонарём, излучающим белый свет, сзади — фонарём, излучающим красный свет."],"c":3,"e":"<p>Водитель должен обозначить груз, перевозимый в тёмное время суток на багажнике сверху, выступающий сбоку более чем на 0.4 метра от внешнего края габаритного огня, опознавательными знаками «Крупногабаритный груз» и спереди — фонарём, излучающим белый свет, сзади — фонарём, излучающим красный свет.</p>","image":"assets/adrive-questions/q102401502.jpg"},{"id":102401561,"themeId":5,"group":1024015,"chapter":24,"chapters":[24],"q":"Разрешена ли Вам перевозка груза показанным способом в тёмное время суток, если габарит автомобиля с грузом не превышает 2.55 метра?","a":["Разрешена только в случае, если груз будет обозначен опознавательными знаками «Крупногабаритный груз».","Разрешена только в случае, если груз будет обозначен опознавательными знаками «Крупногабаритный груз» и фонарём, излучающим белый свет, спереди и сзади — излучающим красный свет.","Разрешена в соответствии со специальными разрешением и правилами.","Запрещена."],"c":1,"e":"<p>Так как общая габаритная ширина автомобиля с грузом не превышает 2.55 метра, достаточно перед началом движения <strong>обозначить выступающие части груза опознавательными знаками «Крупногабаритный груз» и фонарями</strong> согласно требования Правил дорожного движения.</p>","image":"assets/adrive-questions/q102401561.jpg"},{"id":102401601,"themeId":5,"group":1024016,"chapter":24,"chapters":[24],"q":"В каком случае водителю будет разрешено перевозить показанный груз, если перевозка будет происходить в тёмное время суток?","a":["Если груз обозначить фонарём, излучающим красный свет.","Если груз обозначить опознавательным знаком «Крупногабаритный груз».","Если выполнить оба перечисленных действия."],"c":2,"e":"<p>В показанной ситуации перевозимый груз выступает за габариты транспортного средства по длине сзади на 1.6 метра, поэтому водителю в тёмное время суток будет разрешено перевозить данный груз, если его обозначить опознавательным знаком «Крупногабаритный груз» и фонарём, излучающим красный свет.</p>","image":"assets/adrive-questions/q102401601.jpg"},{"id":102401602,"themeId":5,"group":1024016,"chapter":24,"chapters":[24],"q":"В каком случае водителю будет разрешено перевозить показанный груз, но в условиях недостаточной видимости?","a":["Если груз обозначить фонарём, излучающим красный свет.","Если груз обозначить опознавательным знаком «Крупногабаритный груз».","Если выполнить оба перечисленных действия."],"c":2,"e":"<p>В показанной ситуации перевозимый груз выступает за габариты транспортного средства по длине сзади на 1.6 метра, поэтому водителю в условиях недостаточной видимости будет разрешено перевозить данный груз, если его обозначить опознавательным знаком «Крупногабаритный груз» и фонарём, излучающим красный свет.</p>","image":"assets/adrive-questions/q102401602.jpg"},{"id":102401661,"themeId":5,"group":1024016,"chapter":24,"chapters":[24],"q":"Разрешена ли перевозка груза в показанных условиях в тёмное время суток?","a":["Разрешена.","Разрешена только тогда, когда груз будет обозначен опознавательным знаком «Крупногабаритный груз».","Разрешена только тогда, когда груз будет обозначен опознавательным знаком «Крупногабаритный груз» и фонарём, излучающим красный свет, сзади.","Запрещена."],"c":2,"e":"<p>Груз, выступающий за габариты транспортного средства сзади б<strong>олее чем на 1 метр</strong>, должен быть обозначен опознавательным знаком <strong>«Крупногабаритный груз»</strong>, а в тёмное время суток, кроме того, сзади — <strong>фонарём, излучающим красный свет</strong>.</p>","image":"assets/adrive-questions/q102401661.jpg"},{"id":102401701,"themeId":5,"group":1024017,"chapter":24,"chapters":[24],"q":"Как должен поступить водитель, если при перевозке крупногабаритного груза (выступающего за габарит более 1 метра) пошёл сильный ливень, и видимость дороги в направлении движения снизилась до 200 метров?","a":["Включить противотуманные фары в дополнение к ближнему свету фар.","Включить аварийную световую сигнализацию и, снизив скорость, двигаться с особой осторожностью.","Заняв крайнее правое положение на проезжей части дороги, совершить вынужденную остановку, обозначить груз фонарём, излучающим красный свет, а при его отсутствии — не возобновлять движение до улучшения видимости дороги."],"c":2,"e":"<p>Если при перевозке крупногабаритного груза (выступающего за габарит более 1 метра) пошёл сильный ливень, и видимость дороги в направлении движения снизилась до 200 метров, водитель должен, заняв крайнее правое положение на проезжей части дороги, совершить вынужденную остановку, обозначить груз фонарём, излучающим красный свет, а при его отсутствии — не возобновлять движение до улучшения видимости дороги.</p>","image":"assets/adrive-questions/q102401701.jpg"},{"id":102401702,"themeId":5,"group":1024017,"chapter":24,"chapters":[24],"q":"Разрешается ли перевозка крупногабаритного груза в тёмное время суток при отсутствии опознавательных знаков «Крупногабаритный груз»?","a":["Запрещается.","Разрешается, если он обозначен спереди — фонарём, излучающим белый свет, сзади — фонарём, излучающим красный свет."],"c":0,"e":"<p>Перевозка крупногабаритного груза при отсутствии опознавательных знаков «Крупногабаритный груз» запрещена независимо от наличия фонарей, обозначающих груз.</p>","image":null},{"id":102402021,"themeId":5,"group":1024020,"chapter":24,"chapters":[24],"q":"На какую наименьшую длину должен выступать груз за габариты транспортного средства по длине, чтобы оно было отнесено к категории крупногабаритных транспортных средств?","a":["0.4 метра.","1 метр.","1.5 метра.","2 метра.","2.55 метра."],"c":3,"e":"<p>Если груз выступает за габариты транспортного средства по длине на 2 метра и более, то оно относится к категории крупногабаритных транспортных средств.</p>","image":null},{"id":102402023,"themeId":5,"group":1024020,"chapter":24,"chapters":[24],"q":"Какой максимальный габарит для транспортного средства по высоте с грузом или без груза допускается от поверхности дороги, чтобы оно не было отнесено к категории крупногабаритных транспортных средств?","a":["2 метра.","2.55 метра.","3 метра.","4 метра.","4.5 метра."],"c":3,"e":"<p>Если габарит для транспортного средства по высоте с грузом или без груза превышает 4 метра от поверхности дороги, то такое транспортное средство относится к категории крупногабаритных транспортных средств, и для его проезда необходимо получение специального разрешения на проезд крупногабаритных транспортных средств.</p>","image":null},{"id":102500102,"themeId":5,"group":1025001,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировка автомобиля при помощи гибкой сцепки при отсутствии водителя за рулём буксируемого автомобиля?","a":["Разрешается, если у буксируемого автомобиля исправна рабочая тормозная система.","Разрешается, если масса буксируемого автомобиля не превышает половину массы буксирующего.","Запрещается."],"c":2,"e":"<p>Буксировка автомобиля при помощи гибкой сцепки при отсутствии водителя за рулём буксируемого автомобиля запрещается.</p>","image":null},{"id":102500201,"themeId":5,"group":1025002,"chapter":25,"chapters":[25],"q":"В каком из перечисленных случаев разрешается перевозка пассажиров, если буксировка осуществляется при помощи сцепки?","a":["В буксируемом автобусе.","В боковом прицепе буксируемого мотоцикла.","В кузове-фургоне буксируемого грузового автомобиля.","Разрешается во всех перечисленных случаях."],"c":1,"e":"<p>Из перечисленных вариантов перевозка пассажиров, если буксировка осуществляется при помощи сцепки, не запрещается в боковом прицепе буксируемого мотоцикла.</p>","image":null},{"id":102500202,"themeId":5,"group":1025002,"chapter":25,"chapters":[25],"q":"В каком из перечисленных случаев разрешается перевозка пассажиров?","a":["В буксируемом при помощи гибкой сцепки легковом автомобиле.","В кабине буксируемого при помощи жёсткой сцепки грузового автомобиля.","В кузове грузового автомобиля, осуществляющего буксировку путём частичной погрузки.","Разрешается во всех перечисленных случаях."],"c":0,"e":"<p>Перевозка пассажиров не запрещается в буксируемом при помощи гибкой сцепки легковом автомобиле.</p>","image":null},{"id":102500221,"themeId":5,"group":1025002,"chapter":25,"chapters":[25],"q":"Разрешается ли перевозка пассажиров в салоне легкового автомобиля, буксирующего при помощи сцепки неисправное транспортное средство?","a":["Да, разрешается.","Разрешается только при буксировке на жёсткой сцепке.","Нет, не разрешается."],"c":0,"e":"<p>Правилами дорожного движения не запрещена перевозка пассажиров в автомобиле, который осуществляет буксировку другого транспортного средства при помощи сцепки.</p>","image":null},{"id":102500222,"themeId":5,"group":1025002,"chapter":25,"chapters":[25],"q":"Разрешается ли перевозка пассажиров в салоне буксируемого легкового автомобиля?","a":["Разрешается только при буксировке на гибкой сцепке.","Разрешается только при буксировке на жёсткой сцепке.","Разрешается при буксировке как на гибкой, так и на жёсткой сцепке.","Нет, не разрешается."],"c":2,"e":"<p>Правилами дорожного движения не запрещена перевозка пассажиров в буксируемом при помощи сцепки легковом автомобиле и мотоцикле с боковым прицепом.</p>","image":null},{"id":102500301,"themeId":5,"group":1025003,"chapter":25,"chapters":[25],"q":"Разрешается ли перевозить пассажиров при буксировке путём частичной погрузки?","a":["Разрешается только в кабине буксирующего транспортного средства.","Разрешается в кабине и кузове буксирующего транспортного средства.","Разрешается в кабине и кузове буксирующего транспортного средства, а также в кабине (салоне) буксируемого транспортного средства.","Перевозка пассажиров запрещена."],"c":0,"e":"<p>Перевозить пассажиров при буксировке путём частичной погрузки разрешается только в кабине буксирующего транспортного средства.</p>","image":"assets/adrive-questions/q102500301.jpg"},{"id":102500302,"themeId":5,"group":1025003,"chapter":25,"chapters":[25],"q":"Как должен поступить водитель транспортного средства, предназначенного для буксировки путём частичной погрузки, если в неисправном автомобиле помимо водителя находится пассажир, а в кабине всего одно пассажирское место?","a":["Разместить двух человек на одном пассажирском месте.","Разместить одного человека в кабине, а другого — на грузовой платформе.","Разместить в кабине только одного человека, а второму отказать в перевозке.","Разместить одного человека в кабине, а другого оставить в буксируемом автомобиле."],"c":2,"e":"<p>Если в неисправном автомобиле помимо водителя находится пассажир, а в кабине всего одно пассажирское место, то водитель ТС при буксировке путём частичной погрузки может разместить в кабине только одного человека. Запрещается перевозка пассажиров сверх количества, предусмотренного конструкцией транспортного средства.</p>","image":null},{"id":102500501,"themeId":5,"group":1025005,"chapter":25,"chapters":[25],"q":"В каком из перечисленных случаев разрешается перевозка пассажиров при буксировке механического транспортного средства при помощи сцепки?","a":["В кабине буксируемого грузового автомобиля.","В кузове-фургоне, оборудованном для перевозки пассажиров, буксируемого грузового автомобиля.","В кузове с бортовой платформой, оборудованном для перевозки пассажиров, буксирующего грузового автомобиля.","Разрешается перевозка пассажиров во всех перечисленных случаях."],"c":2,"e":"<p>Перевозка пассажиров при буксировке механического транспортного средства при помощи сцепки разрешается в кузове с бортовой платформой, оборудованном для перевозки пассажиров, буксирующего грузового автомобиля.</p>","image":"assets/adrive-questions/q102500501.jpg"},{"id":102500502,"themeId":5,"group":1025005,"chapter":25,"chapters":[25],"q":"В каком из перечисленных случаев разрешается перевозка пассажиров при буксировке механического транспортного средства при помощи гибкой сцепки?","a":["В буксируемом легковом автомобиле.","В буксирующем легковом автомобиле.","На буксируемом мотоцикле с боковым прицепом.","Перевозка пассажиров разрешается во всех перечисленных случаях."],"c":3,"e":"<p>Перевозка пассажиров при буксировке механического транспортного средства при помощи гибкой сцепки не запрещается:</p> <ul><li>в буксируемом легковом автомобиле;</li> <li>в буксирующем легковом автомобиле;</li> <li>на буксируемом мотоцикле с боковым прицепом.</li></ul>","image":null},{"id":102500601,"themeId":5,"group":1025006,"chapter":25,"chapters":[25],"q":"Разрешается ли перевозка пассажиров в транспортных средствах, буксируемых путём частичной погрузки?","a":["Разрешается в легковом автомобиле.","Разрешается в кабине грузового автомобиля с технически допустимой общей массой не более 3.5 тонны.","Разрешается в кузове-фургоне грузового автомобиля с технически допустимой общей массой не более 3.5 тонны.","Во всех транспортных средствах нахождение людей запрещено."],"c":3,"e":"<p>В транспортных средствах, буксируемых путём частичной погрузки, перевозка пассажиров запрещается.</p>","image":null},{"id":102500602,"themeId":5,"group":1025006,"chapter":25,"chapters":[25],"q":"В каком из показанных автомобилей разрешена перевозка пассажиров при осуществлении буксировки?","a":["В обоих автомобилях.","Только в красном автомобиле.","В обоих автомобилях перевозка пассажиров запрещена."],"c":0,"e":"<p>В показанной ситуации осуществляется буксировка легкового автомобиля на гибкой сцепке, поэтому перевозка пассажиров разрешена в обоих автомобилях.</p>","image":"assets/adrive-questions/q102500602.jpg"},{"id":102500701,"themeId":5,"group":1025007,"chapter":25,"chapters":[25],"q":"В каких пределах должно быть расстояние между буксирующим и буксируемым транспортными средствами при буксировке с помощью гибкой сцепки?","a":["1.5–3 метра.","2–4 метра.","3–4 метра.","4–6 метров."],"c":3,"e":"<p>При буксировке с помощью гибкой сцепки расстояние между буксирующим и буксируемым транспортными средствами должно быть от 4 до 6 метров.</p>","image":"assets/adrive-questions/q102500701.jpg"},{"id":102500702,"themeId":5,"group":1025007,"chapter":25,"chapters":[25],"q":"Соответствует ли расстояние между буксирующим и буксируемым транспортными средствами разрешённому Правилами дорожного движения для такого способа буксировки?","a":["Да, соответствует.","Нет, не соответствует."],"c":0,"e":"<p>В показанной ситуации осуществляется буксировка легкового автомобиля на гибкой сцепке длинной 5 метров, поэтому расстояние между буксирующим и буксируемым транспортными средствами соответствует разрешённому Правилами дорожного движения для такого способа буксировки (от 4 до 6 метров).</p>","image":"assets/adrive-questions/q102500702.jpg"},{"id":102500721,"themeId":5,"group":1025007,"chapter":25,"chapters":[25],"q":"Какое минимальное расстояние допускается между буксирующим и буксируемым транспортными средствами при буксировке с помощью гибкой сцепки?","a":["3 метра.","4 метра.","5 метров.","6 метров."],"c":1,"e":"<p>При буксировке с помощью гибкой сцепки расстояние между буксирующим и буксируемым транспортными средствами должно быть в пределах 4–6 метров.</p>","image":"assets/adrive-questions/q102500721.jpg"},{"id":102500722,"themeId":5,"group":1025007,"chapter":25,"chapters":[25],"q":"Какое максимальное расстояние допускается между буксирующим и буксируемым транспортными средствами при буксировке с помощью гибкой сцепки?","a":["3 метра.","4 метра.","5 метров.","6 метров."],"c":3,"e":"<p>При буксировке с помощью гибкой сцепки расстояние между буксирующим и буксируемым транспортными средствами должно быть в пределах 4–6 метров.</p>","image":"assets/adrive-questions/q102500722.jpg"},{"id":102500801,"themeId":5,"group":1025008,"chapter":25,"chapters":[25],"q":"В каких пределах должно быть расстояние между буксирующим и буксируемым транспортными средствами при буксировке с помощью жёсткой сцепки?","a":["Не более 2 метров.","Не более 3 метров.","Не более 4 метров.","От 3 до 5 метров.","От 4 до 6 метров."],"c":2,"e":"<p>При буксировке с помощью жёсткой сцепки расстояние между буксирующим и буксируемым транспортными средствами должно быть не более 4 метров</p>","image":"assets/adrive-questions/q102500801.jpg"},{"id":102500802,"themeId":5,"group":1025008,"chapter":25,"chapters":[25],"q":"Соответствует ли расстояние между буксирующим и буксируемым транспортными средствами, разрешённому Правилами дорожного движения для такого способа буксировки?","a":["Да, соответствует.","Нет, не соответствует."],"c":0,"e":"<p>В показанной ситуации осуществляется буксировка автомобиля на жёсткой сцепке длинной 2.5 метра, поэтому расстояние между буксирующим и буксируемым транспортными средствами соответствует разрешённому Правилами дорожного движения для такого способа буксировки (не более 4 метров).</p>","image":"assets/adrive-questions/q102500802.jpg"},{"id":102500901,"themeId":5,"group":1025009,"chapter":25,"chapters":[25],"q":"Соответствует ли расстояние между буксирующим и буксируемым транспортными средствами разрешённому Правилами дорожного движения для такого способа буксировки?","a":["Да, соответствует.","Нет, не соответствует."],"c":1,"e":"<p>В показанной ситуации осуществляется буксировка легкового автомобиля на гибкой сцепке длинной 3.5 метра, поэтому расстояние между буксирующим и буксируемым транспортными средствами не соответствует разрешённому Правилами дорожного движения для такого способа буксировки (от 4 до 6 метров).</p>","image":"assets/adrive-questions/q102500901.jpg"},{"id":102500902,"themeId":5,"group":1025009,"chapter":25,"chapters":[25],"q":"Соответствует ли расстояние между буксирующим и буксируемым транспортными средствами, показанное на рисунке, разрешённому Правилами дорожного движения для такого способа буксировки?","a":["Да, соответствует.","Нет, не соответствует."],"c":0,"e":"<p>В показанной ситуации осуществляется буксировка автомобиля на жёсткой сцепке длиной 2 метра, поэтому расстояние между буксирующим и буксируемым транспортными средствами соответствует разрешённому Правилами дорожного движения (не более 4 метров) для такого способа буксировки.</p>","image":"assets/adrive-questions/q102500902.jpg"},{"id":102501001,"themeId":5,"group":1025010,"chapter":25,"chapters":[25],"q":"Каким образом разрешено осуществлять буксировку автомобиля, у которого неисправна рабочая тормозная система, а масса меньше половины массы буксирующего автомобиля?","a":["Только путём частичной погрузки.","Только при помощи жёсткой сцепки.","При помощи жёсткой или гибкой сцепки.","Путём частичной погрузки или при помощи жёсткой сцепки.","Любым из перечисленных способов."],"c":3,"e":"<p>Осуществлять буксировку автомобиля, у которого неисправна рабочая тормозная система, разрешено путём частичной погрузки, при этом, если масса буксируемого автомобиля меньше половины массы буксирующего автомобиля, также разрешено осуществлять буксировку при помощи жёсткой сцепки.</p>","image":null},{"id":102501002,"themeId":5,"group":1025010,"chapter":25,"chapters":[25],"q":"Каким образом разрешено осуществлять буксировку автомобиля, у которого неисправна рабочая тормозная система, а масса больше половины массы буксирующего автомобиля?","a":["Только путём частичной погрузки.","Только при помощи жёсткой сцепки.","При помощи жёсткой или гибкой сцепки.","Путём частичной погрузки или при помощи жёсткой сцепки.","Любым из перечисленных способов буксировка запрещена."],"c":0,"e":"<p>Осуществлять буксировку автомобиля, у которого неисправна рабочая тормозная система, а масса больше половины массы буксирующего автомобиля, разрешено только путём частичной погрузки.</p>","image":null},{"id":102501021,"themeId":5,"group":1025010,"chapter":25,"chapters":[25],"q":"В каком из перечисленных случаев допускается буксировка автомобиля, у которого неисправно рулевое управление?","a":["На минимально допустимой гибкой сцепке при наличии водителя за рулём буксируемого автомобиля.","На жёсткой сцепке, когда её конструкция не обеспечивает движение буксируемого транспортного средства по траектории буксирующего.","При буксировке путём частичной погрузки.","Допускается во всех перечисленных случаях.","Не допускается во всех перечисленных случаях."],"c":2,"e":"<p>При буксировке путём частичной погрузки допускаются неисправности рабочей тормозной системы и рулевого управления буксируемого транспортного средства.</p>","image":null},{"id":102501101,"themeId":5,"group":1025011,"chapter":25,"chapters":[25],"q":"Каким образом разрешено осуществлять буксировку автомобиля, у которого неисправно рулевое управление?","a":["Только путём частичной погрузки.","Только при помощи жёсткой сцепки, когда конструкция жёсткой сцепки обеспечивает движение буксируемого автомобиля по траектории буксирующего.","Путём частичной погрузки или при помощи жёсткой сцепки, когда конструкция жёсткой сцепки обеспечивает движение буксируемого автомобиля по траектории буксирующего."],"c":2,"e":"<p>Осуществлять буксировку автомобиля, у которого неисправно рулевое управление, разрешено путём частичной погрузки или при помощи жёсткой сцепки, когда конструкция жёсткой сцепки обеспечивает движение буксируемого автомобиля по траектории буксирующего.</p>","image":null},{"id":102501102,"themeId":5,"group":1025011,"chapter":25,"chapters":[25],"q":"Разрешается ли осуществлять буксировку механического транспортного средства, у которого неисправно рулевое управление, при помощи жёсткой сцепки?","a":["Разрешается, если масса буксируемого транспортного средства не более половины массы буксирующего.","Разрешается, если конструкция жёсткой сцепки обеспечивает движение буксируемого автомобиля по траектории буксирующего.","Разрешается только при выполнении обоих перечисленных условий."],"c":1,"e":"<p>Осуществлять буксировку механического транспортного средства, у которого неисправно рулевое управление, при помощи жёсткой сцепки, разрешено, если конструкция жёсткой сцепки обеспечивает движение буксируемого автомобиля по траектории буксирующего.</p>","image":null},{"id":102501121,"themeId":5,"group":1025011,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировка автомобиля при помощи жёсткой сцепки с неисправным рулевым управлением?","a":["Да, разрешается.","Разрешается только в случае, когда конструкция жёсткой сцепки обеспечивает движение буксируемого транспортного средства по траектории буксирующего.","Нет, не разрешается."],"c":1,"e":"<p>При буксировке с помощью жёсткой сцепки у буксируемого транспортного средства должно быть исправно рулевое управление, кроме случая, когда конструкция жёсткой сцепки обеспечивает его движение по траектории буксирующего.</p>","image":"assets/adrive-questions/q102501121.jpg"},{"id":102501201,"themeId":5,"group":1025012,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировать легковой автомобиль, у которого неисправна рабочая тормозная система, при помощи гибкой сцепки?","a":["Разрешается при скорости буксировки не более 30 км/ч.","Разрешается, если у него исправна стояночная тормозная система.","Разрешается при выполнении обоих перечисленных условий.","Запрещается."],"c":3,"e":"<p>Буксировать легковой автомобиль, у которого неисправна рабочая тормозная система, при помощи гибкой сцепки, запрещается.</p>","image":null},{"id":102501202,"themeId":5,"group":1025012,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировать легковой автомобиль, у которого неисправна рабочая тормозная система, при помощи жёсткой сцепки?","a":["Разрешается при скорости буксировки не более 30 км/ч.","Разрешается при длине жёсткого буксирующего устройства не более двух метров.","Разрешается, если масса буксируемого автомобиля не превышает половины массы буксирующего.","Запрещается."],"c":2,"e":"<p>Буксировать легковой автомобиль, у которого неисправна рабочая тормозная система, при помощи жёсткой сцепки, разрешается, если масса буксируемого автомобиля не превышает половины массы буксирующего.</p>","image":null},{"id":102501221,"themeId":5,"group":1025012,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировать с помощью гибкой сцепки автомобиль, у которого исправно рулевое управление, но неисправна рабочая тормозная система?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается только в том случае, если масса буксируемого автомобиля составляет не более половины массы буксирующего."],"c":1,"e":"<p>При буксировке с помощью гибкой сцепки у буксируемого транспортного средства должны быть исправны и рабочая тормозная система, и рулевое управление.</p>","image":"assets/adrive-questions/q102501221.jpg"},{"id":102501301,"themeId":5,"group":1025013,"chapter":25,"chapters":[25],"q":"Какие системы и механизмы должны быть исправны у буксируемого автомобиля в показанной ситуации (конструкция жёсткой сцепки не обеспечивает движение буксируемому автомобилю по траектории буксирующего), если масса автомобилей приблизительно одинаковая?","a":["Рулевое управление.","Рабочая тормозная система.","Стояночная тормозная система.","Рабочая тормозная система и рулевое управление.","Должны быть исправны все перечисленные системы и механизмы."],"c":3,"e":"<p>В показанной ситуации конструкция жёсткой сцепки не обеспечивает движение буксируемому автомобилю по траектории буксирующего и масса автомобилей приблизительно одинаковая, поэтому у буксируемого автомобиля должны быть исправны рабочая тормозная система и рулевое управление.</p>","image":"assets/adrive-questions/q102501301.jpg"},{"id":102501302,"themeId":5,"group":1025013,"chapter":25,"chapters":[25],"q":"Какие системы и механизмы должны быть исправны у буксируемого автомобиля в показанной ситуации (конструкция жёсткой сцепки обеспечивает движение буксируемому автомобилю по траектории буксирующего), если массы автомобилей приблизительно равны?","a":["Рулевое управление.","Рабочая тормозная система.","Стояночная тормозная система.","Рабочая тормозная система и рулевое управление.","Должны быть исправны все перечисленные системы и механизмы."],"c":1,"e":"<p>В показанной ситуации конструкция жёсткой сцепки обеспечивает движение буксируемому автомобилю по траектории буксирующего и масса автомобилей приблизительно одинаковая, поэтому у буксируемого автомобиля должны быть исправна рабочая тормозная система.</p>","image":"assets/adrive-questions/q102501302.jpg"},{"id":102501321,"themeId":5,"group":1025013,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировка легкового автомобиля на жёсткой сцепке, если его фактическая масса составляет 1.3 тонны, а фактическая масса буксирующего автомобиля составляет 2.8 тонны?","a":["Разрешается только при условии, что у буксируемого автомобиля исправна рабочая тормозная система.","Разрешается независимо от состояния рабочей тормозной системы буксируемого автомобиля."],"c":1,"e":"<p>При буксировке с помощью жёсткой сцепки у буксируемого транспортного средства при массе более половины массы буксирующего транспортного средства должна быть исправна рабочая тормозная система. В данном случае масса буксируемого транспортного средства не превышает половины массы буксирующего.</p>","image":"assets/adrive-questions/q102501321.jpg"},{"id":102501322,"themeId":5,"group":1025013,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировать оборудованный гидроусилителем руля легковой автомобиль с остановленным двигателем при помощи жёсткой сцепки, если её конструкция обеспечивает движение буксируемого автомобиля по траектории буксирующего?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Правилами дорожного движения не запрещается буксировка на жёсткой сцепке транспортных средств, если работа их рабочих тормозных и (или) рулевых систем связана с работой двигателя, который остановлен.</p>","image":null},{"id":102501323,"themeId":5,"group":1025013,"chapter":25,"chapters":[25],"q":"У Вас во время движения по дороге вне населённого пункта закончилось топливо, и двигатель заглох. Каким образом разрешается осуществить буксировку до ближайшей автозаправочной станции, если работа рулевого управления и рабочей тормозной системы Вашего автомобиля связана с работой двигателя?","a":["При помощи гибкой сцепки.","При помощи жёсткой сцепки.","При помощи гибкой или жёсткой сцепки."],"c":1,"e":"<p>Запрещается буксировка механических транспортных средств на гибкой сцепке, если работа их рабочих тормозных и (или) рулевых систем связана с работой двигателя, который остановлен. При этом Правилами дорожного движения не запрещается буксировка на жёсткой сцепке транспортных средств в аналогичных условиях.</p>","image":null},{"id":102501401,"themeId":5,"group":1025014,"chapter":25,"chapters":[25],"q":"Какие из перечисленных неисправностей допускаются у буксируемого транспортного средства при его буксировке путём частичной погрузки?","a":["Неисправности рулевого управления.","Неисправности рабочей тормозной системы.","Неисправности стояночной тормозной системы.","Допускаются все перечисленные неисправности.","Не допускается ни одной из перечисленных неисправностей."],"c":3,"e":"<p>При буксировке путём частичной погрузки у буксируемого ТС допускаются любые неисправности тормозных систем и рулевого управления.</p>","image":null},{"id":102501402,"themeId":5,"group":1025014,"chapter":25,"chapters":[25],"q":"Какие из перечисленных неисправностей допускаются у буксируемого транспортного средства при его буксировке с помощью гибкой сцепки?","a":["Неисправности рулевого управления.","Неисправности рабочей тормозной системы.","Неисправности стояночной тормозной системы.","Допускаются все перечисленные неисправности.","Не допускается ни одной из перечисленных неисправностей."],"c":2,"e":"<p>При буксировке с помощью гибкой сцепки допускаются неисправности стояночной тормозной системы.</p>","image":null},{"id":102501421,"themeId":5,"group":1025014,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировка автомобиля при помощи жёсткой сцепки с неисправной рабочей тормозной системой?","a":["Да, разрешается.","Разрешается, если масса буксируемого автомобиля составляет менее половины массы буксирующего.","Нет, не разрешается."],"c":1,"e":"<p>При буксировке с помощью жёсткой сцепки при массе буксируемого транспортного средства более половины массы буксирующего у буксируемого транспортного средства должна быть исправна рабочая тормозная система.</p>","image":"assets/adrive-questions/q102501421.jpg"},{"id":102501901,"themeId":5,"group":1025019,"chapter":25,"chapters":[25],"q":"При каких из перечисленных условий запрещена буксировка при помощи гибкой сцепки?","a":["В гололедицу.","В условиях снегопада.","В условиях недостаточной видимости.","В тёмное время суток."],"c":0,"e":"<p>Буксировка механического транспортного средства при помощи гибкой сцепки запрещена в гололедицу.</p>","image":null},{"id":102501902,"themeId":5,"group":1025019,"chapter":25,"chapters":[25],"q":"Что из перечисленного не запрещается на проезжей части дороги в гололедицу?","a":["Движение на мопеде.","Движение на мотоцикле без бокового прицепа.","Буксировка механических транспортных средств при помощи гибкой сцепки.","Запрещено всё перечисленное."],"c":1,"e":"<p>В гололедицу движение на мотоцикле без бокового прицепа не запрещено.</p>","image":null},{"id":102501921,"themeId":5,"group":1025019,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировка в гололедицу, если у буксируемого транспортного средства исправны тормоза и рулевое управление?","a":["Да, разрешается.","Разрешается только на жёсткой сцепке или путём частичной погрузки.","Нет, не разрешается."],"c":1,"e":"<p>Запрещается буксировка в гололедицу при помощи гибкой сцепки. Остальные способы буксировки в таких условиях не запрещены.</p>","image":null},{"id":102502001,"themeId":5,"group":1025020,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировка грузового автомобиля с технически допустимой общей массой не более 3.5 тонны показанным на рисунке способом?","a":["Да, разрешается.","Разрешается только в случае, если масса буксируемого автомобиля не превышает половины массы буксирующего.","Нет, не разрешается."],"c":2,"e":"<p>В показанной ситуации осуществляется буксировка грузового автомобиля с технически допустимой общей массой не более 3.5 тонны седельным тягачом с полуприцепом, поэтому буксировка запрещена.</p>","image":"assets/adrive-questions/q102502001.jpg"},{"id":102502002,"themeId":5,"group":1025020,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировка легкового автомобиля показанным способом?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации осуществляется буксировка автомобиля легковым автомобилем с прицепом, поэтому буксировка запрещена. Согласно Правилам дорожного движения запрещается буксировка двух и более транспортных средств, за исключением седельного тягача с полуприцепом.</p>","image":"assets/adrive-questions/q102502002.jpg"},{"id":102502101,"themeId":5,"group":1025021,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировка мотоцикла таким образом?","a":["Разрешается, только если у мотоцикла исправны рулевое управление и рабочая тормозная система.","Разрешается, только если расстояние между автомобилем и мотоциклом будет в пределах 4–6 метров.","Разрешается при выполнении обоих перечисленных условий.","Буксировка мотоцикла запрещается."],"c":2,"e":"<p>В показанной ситуации осуществляется буксировка мотоцикла с боковым прицепом легковым автомобилем, поэтому буксировка будет разрешена, если у мотоцикла исправны рулевое управление и рабочая тормозная система и расстояние между автомобилем и мотоциклом будет в пределах 4–6 метров.</p>","image":"assets/adrive-questions/q102502101.jpg"},{"id":102502102,"themeId":5,"group":1025021,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировка мотоцикла таким образом?","a":["Разрешается, только если у мотоцикла исправны рулевое управление и рабочая тормозная система.","Разрешается, только если расстояние между автомобилем и мотоциклом будет в пределах 4–6 метров.","Разрешается при выполнении обоих перечисленных условий.","Буксировка мотоцикла запрещается."],"c":3,"e":"<p>В показанной ситуации осуществляется буксировка мотоцикла без бокового прицепа легковым автомобилем, а согласно Правилам дорожного движения такая буксировка запрещена.</p>","image":"assets/adrive-questions/q102502102.jpg"},{"id":102502201,"themeId":5,"group":1025022,"chapter":25,"chapters":[25],"q":"Разрешается ли Вам произвести буксировку с помощью гибкой сцепки автомобиля, у которого не заводится двигатель, если этот автомобиль оборудован гидроусилителем рулевого управления?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Произвести буксировку с помощью гибкой сцепки автомобиля, у которого не заводится двигатель, если этот автомобиль оборудован гидроусилителем рулевого управления, запрещено, так как работа гидроусилителя зависит от работы двигателя.</p>","image":null},{"id":102502202,"themeId":5,"group":1025022,"chapter":25,"chapters":[25],"q":"Разрешается ли Вам произвести буксировку с помощью гибкой сцепки автомобиля, у которого не заводится двигатель, если этот автомобиль оборудован вакуумным усилителем рабочей тормозной системы?","a":["Да, разрешается.","Разрешается только в случае, если масса буксируемого автомобиля не превышает половины массы буксирующего.","Нет, не разрешается."],"c":2,"e":"<p>Произвести буксировку с помощью гибкой сцепки автомобиля, у которого не заводится двигатель, если этот автомобиль оборудован вакуумным усилителем рабочей тормозной системы, запрещено, так как работа усилителя связана с работой двигателя.</p>","image":"assets/adrive-questions/q102502202.jpg"},{"id":102502251,"themeId":5,"group":1025022,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировка автомобиля на гибкой сцепке, если работа его тормозной и рулевой систем связана с работой двигателя, который остановлен?","a":["Разрешается, если масса буксируемого автомобиля составляет менее половины массы буксирующего автомобиля.","Разрешается в любом случае.","Запрещается."],"c":2,"e":"<p>Буксировка механических транспортных средств <strong>на гибкой сцепке</strong>, если работа их рабочих тормозных и (или) рулевых систем связана с работой двигателя, который остановлен, <strong>запрещается при любых условиях</strong>.</p>","image":"assets/adrive-questions/q102502251.jpg"},{"id":102502321,"themeId":5,"group":1025023,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировать оборудованный гидроусилителем руля легковой автомобиль, если у него не работает двигатель?","a":["Разрешается только путём частичной погрузки.","Разрешается путём частичной погрузки или на жёсткой сцепке.","Разрешается только на жёсткой сцепке.","Нет, не разрешается."],"c":1,"e":"<p>При буксировке путём частичной погрузки допускаются неисправности рабочей тормозной системы и рулевого управления буксируемого транспортного средства.</p> <p>Запрещается буксировка механических транспортных средств на гибкой сцепке, если работа их рабочих тормозных и (или) рулевых систем связана с работой двигателя, который остановлен.</p> <p>При буксировке с помощью жёсткой сцепки у буксируемого транспортного средства должно быть исправно рулевое управление. В поставленном вопросе нет сведений о наличии неисправности рулевого управления. Рулевое управление действует, вращение рулевого колеса затруднено при нахождении автомобиля в неподвижном состоянии. При буксировке на жёсткой сцепке на скорости до 50 км/ч допустимо буксировать автомобиль, у которого гидроусилитель руля не оказывает дополнительного воздействия на управляемые колёса. Допустимо буксировать автомобиль как на сцепке, обеспечивающей движение буксируемого автомобиля по траектории буксирующего (например, треугольник), так и на обыкновенной жёсткой сцепке (например, штанга).</p> <p>Таким образом, случаи разрешённой буксировки на жёсткой сцепке, когда двигатель автомобиля остановлен, а гидроусилитель руля исправен:</p> <ol><li>Жёсткая сцепка обеспечивает движение буксируемого транспортного средства по траектории буксирующего.</li> <li>Жёсткая сцепка не обеспечивает движение буксируемого ТС по траектории буксирующего, но гидроусилитель руля исправен, а буксировка технически возможна и безопасна.</li></ol>","image":null},{"id":102502401,"themeId":5,"group":1025024,"chapter":25,"chapters":[25],"q":"Буксировка каких из перечисленных транспортных средств запрещена с помощью сцепки?","a":["Мотоцикла с боковым прицепом.","Седельного тягача с полуприцепом.","Легкового автомобиля с одноосным прицепом.","Буксировка всех перечисленных транспортных средств запрещена.","Буксировка всех перечисленных транспортных средств не запрещена."],"c":2,"e":"<p>Буксировка транспортного средства с прицепом запрещена, кроме буксировки седельного автопоезда.</p>","image":null},{"id":102502402,"themeId":5,"group":1025024,"chapter":25,"chapters":[25],"q":"Разрешается ли буксировать легковой автомобиль так, как показано на рисунке?","a":["Разрешается.","Разрешается, если общая длина состава транспортных средств не превышает 20 метров.","Запрещается."],"c":2,"e":"<p>В показанной ситуации осуществляется буксировка автомобиля с прицепом легковым автомобилем, поэтому буксировка запрещена Согласно Правилам дорожного движения запрещается буксировка двух и более транспортных средств, за исключением седельного тягача с полуприцепом.</p>","image":"assets/adrive-questions/q102502402.jpg"},{"id":102502501,"themeId":5,"group":1025025,"chapter":25,"chapters":[25],"q":"Разрешается ли осуществлять буксировку транспортных средств таким способом?","a":["Разрешается.","Разрешается, если общая длина состава транспортных средств не превышает 20 метров.","Запрещается."],"c":2,"e":"<p>В показанной ситуации осуществляется буксировка двух легковых автомобилей грузовым автомобилем, поэтому буксировка таким способом будет запрещена. Согласно Правилам дорожного движения запрещается буксировка двух и более транспортных средств, за исключением седельного тягача с полуприцепом.</p>","image":"assets/adrive-questions/q102502501.jpg"}];